const CSV_IMPORTED_QUESTIONS = [
  {"id": 20150401, "year": 201504, "num": 1, "field": "structure", "text": "水の比熱に関する記述として、適切なものは次のうちどれか。", "opts": ["煙突の高さを表す。", "安全弁の吹出し圧力を表す。", "燃料油の粘度だけを表す。", "水1kgの温度を1K上げるのに必要な熱量に関係する。", "水面計のガラス長さを表す。"], "ans": 3, "exp": "比熱は単位質量の物質の温度を単位温度上げるために必要な熱量である。"},
  {"id": 20150402, "year": 201504, "num": 2, "field": "structure", "text": "絶対圧力に関する記述として、適切なものは次のうちどれか。", "opts": ["大気圧を基準にした圧力である。", "水位の高さだけを示す。", "燃料の発熱量である。", "真空を基準にした圧力である。", "安全弁の口径だけを示す。"], "ans": 3, "exp": "絶対圧力は完全真空を基準とする圧力で、ゲージ圧とは区別する。"},
  {"id": 20150403, "year": 201504, "num": 3, "field": "structure", "text": "圧力が高くなると水の沸点は一般にどうなるか。", "opts": ["低くなる。", "変わらない。", "必ず0度になる。", "高くなる。", "燃料の種類だけで決まる。"], "ans": 3, "exp": "飽和温度は圧力が高くなるほど高くなる。"},
  {"id": 20150404, "year": 201504, "num": 4, "field": "structure", "text": "湿り蒸気に関する記述として、適切なものは次のうちどれか。", "opts": ["乾き飽和蒸気と水滴が混じった蒸気である。", "必ず過熱蒸気である。", "燃料ガスだけをいう。", "水面計の内部水だけをいう。", "圧力計内の空気だけをいう。"], "ans": 0, "exp": "湿り蒸気は蒸気中に水滴を含む状態で、乾き度が1未満である。"},
  {"id": 20150405, "year": 201504, "num": 5, "field": "structure", "text": "伝熱面にすすが付着した場合の影響として、適切なものは次のうちどれか。", "opts": ["燃料中の硫黄分が消える。", "伝熱が必ず良くなる。", "水位が自動で安定する。", "熱伝達が悪くなり、排ガス温度が上がることがある。", "安全弁が不要になる。"], "ans": 3, "exp": "すすは断熱層となり、熱効率低下や排ガス温度上昇の原因となる。"},
  {"id": 20150406, "year": 201504, "num": 6, "field": "structure", "text": "炉壁の耐火材に関する記述として、適切なものは次のうちどれか。", "opts": ["高温ガスから外壁を保護し、熱損失を抑える。", "燃料を自動で脱硫する。", "水の硬度を下げる。", "圧力計の目盛を増やす。", "水面計の代わりに水位を表示する。"], "ans": 0, "exp": "耐火材や保温材は高温部の保護と熱損失低減に役立つ。"},
  {"id": 20150407, "year": 201504, "num": 7, "field": "structure", "text": "水循環が悪くなると起こり得る障害として、適切なものは次のうちどれか。", "opts": ["伝熱面の過熱や焼損。", "燃料の発熱量増加。", "安全弁の自動増設。", "水面計の不要化。", "煙突高さの低下。"], "ans": 0, "exp": "水循環不良は冷却不足を招き、伝熱面の過熱につながる。"},
  {"id": 20150408, "year": 201504, "num": 8, "field": "structure", "text": "ドラムに関する記述として、適切なものは次のうちどれか。", "opts": ["燃料だけを貯蔵する。", "蒸気と水を分離し、水管群の水循環にも関係する。", "煙突の先端部である。", "安全弁のばねである。", "給水ポンプの羽根車である。"], "ans": 1, "exp": "ドラムは気水分離や給水・蒸気の集まり、水循環に関係する主要部である。"},
  {"id": 20150409, "year": 201504, "num": 9, "field": "structure", "text": "貫流ボイラーで水質管理が重要な理由として、適切なものは次のうちどれか。", "opts": ["安全弁を設けないため。", "水を全く使わないため。", "燃料だけで蒸気を直接作るため。", "保有水量が少なく、管内でのスケールや腐食の影響を受けやすい。", "水面計が常に不要なため。"], "ans": 3, "exp": "貫流ボイラーは保有水量が少なく、給水管理と制御が重要である。"},
  {"id": 20150410, "year": 201504, "num": 10, "field": "structure", "text": "丸ボイラーの特徴として、適切なものは次のうちどれか。", "opts": ["安全弁を設けることができない。", "必ず水を保有しない。", "燃料ガスだけを貯蔵する。", "胴内に比較的多くの水を保有するものがある。", "蒸気を発生できない。"], "ans": 3, "exp": "丸ボイラーは胴に水を保有し、炉筒煙管式などが代表例である。"},
  {"id": 20150411, "year": 201504, "num": 11, "field": "handling", "text": "点火前に燃料漏れを確認する理由として、適切なものは次のうちどれか。", "opts": ["給水を軟化するため。", "漏れた燃料への着火や爆発を防ぐため。", "蒸気の乾き度を上げるためだけ。", "安全弁の口径を測るため。", "水面計の色を変えるため。"], "ans": 1, "exp": "燃料漏れは火災や爆発の原因となるため、点火前確認が必要である。"},
  {"id": 20150412, "year": 201504, "num": 12, "field": "handling", "text": "冷たいボイラーを急激にたき上げることが適切でない理由として、適切なものは次のうちどれか。", "opts": ["煙突が短くなるため。", "燃料が必ず不要になるため。", "水位が見えなくなる法令があるため。", "安全弁が増えるため。", "熱応力や漏れを生じやすいため。"], "ans": 4, "exp": "急熱は部材の温度差を大きくし、熱応力や漏れの原因となる。"},
  {"id": 20150413, "year": 201504, "num": 13, "field": "handling", "text": "水面計の水側連絡管が詰まった場合に起こり得ることとして、適切なものは次のうちどれか。", "opts": ["給水ポンプの能力が必ず向上する。", "燃料発熱量が上がる。", "安全弁が不要になる。", "実際より水位が高く見えるなど誤表示の原因となる。", "排ガス中の酸素がゼロになる。"], "ans": 3, "exp": "水面計連絡管の閉塞は誤水位表示につながるため危険である。"},
  {"id": 20150414, "year": 201504, "num": 14, "field": "handling", "text": "水面計の蒸気側連絡管が詰まった場合の注意として、適切なものは次のうちどれか。", "opts": ["燃料中の水分が消える。", "表示は必ず正確になる。", "燃焼状態だけが改善する。", "安全弁の作動圧が下がる。", "水位表示が不正確になるため機能試験で確認する。"], "ans": 4, "exp": "蒸気側、水側いずれの連絡管閉塞も水位誤認の原因となる。"},
  {"id": 20150415, "year": 201504, "num": 15, "field": "handling", "text": "水位が見えなくなったときの対応として、適切なものは次のうちどれか。", "opts": ["水位を確認せず燃焼を続ける。", "燃焼を停止し、水位確認と原因確認を行う。", "燃焼量を最大にする。", "安全弁を固定する。", "低水位警報を外す。"], "ans": 1, "exp": "水位不明のまま運転することは危険であり、まず安全側に停止する。"},
  {"id": 20150416, "year": 201504, "num": 16, "field": "handling", "text": "ボイラー水の電気伝導率を測る目的として、適切なものは次のうちどれか。", "opts": ["燃料の発熱量を直接測るため。", "溶解固形分の濃縮状態を推定するため。", "安全弁のばね力を測るため。", "火炎の明るさを測るため。", "煙突高さを測るため。"], "ans": 1, "exp": "電気伝導率はボイラー水の濃縮管理の指標として用いられる。"},
  {"id": 20150417, "year": 201504, "num": 17, "field": "handling", "text": "りん酸塩処理に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料の硫黄分を除去する。", "硬度成分を軟らかいスラッジとして処理する目的で用いられることがある。", "安全弁の吹出し圧力を上げる。", "煙突内のすすを燃やす。", "水位を直接表示する。"], "ans": 1, "exp": "りん酸塩処理は硬度成分によるスケール障害の防止に関係する。"},
  {"id": 20150418, "year": 201504, "num": 18, "field": "handling", "text": "脱酸素剤を用いる目的として、適切なものは次のうちどれか。", "opts": ["安全弁を固定する。", "燃料の粘度を上げる。", "排ガス中の酸素を増やす。", "水面計を不要にする。", "給水中の溶存酸素を減らし腐食を抑える。"], "ans": 4, "exp": "溶存酸素は腐食原因となるため、脱気や脱酸素剤で管理する。"},
  {"id": 20150419, "year": 201504, "num": 19, "field": "handling", "text": "アルカリ腐食や苛性脆化に関する問題で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["過度なアルカリ濃縮や応力部での障害として整理する。", "燃料の完全燃焼だけの問題である。", "水位計の照明だけの問題である。", "煙突高さだけで決まる。", "安全弁口径だけで決まる。"], "ans": 0, "exp": "水質の過度な濃縮や局部濃縮は腐食・脆化の問題として問われる。"},
  {"id": 20150420, "year": 201504, "num": 20, "field": "handling", "text": "キャリオーバが発生した場合に起こり得ることとして、適切なものは次のうちどれか。", "opts": ["蒸気が必ず完全に乾く。", "蒸気配管や過熱器に水分・不純物が運ばれる。", "燃料消費がゼロになる。", "水位確認が不要になる。", "安全弁が必ず閉じなくなる。"], "ans": 1, "exp": "キャリオーバは蒸気側への水分・不純物持込みで、配管や機器に悪影響を及ぼす。"},
  {"id": 20150421, "year": 201504, "num": 21, "field": "fuel", "text": "液体燃料の引火点に関する記述として、適切なものは次のうちどれか。", "opts": ["煙突内の温度である。", "必ず燃焼温度と同じである。", "水の沸点である。", "安全弁の作動温度である。", "可燃性蒸気を発生し、点火源で引火し得る最低温度である。"], "ans": 4, "exp": "引火点は燃料の取扱安全上重要な性質である。"},
  {"id": 20150422, "year": 201504, "num": 22, "field": "fuel", "text": "燃料の密度に関する記述として、適切なものは次のうちどれか。", "opts": ["排ガス中の酸素濃度である。", "水位の高さだけを示す。", "安全弁の吹出し量である。", "単位体積当たりの質量で、貯蔵量や流量換算に関係する。", "給水のpHである。"], "ans": 3, "exp": "密度は質量と体積の換算や燃料管理で用いられる。"},
  {"id": 20150423, "year": 201504, "num": 23, "field": "fuel", "text": "燃料の元素分析で主に見る成分として、適切でないものは次のうちどれか。", "opts": ["水面計目盛", "水素", "硫黄", "酸素", "炭素"], "ans": 0, "exp": "燃料の元素分析では炭素、水素、硫黄、酸素、窒素などが扱われる。"},
  {"id": 20150424, "year": 201504, "num": 24, "field": "fuel", "text": "重油中の硫黄分が多い場合に起こりやすい障害として、適切なものは次のうちどれか。", "opts": ["燃焼用空気不要化。", "水位の自動安定。", "安全弁の不要化。", "SOx発生や低温腐食。", "灰分の完全消失。"], "ans": 3, "exp": "硫黄分はSOxや硫酸露点、低温腐食と関連する。"},
  {"id": 20150425, "year": 201504, "num": 25, "field": "fuel", "text": "低温腐食を防ぐ考え方として、適切なものは次のうちどれか。", "opts": ["空気予熱器を必ず水で満たす。", "排ガスを必ず0度まで冷やす。", "硫黄分を増やす。", "排ガス温度を酸露点以下にしないよう管理する。", "燃焼用空気をゼロにする。"], "ans": 3, "exp": "低温腐食は酸露点以下で起こりやすく、排ガス温度管理が重要である。"},
  {"id": 20150426, "year": 201504, "num": 26, "field": "fuel", "text": "燃料油の霧化が悪い場合に起こり得ることとして、適切なものは次のうちどれか。", "opts": ["黒煙や未燃分の増加。", "完全燃焼の保証。", "燃料消費ゼロ。", "NOx必ずゼロ。", "水位の自動補正。"], "ans": 0, "exp": "霧化不良は燃料と空気の混合不良を招き、不完全燃焼につながる。"},
  {"id": 20150427, "year": 201504, "num": 27, "field": "fuel", "text": "油バーナの燃焼量調整に関係するものとして、適切なものは次のうちどれか。", "opts": ["作業者の人数だけ。", "水面計の目盛色だけ。", "安全弁の銘板だけ。", "煙突の塗色だけ。", "燃料圧力、戻り油量、空気量など。"], "ans": 4, "exp": "油バーナでは燃料供給量と空気量を適切に調整する。"},
  {"id": 20150428, "year": 201504, "num": 28, "field": "fuel", "text": "バーナタイルの目的として、適切なものは次のうちどれか。", "opts": ["給水を軟化する。", "火炎の安定や燃焼室入口部の保護に役立つ。", "燃料の硫黄を除去する。", "水面計の水位を表示する。", "安全弁を作動させる。"], "ans": 1, "exp": "バーナタイルは火炎保持や高温部保護に関係する部材である。"},
  {"id": 20150429, "year": 201504, "num": 29, "field": "fuel", "text": "都市ガスなどの気体燃料で漏えい検知が重要な理由として、適切なものは次のうちどれか。", "opts": ["給水ポンプを止めるためだけ。", "水質を悪化させるためだけ。", "安全弁の作動圧が上がるためだけ。", "煙突を短くするため。", "空気と混合して爆発性混合気を作るおそれがあるため。"], "ans": 4, "exp": "気体燃料は漏えい時に火災・爆発リスクが大きく、検知と換気が重要である。"},
  {"id": 20150430, "year": 201504, "num": 30, "field": "fuel", "text": "ガス燃料の燃焼管理で確認する事項として、適切なものは次のうちどれか。", "opts": ["安全弁の価格だけ。", "水面計の材質だけ。", "ガス圧、空気量、火炎状態、漏えいの有無。", "燃料タンク底の水だけ。", "ボイラー室の床色だけ。"], "ans": 2, "exp": "ガス燃料では圧力、空気量、火炎、漏えい管理が重要である。"},
  {"id": 20150431, "year": 201504, "num": 31, "field": "law", "text": "伝熱面積の問題で『片面だけが燃焼ガスに触れる』場合の読み方として、適切なものは次のうちどれか。", "opts": ["燃料価格だけで決める。", "すべて両面を無条件に加える。", "算入方法が部位や構造で異なるため条件を確認する。", "作業者数で決める。", "水面計の本数で決める。"], "ans": 2, "exp": "伝熱面積はボイラー種類と伝熱面の条件により扱いが変わる。"},
  {"id": 20150432, "year": 201504, "num": 32, "field": "law", "text": "貫流ボイラーの法令上の扱いで注意すべきこととして、適切なものは次のうちどれか。", "opts": ["伝熱面積や最高使用圧力などの条件を確認する。", "常に法令対象外である。", "燃料がガスならすべて同じ扱いである。", "水処理をすれば区分は不要である。", "煙突高さだけで決まる。"], "ans": 0, "exp": "貫流ボイラーは規模や条件により区分が変わるため、条件読みが重要である。"},
  {"id": 20150433, "year": 201504, "num": 33, "field": "law", "text": "ボイラー室に関する法令問題で見落としやすい条件として、適切なものは次のうちどれか。", "opts": ["出入口、通路、可燃物、換気など。", "作業者の趣味。", "燃料販売店の広告。", "机の色だけ。", "水面計メーカーの所在地。"], "ans": 0, "exp": "ボイラー室では安全な取扱いと避難・火災防止の観点が問われる。"},
  {"id": 20150434, "year": 201504, "num": 34, "field": "law", "text": "ボイラー据付け時の基礎や周囲空間に関する記述として、適切なものは次のうちどれか。", "opts": ["点検できないほど密着させる。", "点検、修理、操作に支障がないようにする。", "出入口をふさぐ。", "可燃物で囲む。", "換気をなくす。"], "ans": 1, "exp": "据付けでは保守点検や安全な操作ができる空間を確保する。"},
  {"id": 20150435, "year": 201504, "num": 35, "field": "law", "text": "ボイラー検査証を滅失した場合の扱いとして、法令問題で注意すべきことは次のうちどれか。", "opts": ["水面計を増やせばよい。", "検査証は不要なので放置する。", "燃料を変えればよい。", "再交付などの手続を確認する。", "安全弁を外せばよい。"], "ans": 3, "exp": "検査証の紛失や記載事項変更は手続問題として問われる。"},
  {"id": 20150436, "year": 201504, "num": 36, "field": "law", "text": "検査証の記載事項変更で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["燃料価格だけで判断する。", "どの変更も届出不要である。", "作業者の昼食だけを届け出る。", "所有者や設置場所など、変更内容に応じた手続を確認する。", "水面計の色だけで判断する。"], "ans": 3, "exp": "検査証記載事項の変更は、必要な手続と期限を問われることがある。"},
  {"id": 20150437, "year": 201504, "num": 37, "field": "law", "text": "廃止したボイラーに関する手続問題で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["水面計だけ外せばよい。", "廃止すれば記録も検査証も必ず放置してよい。", "燃料を抜けば手続不要と決めつける。", "煙突だけ残せば使用中とみなす。", "廃止届や検査証返還などの扱いを確認する。"], "ans": 4, "exp": "廃止時は届出や検査証の扱いが問われる。"},
  {"id": 20150438, "year": 201504, "num": 38, "field": "law", "text": "休止中のボイラーを再使用する場合の注意として、適切なものは次のうちどれか。", "opts": ["休止期間や検査証有効期間、必要検査を確認する。", "必ず無検査で再使用できる。", "燃料を入れれば直ちに使用できる。", "水面計を外したまま使用する。", "安全弁を固定して使用する。"], "ans": 0, "exp": "再使用では休止期間や検査証の状態に応じた手続確認が必要である。"},
  {"id": 20150439, "year": 201504, "num": 39, "field": "law", "text": "作業主任者が圧力の急激な上昇を防ぐべき理由として、適切なものは次のうちどれか。", "opts": ["煙突高さを上げるため。", "燃料価格を下げるためだけ。", "水面計の色を変えるため。", "過圧や熱応力などの危険を防ぐため。", "検査証を不要にするため。"], "ans": 3, "exp": "作業主任者は圧力、水位、燃焼などを監視し、安全な運転を確保する。"},
  {"id": 20150440, "year": 201504, "num": 40, "field": "law", "text": "ボイラー取扱者に必要な基本姿勢として、適切なものは次のうちどれか。", "opts": ["燃料漏れを放置する。", "安全装置を無効化する。", "水位を見ない。", "異常兆候を見逃さず、手順と法令に従う。", "検査証を破棄する。"], "ans": 3, "exp": "取扱者には安全確認、手順遵守、異常時対応が求められる。"},
  {"id": 20151001, "year": 201510, "num": 1, "field": "structure", "text": "節炭器の水漏れが疑われる兆候として、適切なものは次のうちどれか。", "opts": ["安全弁の不要化。", "燃料発熱量の上昇。", "水位計の消失。", "煙道内の湿りや給水量の異常増加。", "煙突高さの自動上昇。"], "ans": 3, "exp": "節炭器漏れでは煙道側への水漏れ、給水量変化、排ガス状態変化などに注意する。"},
  {"id": 20151002, "year": 201510, "num": 2, "field": "structure", "text": "空気予熱器で燃焼用空気を予熱する利点として、適切なものは次のうちどれか。", "opts": ["安全弁の作動を止める。", "水位確認を不要にする。", "燃料中の灰分をなくす。", "燃焼改善と熱効率向上に役立つ。", "給水を軟化する。"], "ans": 3, "exp": "空気予熱器は排熱を利用して燃焼用空気を温め、効率改善に寄与する。"},
  {"id": 20151003, "year": 201510, "num": 3, "field": "structure", "text": "給水ポンプのキャビテーションに関する記述として、適切なものは次のうちどれか。", "opts": ["煙突の自然通風をいう。", "燃料の完全燃焼をいう。", "水面計の吹出しをいう。", "安全弁の吹出しをいう。", "吸込み側圧力低下などで気泡が発生し、騒音や損傷を招く。"], "ans": 4, "exp": "キャビテーションはポンプ内で気泡が発生・崩壊し、性能低下や損傷につながる現象である。"},
  {"id": 20151004, "year": 201510, "num": 4, "field": "structure", "text": "水面計を2個設ける趣旨として、適切なものは次のうちどれか。", "opts": ["煙突通風を止めるため。", "水位を見えにくくするため。", "燃料を節約するためだけ。", "蒸気圧を下げるためだけ。", "一方に異常があっても水位確認の信頼性を高めるため。"], "ans": 4, "exp": "水面計は低水位事故防止に重要で、複数設置により確認の信頼性を高める。"},
  {"id": 20151005, "year": 201510, "num": 5, "field": "structure", "text": "安全弁の弁座漏れがある場合の影響として、適切なものは次のうちどれか。", "opts": ["燃焼効率が必ず上がる。", "蒸気漏れによる損失や作動不良につながる。", "水質が必ず改善する。", "給水が不要になる。", "低水位が起こらなくなる。"], "ans": 1, "exp": "安全弁の漏れは蒸気損失や機能低下の原因となるため点検が必要である。"},
  {"id": 20151006, "year": 201510, "num": 6, "field": "structure", "text": "圧力計の目盛範囲に関する記述として、適切なものは次のうちどれか。", "opts": ["目盛は全く不要である。", "使用圧力を読み取りやすく、過圧も確認できる範囲が必要である。", "燃料の粘度だけを表示すればよい。", "水位だけを表示すればよい。", "煙突高さだけを表示すればよい。"], "ans": 1, "exp": "圧力計は運転圧力と安全管理に必要な範囲を読み取れるものを用いる。"},
  {"id": 20151007, "year": 201510, "num": 7, "field": "structure", "text": "インタロックに関する記述として、適切なものは次のうちどれか。", "opts": ["水処理薬剤の名称である。", "燃料を加熱するだけの装置である。", "必要条件が満たされないと燃焼開始などを許可しない仕組みである。", "煙突内のすすである。", "安全弁のばね材料である。"], "ans": 2, "exp": "燃焼安全では、送風や火炎検出などの条件を満たさないと燃料供給しない制御が重要である。"},
  {"id": 20151008, "year": 201510, "num": 8, "field": "structure", "text": "シーケンス制御に関する記述として、適切なものは次のうちどれか。", "opts": ["水の硬度だけを下げる制御である。", "点火、燃焼、停止などを所定の順序で進める制御である。", "燃料の硫黄分を測る制御である。", "安全弁を固定する制御である。", "煙突高さを測る制御である。"], "ans": 1, "exp": "シーケンス制御は、安全な順序で機器を動作させるために用いられる。"},
  {"id": 20151009, "year": 201510, "num": 9, "field": "structure", "text": "高圧燃料遮断に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料中の水分を増やす機能である。", "給水を加熱する機能である。", "水位を高く表示する機能である。", "蒸気圧力が異常に上昇したとき燃料供給を止める安全機能である。", "煙突を冷却する機能である。"], "ans": 3, "exp": "高圧時の燃料遮断は過圧事故を防ぐための安全機能である。"},
  {"id": 20151010, "year": 201510, "num": 10, "field": "structure", "text": "蒸気止め弁に関する記述として、適切なものは次のうちどれか。", "opts": ["給水中の酸素を除去する薬剤である。", "ボイラーから蒸気を送る配管を開閉するために設ける。", "燃料油をろ過する装置である。", "煙突内の通風力を発生させる装置である。", "水面計の代わりに水位を示す装置である。"], "ans": 1, "exp": "蒸気止め弁は蒸気の送出を開閉する重要な附属品である。"},
  {"id": 20151011, "year": 201510, "num": 11, "field": "handling", "text": "ウォータハンマが起こりやすい状況として、適切なものは次のうちどれか。", "opts": ["燃料タンクが空である。", "蒸気配管内に復水がたまっている。", "煙突が高い。", "安全弁の銘板が読める。", "給水が軟化されている。"], "ans": 1, "exp": "蒸気配管内の復水はウォータハンマの原因となるため、ドレン排出が重要である。"},
  {"id": 20151012, "year": 201510, "num": 12, "field": "handling", "text": "長期停止前の清掃で重視すべきこととして、適切なものは次のうちどれか。", "opts": ["煙道を詰まらせる。", "燃料漏れを放置する。", "水位計を破損させる。", "安全弁を固定する。", "スラッジやすすを除去し、腐食原因を減らす。"], "ans": 4, "exp": "停止保存前は内部・外部の汚れを除去して腐食や劣化を防ぐ。"},
  {"id": 20151013, "year": 201510, "num": 13, "field": "handling", "text": "満水保存でボイラー水を満たす理由として、適切なものは次のうちどれか。", "opts": ["煙突を洗うため。", "燃料を増やすため。", "安全弁を作動させ続けるため。", "水面計を隠すため。", "空気との接触を減らして腐食を抑えるため。"], "ans": 4, "exp": "満水保存は脱酸素した水で満たし、酸素接触を抑える保存法である。"},
  {"id": 20151014, "year": 201510, "num": 14, "field": "handling", "text": "燃焼安全装置のリセット後に直ちに再点火してよいかについて、適切なものは次のうちどれか。", "opts": ["原因確認と換気など安全確認が必要である。", "原因を確認せず何度も再点火してよい。", "燃料を増やして再点火する。", "火炎検出器を外す。", "低水位警報を止める。"], "ans": 0, "exp": "安全装置が作動した場合は原因を確認し、未燃ガス排出などを行ってから再点火する。"},
  {"id": 20151015, "year": 201510, "num": 15, "field": "handling", "text": "火炎検出器の点検で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["常に取り外して運転する。", "汚れているほど感度が上がる。", "汚れ、取付位置、検出状態を確認する。", "水位確認の代わりに使う。", "燃料の硫黄分を測る。"], "ans": 2, "exp": "火炎検出器の異常は失火検出や燃料遮断に影響する。"},
  {"id": 20151016, "year": 201510, "num": 16, "field": "handling", "text": "逆火が発生した場合の対応として、適切なものは次のうちどれか。", "opts": ["炉内換気をしない。", "燃料をさらに多く送る。", "燃料を遮断し、原因を確認してから再点火する。", "安全装置を無効にする。", "水位を見ずに運転を続ける。"], "ans": 2, "exp": "逆火は燃焼異常であり、燃料遮断、換気、原因確認が必要である。"},
  {"id": 20151017, "year": 201510, "num": 17, "field": "handling", "text": "燃料油圧が異常に低い場合に疑う事項として、適切なものは次のうちどれか。", "opts": ["水位が高いことだけ。", "ストレーナ詰まり、ポンプ不良、弁の状態など。", "安全弁の口径だけ。", "煙突高さだけ。", "ボイラー検査証の有効期間だけ。"], "ans": 1, "exp": "燃料油圧異常では燃料系統の詰まり、漏れ、ポンプ、弁を確認する。"},
  {"id": 20151018, "year": 201510, "num": 18, "field": "handling", "text": "排ガス温度が通常より高い場合に疑うこととして、適切なものは次のうちどれか。", "opts": ["伝熱面のすす付着やスケール付着。", "水質が必ず完全であること。", "燃料が不要になったこと。", "安全弁が不要になったこと。", "水面計の閉塞だけ。"], "ans": 0, "exp": "排ガス温度上昇は伝熱不良や燃焼過剰などのサインとなる。"},
  {"id": 20151019, "year": 201510, "num": 19, "field": "handling", "text": "日常点検で給水系統について確認する事項として、適切なものは次のうちどれか。", "opts": ["安全弁の価格だけ。", "燃料販売店の所在地だけ。", "煙突の塗装色だけ。", "ポンプ、弁、漏れ、圧力、給水量など。", "作業者の通勤経路だけ。"], "ans": 3, "exp": "給水系統の異常は低水位や運転停止につながるため、日常確認が重要である。"},
  {"id": 20151020, "year": 201510, "num": 20, "field": "handling", "text": "燃焼状態の目視確認で見る事項として、適切なものは次のうちどれか。", "opts": ["水処理薬剤の容器色だけ。", "作業靴の色だけ。", "検査証の紙質だけ。", "火炎の形、色、安定性、煙の状態など。", "燃料販売店の看板だけ。"], "ans": 3, "exp": "火炎や煙の状態は燃焼良否を判断する基本情報である。"},
  {"id": 20151021, "year": 201510, "num": 21, "field": "fuel", "text": "炉内圧が正圧になりすぎた場合の問題として、適切なものは次のうちどれか。", "opts": ["安全弁が不要になる。", "水質が必ず改善する。", "燃料消費がゼロになる。", "火炎や燃焼ガスの噴出のおそれがある。", "排ガスが発生しない。"], "ans": 3, "exp": "炉内圧の過度な正圧は燃焼ガス漏れや安全上の問題を招く。"},
  {"id": 20151022, "year": 201510, "num": 22, "field": "fuel", "text": "通風が強すぎる場合に起こり得ることとして、適切なものは次のうちどれか。", "opts": ["燃料が不要になる。", "火炎が不安定になり、排ガス熱損失が増えることがある。", "水位が必ず上がる。", "スケールが瞬時に消える。", "安全弁が開かなくなる。"], "ans": 1, "exp": "過大通風は燃焼不安定や熱損失増加の原因になる。"},
  {"id": 20151023, "year": 201510, "num": 23, "field": "fuel", "text": "空気不足で増加しやすいものとして、適切なものは次のうちどれか。", "opts": ["ボイラー検査証の枚数。", "給水硬度の低下。", "安全弁数。", "一酸化炭素。", "水面計の長さ。"], "ans": 3, "exp": "空気不足では不完全燃焼となりCOやすすが増加しやすい。"},
  {"id": 20151024, "year": 201510, "num": 24, "field": "fuel", "text": "燃焼温度が高いほど増加しやすい大気汚染物質として、適切なものは次のうちどれか。", "opts": ["NOx。", "水蒸気の乾き度。", "給水硬度。", "安全弁口径。", "ボイラー室照度。"], "ans": 0, "exp": "高温燃焼ではサーマルNOxが増加しやすい。"},
  {"id": 20151025, "year": 201510, "num": 25, "field": "fuel", "text": "理論空気量に関する記述として、適切なものは次のうちどれか。", "opts": ["安全弁の吹出し量である。", "実際に必ず供給してはならない空気量である。", "水処理に必要な薬剤量である。", "燃料を完全燃焼させるのに理論上必要な最小空気量である。", "煙突高さの別名である。"], "ans": 3, "exp": "理論空気量は完全燃焼に必要な最小空気量で、実際には過剰空気を加える。"},
  {"id": 20151026, "year": 201510, "num": 26, "field": "fuel", "text": "空気比に関する記述として、適切なものは次のうちどれか。", "opts": ["実際空気量を理論空気量で割った値である。", "燃料の密度を水の密度で割った値である。", "水位を胴径で割った値である。", "安全弁口径を圧力で割った値である。", "煙突高さを室温で割った値である。"], "ans": 0, "exp": "空気比は実際に供給した空気量と理論空気量の比である。"},
  {"id": 20151027, "year": 201510, "num": 27, "field": "fuel", "text": "排ガス中CO2濃度が燃焼管理で使われる理由として、適切なものは次のうちどれか。", "opts": ["燃料価格を示すため。", "水位を直接示すため。", "給水硬度を示すため。", "安全弁の設定圧を示すため。", "空気比や燃焼状態を推定する手掛かりになるため。"], "ans": 4, "exp": "CO2、O2、COは燃焼状態や過剰空気判断の指標として用いられる。"},
  {"id": 20151028, "year": 201510, "num": 28, "field": "fuel", "text": "白煙が見える場合に考えられるものとして、適切なものは次のうちどれか。", "opts": ["水蒸気の凝縮や燃料中水分など。", "必ず完全燃焼で異常なし。", "必ず燃料がない。", "安全弁が開いている証拠だけ。", "水面計が正常な証拠だけ。"], "ans": 0, "exp": "白煙は水蒸気の凝縮などの場合があるが、燃料や燃焼状態と合わせて判断する。"},
  {"id": 20151029, "year": 201510, "num": 29, "field": "fuel", "text": "燃焼効率を悪化させる要因として、適切でないものは次のうちどれか。", "opts": ["過大な過剰空気", "伝熱面のすす付着", "適正な空気比と清浄な伝熱面", "燃料の霧化不良", "排ガス温度の過大"], "ans": 2, "exp": "適正空気比と清浄な伝熱面は効率維持に有効である。"},
  {"id": 20151030, "year": 201510, "num": 30, "field": "fuel", "text": "燃焼に必要な三要素として、適切な組合せは次のうちどれか。", "opts": ["給水、吹出し、保存。", "水位、圧力、検査証。", "安全弁、水面計、圧力計。", "可燃物、酸素、点火源又は温度。", "煙突、床、照明。"], "ans": 3, "exp": "燃焼には可燃物、酸素、着火に足る温度又は点火源が必要である。"},
  {"id": 20151031, "year": 201510, "num": 31, "field": "law", "text": "安全弁の調整に関する記述として、適切なものは次のうちどれか。", "opts": ["水面計の代わりに使う。", "運転中に任意に締め込んでよい。", "作動しないよう固定する。", "燃料節約のため封鎖する。", "みだりに調整を変更してはならない。"], "ans": 4, "exp": "安全弁は過圧防止の重要装置であり、勝手な調整や固定は危険である。"},
  {"id": 20151032, "year": 201510, "num": 32, "field": "law", "text": "水面計の機能保持に関する記述として、適切なものは次のうちどれか。", "opts": ["見やすく、閉塞や漏れがない状態に保つ。", "常に閉じて見えないようにする。", "水位を隠す。", "燃料油を流す。", "安全弁の代わりに用いる。"], "ans": 0, "exp": "水面計は低水位事故防止に直結するため、機能保持が重要である。"},
  {"id": 20151033, "year": 201510, "num": 33, "field": "law", "text": "圧力計の機能確認で注意することとして、適切なものは次のうちどれか。", "opts": ["目盛を隠す。", "常に指針を固定する。", "指示の戻り、漏れ、コックの開閉状態などを確認する。", "燃料を通す。", "水処理薬剤を注入する。"], "ans": 2, "exp": "圧力計は過圧防止の基本情報を示すため、指示異常や閉塞に注意する。"},
  {"id": 20151034, "year": 201510, "num": 34, "field": "law", "text": "定期自主検査で附属品を点検する意義として、適切なものは次のうちどれか。", "opts": ["作業主任者を不要にするため。", "検査証を不要にするため。", "燃料価格を下げるためだけ。", "安全運転に必要な機器の異常を早期に発見するため。", "水位確認をやめるため。"], "ans": 3, "exp": "附属品の異常は事故に直結するため、定期的な確認が重要である。"},
  {"id": 20151035, "year": 201510, "num": 35, "field": "law", "text": "定期自主検査の補修結果に関する記録として、適切なものは次のうちどれか。", "opts": ["異常の内容と補修内容を記録する。", "異常があっても記録しない。", "燃料販売店だけを記録する。", "作業者の趣味だけを記録する。", "煙突の色だけを記録する。"], "ans": 0, "exp": "定期自主検査では点検結果と補修内容の記録が重要である。"},
  {"id": 20151036, "year": 201510, "num": 36, "field": "law", "text": "法令問題で『遅滞なく』とある場合の注意として、適切なものは次のうちどれか。", "opts": ["水位で意味が変わる。", "いつでもよいという意味である。", "必ず1年後という意味である。", "燃料の種類で意味が変わる。", "期限表現を読み落とさず、手続のタイミングを確認する。"], "ans": 4, "exp": "法令の期限語は手続問題で正誤を分ける。"},
  {"id": 20151037, "year": 201510, "num": 37, "field": "law", "text": "法令問題で『所轄労働基準監督署長』が出る場合の注意として、適切なものは次のうちどれか。", "opts": ["安全弁の形式名である。", "燃料販売店のことと考える。", "作業主任者の別名である。", "水面計のメーカーである。", "届出先や申請先を混同しない。"], "ans": 4, "exp": "届出・申請・検査では相手先を問う問題が出やすい。"},
  {"id": 20151038, "year": 201510, "num": 38, "field": "law", "text": "数値条件がある法令問題の解き方として、適切なものは次のうちどれか。", "opts": ["燃料名だけで選ぶ。", "数値を読まずに選ぶ。", "常に最も長い選択肢を選ぶ。", "単位、以上・未満、除外条件をセットで確認する。", "問題番号で選ぶ。"], "ans": 3, "exp": "法令問題は境界値、単位、対象除外の読み違いが失点原因になりやすい。"},
  {"id": 20151039, "year": 201510, "num": 39, "field": "law", "text": "『ただし書き』がある選択肢を読む際の注意として、適切なものは次のうちどれか。", "opts": ["例外は常に本文を取り消さない。", "ただし書きは必ず無視する。", "本文と例外条件の両方を確認する。", "燃料の色で判断する。", "水面計の数だけで判断する。"], "ans": 2, "exp": "ただし書きは適用範囲や例外を示し、正誤に直結することがある。"},
  {"id": 20151040, "year": 201510, "num": 40, "field": "law", "text": "法令問題で『直ちに』と『遅滞なく』が問われた場合の基本姿勢として、適切なものは次のうちどれか。", "opts": ["燃料の種類だけで決める。", "どちらも必ず1年後という意味である。", "どちらも手続不要という意味である。", "手続の緊急度や期限表現を区別して読む。", "水位だけで決める。"], "ans": 3, "exp": "期限表現は届出や報告の正誤に関わるため、文言を区別する。"},
  {"id": 20180401, "year": 201804, "num": 1, "field": "structure", "text": "飽和蒸気表を用いる目的として、適切なものは次のうちどれか。", "opts": ["煙突の塗装方法を決める。", "燃料タンクの容量だけを調べる。", "水面計の本数を決める。", "安全弁の色を決める。", "圧力に対応する飽和温度やエンタルピなどを調べる。"], "ans": 4, "exp": "飽和蒸気表は圧力、温度、比体積、エンタルピなど蒸気の状態量を調べるために用いる。"},
  {"id": 20180402, "year": 201804, "num": 2, "field": "structure", "text": "ゲージ圧力に関する記述として、適切なものは次のうちどれか。", "opts": ["完全真空を基準として測った圧力である。", "大気圧を基準として測った圧力である。", "燃料の発熱量である。", "水位を質量で表した値である。", "煙突の通風力だけを表す。"], "ans": 1, "exp": "通常の圧力計は大気圧を基準としたゲージ圧を示す。"},
  {"id": 20180403, "year": 201804, "num": 3, "field": "structure", "text": "蒸発熱に関する記述として、適切なものは次のうちどれか。", "opts": ["飽和水を飽和蒸気にするために必要な熱である。", "水の温度を0度まで下げる熱である。", "燃料の灰分を表す値である。", "安全弁の口径を表す値である。", "水面計の長さを表す値である。"], "ans": 0, "exp": "蒸発熱は液体から気体への状態変化に必要な潜熱である。"},
  {"id": 20180404, "year": 201804, "num": 4, "field": "structure", "text": "蒸気の比体積に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料の硫黄分である。", "単位体積当たりの質量である。", "単位質量当たりの体積である。", "給水の硬度である。", "安全弁のばね力である。"], "ans": 2, "exp": "比体積は密度の逆数で、1kg当たりの体積を表す。"},
  {"id": 20180405, "year": 201804, "num": 5, "field": "structure", "text": "伝熱面の外部腐食に関する記述として、適切なものは次のうちどれか。", "opts": ["安全弁の作動だけで起こる。", "給水の硬度だけで必ず発生する。", "燃料を使わないと必ず発生する。", "水面計の閉塞だけが原因である。", "燃焼ガス中の成分や結露により煙道側から腐食することがある。"], "ans": 4, "exp": "外部腐食は燃焼ガス側での酸露点腐食や湿気などが関係する。"},
  {"id": 20180406, "year": 201804, "num": 6, "field": "structure", "text": "燃焼室容積が小さすぎる場合に起こり得ることとして、適切なものは次のうちどれか。", "opts": ["水位が自動で安定する。", "完全燃焼が必ず保証される。", "燃料が不要になる。", "燃焼が完結しにくく、未燃分やばいじんが増えることがある。", "安全弁が不要になる。"], "ans": 3, "exp": "燃焼には適切な空間、温度、混合、時間が必要である。"},
  {"id": 20180407, "year": 201804, "num": 7, "field": "structure", "text": "水管ボイラーの長所として、適切なものは次のうちどれか。", "opts": ["水循環が常に不要である。", "高圧大容量に適した構造としやすい。", "安全弁を設けられない。", "給水管理が不要である。", "燃焼室を持てない。"], "ans": 1, "exp": "水管ボイラーは水管内の水を加熱する構造で、高圧大容量に適用しやすい。"},
  {"id": 20180408, "year": 201804, "num": 8, "field": "structure", "text": "水管の過熱を防ぐために重要なこととして、適切なものは次のうちどれか。", "opts": ["適正な水循環と水質管理を保つ。", "水位を常に下げる。", "スケールを厚く付ける。", "給水を止める。", "吹出しを行わない。"], "ans": 0, "exp": "水管の冷却には水循環が重要で、スケール付着も過熱の原因となる。"},
  {"id": 20180409, "year": 201804, "num": 9, "field": "structure", "text": "炉筒煙管ボイラーで煙管にすすが付着した場合の影響として、適切なものは次のうちどれか。", "opts": ["安全弁が不要になる。", "伝熱が必ず良くなる。", "水処理が不要になる。", "伝熱が悪くなり、排ガス温度が高くなることがある。", "燃料中の水分がなくなる。"], "ans": 3, "exp": "煙管のすす付着は熱効率低下につながる。"},
  {"id": 20180410, "year": 201804, "num": 10, "field": "structure", "text": "貫流ボイラーの始動停止に関する特徴として、適切なものは次のうちどれか。", "opts": ["保有水量が非常に多く、常に始動に数日を要する。", "保有水量が少なく、比較的短時間で始動停止しやすい。", "燃料を使わない。", "給水ポンプが不要である。", "蒸気を発生しない。"], "ans": 1, "exp": "貫流ボイラーは保有水量が少なく、応答が速い一方で制御と水質管理が重要である。"},
  {"id": 20180411, "year": 201804, "num": 11, "field": "handling", "text": "点火前に炉内を換気する時間や回数を守る理由として、適切なものは次のうちどれか。", "opts": ["未燃ガスを十分に排出するため。", "水位を高く見せるため。", "燃料の発熱量を増やすため。", "安全弁の設定を変えるため。", "給水を軟化するため。"], "ans": 0, "exp": "点火前換気は未燃ガス爆発を防ぐ基本操作である。"},
  {"id": 20180412, "year": 201804, "num": 12, "field": "handling", "text": "手動点火で火種を近づける順序として、安全上適切な考え方は次のうちどれか。", "opts": ["火炎を確認せず燃料を増やす。", "燃料を先に多量に出してから火種を探す。", "換気せずに燃料を出す。", "火種を先に置き、燃料を後から供給する。", "安全装置を外して点火する。"], "ans": 3, "exp": "燃料を先に出すと未燃燃料がたまり危険である。"},
  {"id": 20180413, "year": 201804, "num": 13, "field": "handling", "text": "水面計の吹出し後に確認すべきこととして、適切なものは次のうちどれか。", "opts": ["水位が速やかに正常位置へ戻るか確認する。", "水位を見ない。", "燃料を最大にする。", "安全弁を固定する。", "吹出し弁を開けたままにする。"], "ans": 0, "exp": "吹出し後の水位復帰で連絡管の閉塞や機能異常を確認する。"},
  {"id": 20180414, "year": 201804, "num": 14, "field": "handling", "text": "水位が高すぎる運転で起こり得ることとして、適切なものは次のうちどれか。", "opts": ["給水が完全に止まる。", "低水位事故だけが起こる。", "燃料が不要になる。", "キャリオーバを起こしやすい。", "安全弁が必ず不要になる。"], "ans": 3, "exp": "高水位は蒸気側への水分持込み、すなわちキャリオーバの原因となる。"},
  {"id": 20180415, "year": 201804, "num": 15, "field": "handling", "text": "給水弁の開度を急変させることが適切でない理由として、適切なものは次のうちどれか。", "opts": ["水位や圧力の急変、熱応力を招くことがある。", "燃料の発熱量が必ず下がる。", "煙突高さが変わる。", "安全弁の数が増える。", "水処理が不要になる。"], "ans": 0, "exp": "給水操作は水位、圧力、胴温度に影響するため慎重に行う。"},
  {"id": 20180416, "year": 201804, "num": 16, "field": "handling", "text": "連続吹出しの管理で見る指標として、適切なものは次のうちどれか。", "opts": ["水面計の製造年月だけ。", "燃料販売店の距離。", "ボイラー水の濃度や電気伝導率。", "安全弁の塗色だけ。", "煙突の外観色だけ。"], "ans": 2, "exp": "連続吹出しは濃縮管理のために行い、電気伝導率などを参考にする。"},
  {"id": 20180417, "year": 201804, "num": 17, "field": "handling", "text": "吹出しを過度に行った場合の問題として、適切なものは次のうちどれか。", "opts": ["燃料消費が必ずゼロになる。", "熱損失が増え、水位低下のおそれがある。", "給水が不要になる。", "安全弁が不要になる。", "燃焼用空気が不要になる。"], "ans": 1, "exp": "過度の吹出しは熱と水を失うため、適正量の管理が必要である。"},
  {"id": 20180418, "year": 201804, "num": 18, "field": "handling", "text": "軟化装置の目的として、適切なものは次のうちどれか。", "opts": ["排ガス中の酸素を増やす。", "燃料の粘度を高める。", "給水中の硬度成分を減らしスケールを防ぐ。", "安全弁の作動圧を下げる。", "水面計を不要にする。"], "ans": 2, "exp": "軟化装置はカルシウム、マグネシウムなど硬度成分を減らす。"},
  {"id": 20180419, "year": 201804, "num": 19, "field": "handling", "text": "給水加熱や脱気の効果として、適切なものは次のうちどれか。", "opts": ["燃料の硫黄分を増やす。", "溶存酸素を減らし、熱効率や腐食防止に役立つ。", "水位計を不要にする。", "安全弁を固定する。", "スケールを厚くする。"], "ans": 1, "exp": "給水加熱は熱効率向上のほか、脱気により腐食抑制にも寄与する。"},
  {"id": 20180420, "year": 201804, "num": 20, "field": "handling", "text": "ボイラー水のpHが低すぎる場合に起こりやすい障害として、適切なものは次のうちどれか。", "opts": ["水位の自動安定。", "燃料の完全燃焼。", "腐食。", "安全弁の増設。", "排ガス熱損失の消失。"], "ans": 2, "exp": "酸性側では腐食が進みやすくなるため、pH管理が重要である。"},
  {"id": 20180421, "year": 201804, "num": 21, "field": "fuel", "text": "燃料中の炭素が完全燃焼したとき主に生じるものとして、適切なものは次のうちどれか。", "opts": ["硫酸。", "一酸化炭素だけ。", "水素。", "二酸化炭素。", "窒素酸化物だけ。"], "ans": 3, "exp": "炭素が完全燃焼するとCO2になる。不完全燃焼ではCOが発生する。"},
  {"id": 20180422, "year": 201804, "num": 22, "field": "fuel", "text": "燃料中の水素が完全燃焼したとき主に生じるものとして、適切なものは次のうちどれか。", "opts": ["二酸化硫黄。", "水蒸気。", "一酸化炭素。", "灰分。", "窒素。"], "ans": 1, "exp": "水素の燃焼生成物は水であり、排ガス中では水蒸気として存在する。"},
  {"id": 20180423, "year": 201804, "num": 23, "field": "fuel", "text": "燃料の粘度が高すぎる場合の影響として、適切なものは次のうちどれか。", "opts": ["噴霧不良を起こしやすい。", "完全燃焼が必ず保証される。", "空気が不要になる。", "水位が安定する。", "安全弁が不要になる。"], "ans": 0, "exp": "粘度が高すぎる燃料油は微粒化しにくく、燃焼不良につながる。"},
  {"id": 20180424, "year": 201804, "num": 24, "field": "fuel", "text": "重油燃焼でバナジウムなどの灰分が問題となる理由として、適切なものは次のうちどれか。", "opts": ["燃料の発熱量を必ず高めるため。", "水位を正確に示すため。", "高温腐食や灰付着の原因となることがある。", "安全弁を作動させるため。", "給水を軟化するため。"], "ans": 2, "exp": "重油中の灰分成分は付着や高温腐食の原因として扱われる。"},
  {"id": 20180425, "year": 201804, "num": 25, "field": "fuel", "text": "燃料油タンクの水抜きが必要な理由として、適切なものは次のうちどれか。", "opts": ["空気比をゼロにするため。", "燃料の硫黄分を増やすため。", "水分混入による燃焼不良や腐食を防ぐため。", "安全弁を不要にするため。", "水面計を洗うため。"], "ans": 2, "exp": "タンク底部の水分はバーナ不調や腐食につながるため排出する。"},
  {"id": 20180426, "year": 201804, "num": 26, "field": "fuel", "text": "空気噴霧式バーナに関する記述として、適切なものは次のうちどれか。", "opts": ["水面計で燃料を霧化する。", "蒸気を発生させない。", "圧縮空気を用いて燃料油を霧化する。", "安全弁で燃料を霧化する。", "燃料を固体のまま燃やす。"], "ans": 2, "exp": "空気噴霧式は霧化媒体として圧縮空気を用いる。"},
  {"id": 20180427, "year": 201804, "num": 27, "field": "fuel", "text": "蒸気噴霧式バーナの特徴として、適切なものは次のうちどれか。", "opts": ["燃料を霧化できない。", "蒸気を全く使わない。", "空気を全く必要としない。", "比較的広い燃焼量範囲に対応しやすいが霧化蒸気を消費する。", "水処理装置である。"], "ans": 3, "exp": "蒸気噴霧式は霧化性能に利点があるが、蒸気消費がある。"},
  {"id": 20180428, "year": 201804, "num": 28, "field": "fuel", "text": "バーナのターンダウン比に関する記述として、適切なものは次のうちどれか。", "opts": ["安定燃焼できる最大燃焼量と最小燃焼量の比である。", "水位と圧力の比である。", "燃料密度と水密度の比だけである。", "安全弁口径と煙突高さの比である。", "給水量と吹出し量の和である。"], "ans": 0, "exp": "ターンダウン比は燃焼量調整範囲を示す。"},
  {"id": 20180429, "year": 201804, "num": 29, "field": "fuel", "text": "ガス燃料の比重に関する安全上の注意として、適切なものは次のうちどれか。", "opts": ["比重が大きいほど必ず無害である。", "比重は漏えい時の危険に関係しない。", "空気より重いか軽いかで滞留しやすい場所が異なる。", "比重は水位だけを示す。", "安全弁の設定圧だけを示す。"], "ans": 2, "exp": "ガス漏えい時の滞留場所はガスの比重や換気条件に左右される。"},
  {"id": 20180430, "year": 201804, "num": 30, "field": "fuel", "text": "ガス遮断弁の役割として、適切なものは次のうちどれか。", "opts": ["排ガス中のCO2を増やすだけ。", "給水を軟化する。", "異常時に燃料ガスの供給を止める。", "水面計の水位を示す。", "安全弁を固定する。"], "ans": 2, "exp": "ガス遮断弁は燃焼安全装置として漏えいや失火時の燃料供給を止める。"},
  {"id": 20180431, "year": 201804, "num": 31, "field": "law", "text": "伝熱面積の算定で『水管』が出た場合に注意すべきこととして、適切なものは次のうちどれか。", "opts": ["水面計の数で算定する。", "必ず管の内外両面を二重に加える。", "燃料の種類だけで算定する。", "作業者数で算定する。", "管のどの面を伝熱面として扱うかを規定に従って読む。"], "ans": 4, "exp": "伝熱面積は部位ごとの算定方法が問われる。"},
  {"id": 20180432, "year": 201804, "num": 32, "field": "law", "text": "温水ボイラーに関する法令問題で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["燃料が同じならすべて同じ扱いである。", "温水なので法令は常に無関係である。", "圧力、温度、伝熱面積などの条件を確認する。", "水面計の有無だけで決める。", "煙突高さだけで決める。"], "ans": 2, "exp": "温水ボイラーも条件によって法令上の区分が変わる。"},
  {"id": 20180433, "year": 201804, "num": 33, "field": "law", "text": "燃料タンクをボイラー室内に置く場合の注意として、適切なものは次のうちどれか。", "opts": ["出入口をふさぐ。", "炉前にこぼしておく。", "火災防止や漏えい防止、配置の条件を確認する。", "換気をなくす。", "安全弁につなぐ。"], "ans": 2, "exp": "燃料の保管は火災防止と避難・操作空間確保の観点で問われる。"},
  {"id": 20180434, "year": 201804, "num": 34, "field": "law", "text": "ボイラー室の照明に関する問題で重視される考え方として、適切なものは次のうちどれか。", "opts": ["水面計を見えなくする。", "常に暗くして運転する。", "計器や水位を確認し安全に操作できる明るさを確保する。", "圧力計を隠す。", "出入口をふさぐ。"], "ans": 2, "exp": "取扱いに必要な計器や水位を確認できる作業環境が必要である。"},
  {"id": 20180435, "year": 201804, "num": 35, "field": "law", "text": "検査証の有効期間が満了する前に必要な対応として、適切なものは次のうちどれか。", "opts": ["水面計を増やせば検査不要である。", "満了後も無条件に使用し続ける。", "燃料を変えれば検査不要である。", "性能検査を受けるなど継続使用の手続を確認する。", "安全弁を閉じれば検査不要である。"], "ans": 3, "exp": "継続使用には性能検査と検査証の有効期間管理が重要である。"},
  {"id": 20180436, "year": 201804, "num": 36, "field": "law", "text": "落成検査を受ける前に使用してよいかを問う問題での基本は次のうちどれか。", "opts": ["原則として必要な検査に合格してから使用する。", "検査前でも常に自由に使用できる。", "燃料が軽油なら検査不要である。", "水位が見えれば検査不要である。", "安全弁を外せば検査不要である。"], "ans": 0, "exp": "設置後の使用開始には法令上必要な検査を確認する。"},
  {"id": 20180437, "year": 201804, "num": 37, "field": "law", "text": "変更検査と性能検査の違いとして、適切なものは次のうちどれか。", "opts": ["変更検査は主要部分変更時、性能検査は継続使用時に関連する。", "どちらも燃料購入時の検査である。", "どちらも水質試験だけである。", "どちらも毎日の点火前点検である。", "違いは存在しない。"], "ans": 0, "exp": "検査名と実施場面を整理することが法令問題の基本である。"},
  {"id": 20180438, "year": 201804, "num": 38, "field": "law", "text": "ボイラーの移設に関する問題で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["水面計を外せば全て不要である。", "移設なら手続は常に不要である。", "燃料を抜けば全て不要である。", "設置場所変更に伴う届出や検査を確認する。", "煙突だけ移せばよい。"], "ans": 3, "exp": "設置場所の変更は届出や検査証の扱いに関係する。"},
  {"id": 20180439, "year": 201804, "num": 39, "field": "law", "text": "ボイラーの構造部分を溶接修理する場合の注意として、適切なものは次のうちどれか。", "opts": ["どんな修理も自由に行える。", "修理内容により届出や検査の要否を確認する。", "安全弁を外せば手続不要である。", "燃料を変えれば手続不要である。", "水面計を閉じれば手続不要である。"], "ans": 1, "exp": "主要部分の修理や変更は法令上の手続対象となることがある。"},
  {"id": 20180440, "year": 201804, "num": 40, "field": "law", "text": "作業主任者が水位を監視する理由として、適切なものは次のうちどれか。", "opts": ["煙突高さを変えるため。", "燃料価格を下げるため。", "検査証を不要にするため。", "低水位や高水位による事故を防ぐため。", "ボイラー室を暗くするため。"], "ans": 3, "exp": "水位監視は低水位過熱やキャリオーバ防止に直結する。"},
  {"id": 20191001, "year": 201910, "num": 1, "field": "structure", "text": "節炭器の主な役割として、適切なものは次のうちどれか。", "opts": ["安全弁を作動不能にする。", "燃料中の硫黄を除去する。", "蒸気中の水滴を増やす。", "排ガスの余熱で給水を加熱する。", "水面計の代わりに水位を測る。"], "ans": 3, "exp": "節炭器は排熱回収により給水を予熱し、効率を高める。"},
  {"id": 20191002, "year": 201910, "num": 2, "field": "structure", "text": "空気予熱器の低温側で注意すべき腐食として、適切なものは次のうちどれか。", "opts": ["燃料タンク内の沈殿だけ。", "水面計の閉塞。", "安全弁の弁座漏れ。", "給水ポンプのキャビテーションだけ。", "酸露点以下で生じる低温腐食。"], "ans": 4, "exp": "排ガス中の硫黄酸化物と水分により、低温部で酸露点腐食が起こり得る。"},
  {"id": 20191003, "year": 201910, "num": 3, "field": "structure", "text": "ブルドン管圧力計に関する記述として、適切なものは次のうちどれか。", "opts": ["水の硬度を測る計器である。", "曲がった管の弾性変形を利用して圧力を示す。", "燃料の発熱量を直接測る。", "火炎の色を測る。", "煙突高さを自動調整する。"], "ans": 1, "exp": "ブルドン管圧力計は圧力による管の変形を指針の動きに変える。"},
  {"id": 20191004, "year": 201910, "num": 4, "field": "structure", "text": "水高計に関する記述として、適切なものは次のうちどれか。", "opts": ["排ガス中のばいじんを測る装置である。", "燃料の発熱量を測る計器である。", "水位の高さを圧力差などから示す計器である。", "安全弁の一種である。", "給水を軟化する薬剤である。"], "ans": 2, "exp": "水高計は水位測定に関係する装置で、水面計とあわせて出題されやすい。"},
  {"id": 20191005, "year": 201910, "num": 5, "field": "structure", "text": "温水ボイラーの逃がし弁に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料を霧化する。", "圧力上昇時に水を逃がして過圧を防ぐ。", "水の硬度を上げる。", "煙突の通風を止める。", "燃料中の硫黄を除去する。"], "ans": 1, "exp": "逃がし弁は温水系統の過圧防止に用いられる。"},
  {"id": 20191006, "year": 201910, "num": 6, "field": "structure", "text": "圧力制御器の役割として、適切なものは次のうちどれか。", "opts": ["水面計のガラスを洗浄する。", "給水の硬度を測定する。", "燃料中の硫黄を除去する。", "蒸気圧力に応じて燃焼量や燃焼の入切を制御する。", "煙突高さを測る。"], "ans": 3, "exp": "圧力制御器は蒸気圧力を設定範囲に保つため燃焼を制御する。"},
  {"id": 20191007, "year": 201910, "num": 7, "field": "structure", "text": "水位制御器の役割として、適切なものは次のうちどれか。", "opts": ["安全弁のばねを調整する。", "燃料の発熱量を測る。", "水位に応じて給水ポンプや給水弁を制御する。", "排ガス中のSOxを除去する。", "煙突を支える。"], "ans": 2, "exp": "水位制御器は安全な水位を保つため給水を制御する。"},
  {"id": 20191008, "year": 201910, "num": 8, "field": "structure", "text": "燃焼量比例制御に関する記述として、適切なものは次のうちどれか。", "opts": ["煙突を伸縮させる制御である。", "常に燃焼を全開だけにする。", "水質だけを制御する。", "安全弁を閉じる制御である。", "負荷に応じて燃料量と空気量を連続的又は段階的に調整する。"], "ans": 4, "exp": "燃焼量制御では負荷に合わせて燃料と空気のバランスを調整する。"},
  {"id": 20191009, "year": 201910, "num": 9, "field": "structure", "text": "燃料遮断弁のフェールセーフとして望ましい状態は次のうちどれか。", "opts": ["圧力が異常でも開き続ける。", "異常時に必ず開く。", "火炎がなくても開き続ける。", "水位が低くても開き続ける。", "電源喪失や異常時に閉じる。"], "ans": 4, "exp": "燃料遮断弁は異常時に燃料供給を止める安全側の動作が求められる。"},
  {"id": 20191010, "year": 201910, "num": 10, "field": "structure", "text": "吹出し弁の設置目的として、適切なものは次のうちどれか。", "opts": ["煙突の高さを測る。", "燃料を霧化する。", "安全弁を作動不能にする。", "ボイラー水中のスラッジや濃縮水を排出する。", "給水の温度だけを測る。"], "ans": 3, "exp": "吹出し弁はボイラー水の濃度管理やスラッジ排出に用いられる。"},
  {"id": 20191011, "year": 201910, "num": 11, "field": "handling", "text": "フォーミングに関する記述として、適切なものは次のうちどれか。", "opts": ["燃料油を加熱する現象である。", "ボイラー水が泡立つ現象である。", "煙突内の通風を止める現象である。", "安全弁が開く現象だけをいう。", "給水を軟化する操作である。"], "ans": 1, "exp": "フォーミングは泡立ちで、キャリオーバの原因になる。"},
  {"id": 20191012, "year": 201910, "num": 12, "field": "handling", "text": "スートブローを怠ると起こり得ることとして、適切なものは次のうちどれか。", "opts": ["燃料が不要になる。", "水位が必ず安定する。", "伝熱低下や排ガス温度上昇。", "給水の硬度が下がる。", "安全弁が不要になる。"], "ans": 2, "exp": "すす付着は伝熱を妨げ、熱損失を増加させる。"},
  {"id": 20191013, "year": 201910, "num": 13, "field": "handling", "text": "停止後にマンホールを開ける際の注意として、適切なものは次のうちどれか。", "opts": ["高圧のまま開ける。", "圧力がなく温度が安全なことを確認する。", "水位を見ず燃焼中に開ける。", "換気を一切しない。", "安全弁を固定してから開ける。"], "ans": 1, "exp": "内部開放作業では残圧、温度、換気などの安全確認が必要である。"},
  {"id": 20191014, "year": 201910, "num": 14, "field": "handling", "text": "湿り保存で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["水を抜いて雨水を入れる。", "空気を多量に混入させる。", "燃料油を満たす。", "水質を管理し、腐食防止に必要な薬品や脱酸素を確認する。", "内部を汚れたまま放置する。"], "ans": 3, "exp": "湿り保存では水中の酸素や水質を管理して腐食を抑える。"},
  {"id": 20191015, "year": 201910, "num": 15, "field": "handling", "text": "低燃焼から高燃焼へ移るとき注意すべきこととして、適切なものは次のうちどれか。", "opts": ["火炎を確認しない。", "燃料だけを急増させる。", "空気を完全に止める。", "空気量と燃料量のバランスを崩さない。", "安全装置を無効化する。"], "ans": 3, "exp": "燃焼量変更時は燃料と空気の比率を適切に保つ。"},
  {"id": 20191016, "year": 201910, "num": 16, "field": "handling", "text": "燃料遮断弁の作動試験で確認することとして、適切なものは次のうちどれか。", "opts": ["給水を軟化すること。", "常に開きっぱなしになること。", "水位を高く表示すること。", "異常時に確実に閉止すること。", "煙突を冷却すること。"], "ans": 3, "exp": "燃料遮断弁は燃焼安全上、確実な閉止が重要である。"},
  {"id": 20191017, "year": 201910, "num": 17, "field": "handling", "text": "ボイラー水が著しく不足しているおそれがある場合の給水について、適切な考え方は次のうちどれか。", "opts": ["水位確認をしない。", "必ず大量に急給水する。", "燃焼を最大にしてから給水する。", "過熱部への急給水は危険なため、手順に従い慎重に判断する。", "安全装置を外す。"], "ans": 3, "exp": "著しい低水位では伝熱面が過熱している可能性があり、急給水は危険となることがある。"},
  {"id": 20191018, "year": 201910, "num": 18, "field": "handling", "text": "燃焼中に黒煙が増えた場合の対応として、適切なものは次のうちどれか。", "opts": ["空気を完全に止める。", "燃料をさらに増やすだけにする。", "空気量、燃料圧、霧化状態などを確認する。", "水位を見ない。", "安全装置を無効にする。"], "ans": 2, "exp": "黒煙は不完全燃焼のサインであり、空気不足や霧化不良を確認する。"},
  {"id": 20191019, "year": 201910, "num": 19, "field": "handling", "text": "日常点検で安全弁について見る事項として、適切なものは次のうちどれか。", "opts": ["水処理薬剤の色だけ。", "燃料の購入価格だけ。", "漏れ、固着、封印、吹出し管の状態など。", "作業者の氏名だけ。", "煙突の外壁色だけ。"], "ans": 2, "exp": "安全弁は過圧防止装置であり、漏れや固着、吹出し管の状態を確認する。"},
  {"id": 20191020, "year": 201910, "num": 20, "field": "handling", "text": "運転日誌に記録する事項として、適切なものは次のうちどれか。", "opts": ["作業者の趣味だけ。", "圧力、水位、燃焼状態、給水量、異常の有無など。", "燃料販売店の広告だけ。", "水面計のメーカーの株価だけ。", "煙突の色の好みだけ。"], "ans": 1, "exp": "運転記録は異常傾向の把握と安全管理に役立つ。"},
  {"id": 20191021, "year": 201910, "num": 21, "field": "fuel", "text": "押込通風に関する記述として、適切なものは次のうちどれか。", "opts": ["送風機で燃焼用空気を炉内へ押し込む方式である。", "煙突だけで排ガスを引く方式である。", "給水ポンプで通風する方式である。", "安全弁で空気を送る方式である。", "水面計で通風を測る方式である。"], "ans": 0, "exp": "押込通風は送風機で燃焼用空気を供給する。"},
  {"id": 20191022, "year": 201910, "num": 22, "field": "fuel", "text": "誘引通風に関する記述として、適切なものは次のうちどれか。", "opts": ["誘引ファンで燃焼ガスを引き出す方式である。", "給水ポンプで排ガスを押す方式である。", "燃料ポンプで空気を送る方式である。", "安全弁で通風を止める方式である。", "水面計でガスを吸う方式である。"], "ans": 0, "exp": "誘引通風は煙道側から燃焼ガスを吸引する方式である。"},
  {"id": 20191023, "year": 201910, "num": 23, "field": "fuel", "text": "空気比が小さすぎる場合に起こりやすいこととして、適切なものは次のうちどれか。", "opts": ["燃料が不要になる。", "排ガス量が無限に増える。", "不完全燃焼、CO、黒煙の増加。", "安全弁が不要になる。", "水位が必ず安定する。"], "ans": 2, "exp": "空気不足は不完全燃焼の代表的な原因である。"},
  {"id": 20191024, "year": 201910, "num": 24, "field": "fuel", "text": "排ガス温度を下げすぎると問題になることとして、適切なものは次のうちどれか。", "opts": ["水位が必ず上がる。", "燃料が完全に不要になる。", "低温腐食のおそれがある。", "安全弁が不要になる。", "空気比が必ずゼロになる。"], "ans": 2, "exp": "排熱回収は有効だが、酸露点以下になると低温腐食が問題となる。"},
  {"id": 20191025, "year": 201910, "num": 25, "field": "fuel", "text": "燃焼ガス中のO2が低くCOが高い場合に疑うこととして、適切なものは次のうちどれか。", "opts": ["過剰空気が多すぎる完全燃焼。", "空気不足による不完全燃焼。", "水処理の過剰。", "安全弁の正常作動。", "検査証の期限切れだけ。"], "ans": 1, "exp": "O2不足とCO増加は空気不足や混合不良を示す。"},
  {"id": 20191026, "year": 201910, "num": 26, "field": "fuel", "text": "排ガス分析計の値を見るときの注意として、適切なものは次のうちどれか。", "opts": ["安全弁の設定を自動変更する。", "値は常に誤差ゼロである。", "水位確認の代わりになる。", "測定位置や漏れ込み空気の影響を考慮する。", "燃料の購入価格を決めるだけである。"], "ans": 3, "exp": "排ガス分析では測定条件や空気漏れによる値の変化に注意する。"},
  {"id": 20191027, "year": 201910, "num": 27, "field": "fuel", "text": "燃焼における三つのTとして扱われる要素に近いものは次のうちどれか。", "opts": ["安全弁、圧力計、水面計。", "水位、圧力、検査証。", "燃料、給水、吹出し。", "温度、時間、混合。", "煙突、床、照明。"], "ans": 3, "exp": "完全燃焼には温度、燃焼時間、燃料と空気の混合が重要である。"},
  {"id": 20191028, "year": 201910, "num": 28, "field": "fuel", "text": "燃焼負荷を急に上げるとき注意すべきこととして、適切なものは次のうちどれか。", "opts": ["空気量が追従せず不完全燃焼にならないようにする。", "空気を必ず止める。", "燃料だけを最大にする。", "火炎を見ない。", "排ガスを測らない。"], "ans": 0, "exp": "燃焼負荷変化時は燃料と空気の追従、火炎安定を確認する。"},
  {"id": 20191029, "year": 201910, "num": 29, "field": "fuel", "text": "燃焼効率を高める基本として、適切でないものは次のうちどれか。", "opts": ["適正空気比を保つ。", "伝熱面を清浄に保つ。", "空気量を常に極端に多くする。", "燃料を適切に霧化する。", "排熱を有効利用する。"], "ans": 2, "exp": "過大な空気量は排ガス熱損失を増やす。"},
  {"id": 20191030, "year": 201910, "num": 30, "field": "fuel", "text": "燃料の発熱量が同じでも実際の効率が変わる理由として、適切なものは次のうちどれか。", "opts": ["安全弁の色だけで決まるため。", "発熱量だけで効率は必ず100%になるため。", "水位と無関係で常に同じになるため。", "燃焼状態や排ガス損失、伝熱状態が異なるため。", "検査証の紙質だけで決まるため。"], "ans": 3, "exp": "ボイラー効率は燃料性状だけでなく燃焼管理や伝熱状態に左右される。"},
  {"id": 20191031, "year": 201910, "num": 31, "field": "law", "text": "作業主任者が燃焼状態を監視する理由として、適切なものは次のうちどれか。", "opts": ["不完全燃焼や異常燃焼を防ぐため。", "給水の硬度を必ず下げるため。", "検査証の有効期間を延ばすためだけ。", "安全弁を不要にするため。", "煙突を短くするため。"], "ans": 0, "exp": "燃焼監視は安全、効率、大気汚染防止に関係する。"},
  {"id": 20191032, "year": 201910, "num": 32, "field": "law", "text": "安全弁の吹出し管で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["管をふさいで圧力を保つ。", "蒸気を作業者へ向けて放出する。", "蒸気や熱水を安全な場所へ導く。", "水面計へ接続して水位を隠す。", "燃料タンクへ接続して加圧する。"], "ans": 2, "exp": "吹出し管は安全弁作動時の蒸気を安全に処理するために設ける。"},
  {"id": 20191033, "year": 201910, "num": 33, "field": "law", "text": "圧力計の指針がゼロに戻らない場合の対応として、適切なものは次のうちどれか。", "opts": ["燃料を増やす。", "正常なので必ず放置する。", "指針を接着剤で固定する。", "水位確認の代わりにする。", "計器異常として点検・交換を検討する。"], "ans": 4, "exp": "圧力計の指示異常は過圧判断を誤る原因となる。"},
  {"id": 20191034, "year": 201910, "num": 34, "field": "law", "text": "水面計のガラス管破損時の対応として、適切なものは次のうちどれか。", "opts": ["安全弁を固定する。", "近づいて素手で押さえる。", "燃焼量を最大にする。", "給水を止めて放置する。", "コックを閉じて噴出を止め、安全を確保する。"], "ans": 4, "exp": "水面計破損時は蒸気や熱水の噴出を止め、安全を確保する。"},
  {"id": 20191035, "year": 201910, "num": 35, "field": "law", "text": "定期自主検査で煙道を確認する理由として、適切なものは次のうちどれか。", "opts": ["検査証の紙色を確認するため。", "作業者の年齢を確認するため。", "燃料販売店を確認するため。", "すす詰まり、腐食、漏れなどを把握するため。", "水面計の照明色を確認するため。"], "ans": 3, "exp": "煙道の異常は燃焼、通風、腐食、安全に関係する。"},
  {"id": 20191036, "year": 201910, "num": 36, "field": "law", "text": "定期自主検査で給水装置を点検する理由として、適切なものは次のうちどれか。", "opts": ["給水不能による低水位事故を防ぐため。", "燃料の価格を下げるため。", "安全弁を不要にするため。", "検査証を自動発行するため。", "煙突を短くするため。"], "ans": 0, "exp": "給水装置は水位維持の要であり、異常は重大事故につながる。"},
  {"id": 20191037, "year": 201910, "num": 37, "field": "law", "text": "法令問題で『労働基準監督署長』と『都道府県労働局長』を読む際の注意として、適切なものは次のうちどれか。", "opts": ["どちらも水面計メーカーである。", "どちらも燃料販売店である。", "どちらも作業主任者である。", "提出先や権限を混同しない。", "どちらも安全弁の形式である。"], "ans": 3, "exp": "法令では届出先、申請先、検査機関の違いが正誤になる。"},
  {"id": 20191038, "year": 201910, "num": 38, "field": "law", "text": "法令問題で単位を読み違えると起こることとして、適切なものは次のうちどれか。", "opts": ["安全弁が不要になる。", "必ず正解に近づく。", "燃料性状が変わる。", "水位が自動で上がる。", "伝熱面積や圧力条件の判断を誤る。"], "ans": 4, "exp": "m2、MPa、kWなどの単位は区分判定に直結する。"},
  {"id": 20191039, "year": 201910, "num": 39, "field": "law", "text": "『除く』という語がある法令問題の基本対応として、適切なものは次のうちどれか。", "opts": ["対象外になるものを先に確認する。", "除外条件を無視する。", "常に全てを対象にする。", "選択肢1だけを選ぶ。", "問題文を読まない。"], "ans": 0, "exp": "除外条件は正誤判断に大きく影響するため、先に対象範囲を確定する。"},
  {"id": 20191040, "year": 201910, "num": 40, "field": "law", "text": "『準用する』という表現が出る問題で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["燃料を準備する意味である。", "規定が一切適用されない意味である。", "他の規定を読み替えて適用する趣旨を確認する。", "水面計を準備する意味である。", "安全弁を外す意味である。"], "ans": 2, "exp": "準用は別の規定を必要な読み替えで適用することを示す。"},
  {"id": 20200401, "year": 202004, "num": 1, "field": "structure", "text": "蒸気の乾き度が1に近いほど、一般にどのような状態か。", "opts": ["水滴を多量に含む。", "水滴の少ない乾いた蒸気である。", "燃料油を多く含む。", "圧力が必ず大気圧である。", "水面計内だけの水である。"], "ans": 1, "exp": "乾き度は湿り蒸気中の蒸気分の割合で、1に近いほど乾いた蒸気である。"},
  {"id": 20200402, "year": 202004, "num": 2, "field": "structure", "text": "同じ圧力で飽和蒸気をさらに加熱したものは次のうちどれか。", "opts": ["復水だけ。", "飽和水。", "湿り蒸気。", "給水。", "過熱蒸気。"], "ans": 4, "exp": "飽和温度を超えて加熱された蒸気を過熱蒸気という。"},
  {"id": 20200403, "year": 202004, "num": 3, "field": "structure", "text": "復水に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料が燃え残った灰である。", "蒸気が凝縮して水に戻ったものである。", "煙突内の空気である。", "安全弁のばねである。", "水処理薬剤の総称である。"], "ans": 1, "exp": "蒸気が放熱して凝縮すると復水になる。"},
  {"id": 20200404, "year": 202004, "num": 4, "field": "structure", "text": "水冷壁の利点として、適切なものは次のうちどれか。", "opts": ["水位計を不要にする。", "燃料の硫黄分をなくす。", "炉壁を冷却しながら放射熱を有効に吸収できる。", "給水ポンプを不要にする。", "安全弁を作動不能にする。"], "ans": 2, "exp": "水冷壁は炉壁保護と放射伝熱面としての役割を持つ。"},
  {"id": 20200405, "year": 202004, "num": 5, "field": "structure", "text": "伝熱面内側にスケールが付着した場合に起こり得ることとして、適切なものは次のうちどれか。", "opts": ["金属温度が上がり、過熱損傷の原因となる。", "伝熱が必ず良くなる。", "燃料が不要になる。", "水位が常に安定する。", "通風が不要になる。"], "ans": 0, "exp": "スケールは熱伝導を妨げ、伝熱面の過熱を招く。"},
  {"id": 20200406, "year": 202004, "num": 6, "field": "structure", "text": "対流伝熱に最も関係が深いものは次のうちどれか。", "opts": ["安全弁のばね。", "燃焼ガスの流れと伝熱面との接触。", "水面計の照明。", "検査証の有効期間。", "燃料タンクの塗色。"], "ans": 1, "exp": "対流伝熱は流体の流れによって熱が伝わる現象である。"},
  {"id": 20200407, "year": 202004, "num": 7, "field": "structure", "text": "自然循環を良好にする条件として、適切なものは次のうちどれか。", "opts": ["給水を完全に止める。", "水位を常に下げる。", "管内にスケールを厚く付ける。", "上昇管と下降管の密度差を保つ。", "通風を止める。"], "ans": 3, "exp": "自然循環は加熱部と非加熱部の密度差で生じる。"},
  {"id": 20200408, "year": 202004, "num": 8, "field": "structure", "text": "蒸気ドラムで行われる働きとして、適切なものは次のうちどれか。", "opts": ["給水の軟化。", "燃料の霧化。", "排ガス分析。", "蒸気と水の分離。", "煙突の支持。"], "ans": 3, "exp": "蒸気ドラムは気水分離と水循環の中心となる。"},
  {"id": 20200409, "year": 202004, "num": 9, "field": "structure", "text": "煙管ボイラーで煙管内を流れるものとして、一般に適切なものは次のうちどれか。", "opts": ["水処理薬剤だけ。", "給水だけ。", "燃料油だけ。", "燃焼ガス。", "圧縮空気だけ。"], "ans": 3, "exp": "煙管には燃焼ガスが通り、管外の水を加熱する。"},
  {"id": 20200410, "year": 202004, "num": 10, "field": "structure", "text": "炉筒の波形構造の目的として、適切なものは次のうちどれか。", "opts": ["熱膨張への追従性や外圧に対する強度を高める。", "燃料を脱硫する。", "水位を測定する。", "排ガス中の酸素を測定する。", "安全弁の吹出し量を減らす。"], "ans": 0, "exp": "波形炉筒は熱膨張による応力緩和や強度上の利点がある。"},
  {"id": 20200411, "year": 202004, "num": 11, "field": "handling", "text": "点火前に水位を確認する理由として、適切なものは次のうちどれか。", "opts": ["燃料の硫黄を除くため。", "低水位のまま加熱する危険を避けるため。", "排ガスを分析するため。", "煙突を冷やすため。", "検査証を更新するため。"], "ans": 1, "exp": "点火前水位確認は低水位事故防止の基本である。"},
  {"id": 20200412, "year": 202004, "num": 12, "field": "handling", "text": "点火後に火炎が安定しない場合の対応として、適切なものは次のうちどれか。", "opts": ["燃料圧、空気量、バーナ状態を確認する。", "安全装置を無効にする。", "燃料だけを増やす。", "換気を止める。", "水位を見ない。"], "ans": 0, "exp": "火炎不安定は燃料・空気・霧化・通風の異常が原因になり得る。"},
  {"id": 20200413, "year": 202004, "num": 13, "field": "handling", "text": "水面計の水位が動かない場合に疑うこととして、適切なものは次のうちどれか。", "opts": ["検査証の汚れだけ。", "燃料発熱量の増加。", "安全弁の増設。", "煙突高さの不足だけ。", "連絡管やコックの閉塞。"], "ans": 4, "exp": "水位変化が見えない場合は閉塞などによる誤表示を疑う。"},
  {"id": 20200414, "year": 202004, "num": 14, "field": "handling", "text": "低水位事故を防ぐ日常管理として、適切なものは次のうちどれか。", "opts": ["水面計、給水装置、低水位警報を確認する。", "水位を見ない。", "給水弁を閉じたままにする。", "警報を切る。", "燃焼量だけを上げる。"], "ans": 0, "exp": "低水位防止には水位確認、給水機能、安全装置の維持が必要である。"},
  {"id": 20200415, "year": 202004, "num": 15, "field": "handling", "text": "吹出しの前後で水位を確認する理由として、適切なものは次のうちどれか。", "opts": ["排ガスを脱硫するため。", "燃料を加熱するため。", "安全弁を閉じるため。", "急激な水位低下を防ぐため。", "煙突を洗浄するため。"], "ans": 3, "exp": "吹出しはボイラー水を排出するため水位低下に注意する。"},
  {"id": 20200416, "year": 202004, "num": 16, "field": "handling", "text": "ボイラー水の濃縮管理が不適切な場合に起こり得ることとして、適切なものは次のうちどれか。", "opts": ["通風の自動停止。", "燃料の完全脱硫。", "安全弁の不要化。", "スケール、泡立ち、キャリオーバ。", "水位確認の不要化。"], "ans": 3, "exp": "水質濃度の管理不良は各種水側障害につながる。"},
  {"id": 20200417, "year": 202004, "num": 17, "field": "handling", "text": "給水中の硬度成分を放置すると起こり得ることとして、適切なものは次のうちどれか。", "opts": ["安全弁の自動調整。", "燃料霧化改善。", "排ガス酸素低下。", "スケール付着。", "水面計照明の改善。"], "ans": 3, "exp": "硬度成分は加熱によりスケールとなることがある。"},
  {"id": 20200418, "year": 202004, "num": 18, "field": "handling", "text": "腐食を防ぐ水管理として、適切なものは次のうちどれか。", "opts": ["吹出しを永久にしない。", "酸素を多く溶かす。", "pHを全く見ない。", "スケールを増やす。", "溶存酸素やpHを適正に管理する。"], "ans": 4, "exp": "腐食防止には脱酸素、pH、濃度管理などが関係する。"},
  {"id": 20200419, "year": 202004, "num": 19, "field": "handling", "text": "キャリオーバ防止策として、適切なものは次のうちどれか。", "opts": ["水面計を閉じる。", "常に高水位にする。", "吹出しを全く行わない。", "燃料だけを増やす。", "適正水位と水質濃度を保つ。"], "ans": 4, "exp": "高水位や濃縮、泡立ちはキャリオーバ原因となる。"},
  {"id": 20200420, "year": 202004, "num": 20, "field": "handling", "text": "スートブローを行う主目的として、適切なものは次のうちどれか。", "opts": ["ボイラー水を軟化する。", "伝熱面に付着したすすを除去する。", "安全弁を調整する。", "検査証を更新する。", "燃料を貯蔵する。"], "ans": 1, "exp": "スートブローは燃焼ガス側のすすを除去し、伝熱を保つ。"},
  {"id": 20200421, "year": 202004, "num": 21, "field": "fuel", "text": "燃料中の硫黄が燃焼して主に関係するものとして、適切なものは次のうちどれか。", "opts": ["給水硬度の低下。", "水位上昇。", "安全弁口径。", "SOxと低温腐食。", "検査証更新。"], "ans": 3, "exp": "硫黄分はSOxや酸露点腐食に関係する。"},
  {"id": 20200422, "year": 202004, "num": 22, "field": "fuel", "text": "燃料中の窒素分や高温燃焼に関係する大気汚染物質として、適切なものは次のうちどれか。", "opts": ["燃料タンク容量。", "給水硬度。", "水面計水位。", "安全弁口径。", "NOx。"], "ans": 4, "exp": "NOxは燃料中窒素や高温下での空気中窒素の酸化により生じる。"},
  {"id": 20200423, "year": 202004, "num": 23, "field": "fuel", "text": "重油の流動点に関する記述として、適切なものは次のうちどれか。", "opts": ["水の沸点である。", "燃料油が流動しにくくなる温度に関係する性質である。", "安全弁の吹出し温度である。", "煙突の表面温度である。", "排ガス中の酸素濃度である。"], "ans": 1, "exp": "流動点は燃料の貯蔵・移送時の加熱管理に関係する。"},
  {"id": 20200424, "year": 202004, "num": 24, "field": "fuel", "text": "燃料油を加熱する主目的として、適切なものは次のうちどれか。", "opts": ["検査証を更新する。", "水位を高くする。", "安全弁を閉じる。", "排ガス中の酸素をなくす。", "粘度を下げて移送や霧化を良くする。"], "ans": 4, "exp": "重油は粘度が高いため、適切な加熱で取扱いや燃焼を改善する。"},
  {"id": 20200425, "year": 202004, "num": 25, "field": "fuel", "text": "燃料油中の水分がバーナに及ぼす影響として、適切なものは次のうちどれか。", "opts": ["火炎不安定や失火の原因となることがある。", "完全燃焼を必ず保証する。", "NOxを必ずゼロにする。", "水位を正確にする。", "安全弁を不要にする。"], "ans": 0, "exp": "燃料油中の水分は噴霧・燃焼を乱す。"},
  {"id": 20200426, "year": 202004, "num": 26, "field": "fuel", "text": "圧力噴霧式バーナで燃料圧力が低すぎる場合に起こり得ることとして、適切なものは次のうちどれか。", "opts": ["水質改善。", "霧化不良。", "安全弁増加。", "給水軟化。", "検査証更新。"], "ans": 1, "exp": "圧力噴霧式では燃料圧力が霧化状態に影響する。"},
  {"id": 20200427, "year": 202004, "num": 27, "field": "fuel", "text": "バーナノズルの摩耗が進むと起こり得ることとして、適切なものは次のうちどれか。", "opts": ["噴霧量や噴霧角が変化する。", "燃料の硫黄分が消える。", "給水硬度が下がる。", "安全弁が不要になる。", "水位が必ず一定になる。"], "ans": 0, "exp": "ノズル摩耗は燃焼量や霧化状態を変化させる。"},
  {"id": 20200428, "year": 202004, "num": 28, "field": "fuel", "text": "空気量不足時の火炎の傾向として、適切なものは次のうちどれか。", "opts": ["常に無色透明となる。", "暗く長い火炎や黒煙を伴うことがある。", "燃焼状態とは無関係である。", "水位が下がるだけである。", "安全弁が必ず開く。"], "ans": 1, "exp": "空気不足では不完全燃焼となり黒煙や長炎を生じやすい。"},
  {"id": 20200429, "year": 202004, "num": 29, "field": "fuel", "text": "ガス燃料の着火前確認として、適切なものは次のうちどれか。", "opts": ["燃料弁を開けっぱなしにする。", "水位を見ずに点火する。", "換気を止める。", "安全装置を外す。", "漏えい、圧力、換気、点火装置を確認する。"], "ans": 4, "exp": "ガス燃料では漏えいと未燃ガス滞留の防止が特に重要である。"},
  {"id": 20200430, "year": 202004, "num": 30, "field": "fuel", "text": "予混合火炎で逆火が問題となる理由として、適切なものは次のうちどれか。", "opts": ["給水が軟化するため。", "水位が高くなるため。", "混合気がバーナ内部へ燃え戻るおそれがあるため。", "安全弁が増えるため。", "排ガス温度が必ず0度になるため。"], "ans": 2, "exp": "予混合燃焼では混合気の流速と火炎速度の関係により逆火が問題となる。"},
  {"id": 20200431, "year": 202004, "num": 31, "field": "law", "text": "伝熱面積の判断でまず確認すべきものとして、適切なものは次のうちどれか。", "opts": ["水面計メーカー。", "作業者の年齢。", "燃料販売店名。", "ボイラーの種類と伝熱面の部位。", "床の色。"], "ans": 3, "exp": "伝熱面積は種類と部位ごとの規定で判断する。"},
  {"id": 20200432, "year": 202004, "num": 32, "field": "law", "text": "小型ボイラーと通常のボイラーを混同しないために重要なものとして、適切なものは次のうちどれか。", "opts": ["作業服の色。", "問題番号。", "選択肢の長さ。", "燃料販売店の広告。", "伝熱面積、圧力、用途などの条件。"], "ans": 4, "exp": "区分問題では数値条件と対象設備を正確に読む。"},
  {"id": 20200433, "year": 202004, "num": 33, "field": "law", "text": "ボイラー室の通路を確保する理由として、適切なものは次のうちどれか。", "opts": ["水面計を隠すため。", "燃料を多く置くため。", "操作、点検、避難を安全に行うため。", "安全弁を閉じるため。", "換気を悪くするため。"], "ans": 2, "exp": "通路確保は日常点検と異常時避難に関係する。"},
  {"id": 20200434, "year": 202004, "num": 34, "field": "law", "text": "ボイラー室内の燃料漏れを放置してはならない理由として、適切なものは次のうちどれか。", "opts": ["水位が高くなるため。", "検査証が増えるため。", "火災や爆発のおそれがあるため。", "安全弁が増設されるため。", "伝熱面積が変わるため。"], "ans": 2, "exp": "燃料漏れは火災・爆発の重大リスクである。"},
  {"id": 20200435, "year": 202004, "num": 35, "field": "law", "text": "ボイラー検査証を備え付ける目的として、適切なものは次のうちどれか。", "opts": ["使用できるボイラーであることや有効期間を確認できるようにする。", "燃料を加熱するため。", "水位を測るため。", "煙突を支えるため。", "安全弁を閉じるため。"], "ans": 0, "exp": "検査証は使用条件や有効期間の管理に関係する。"},
  {"id": 20200436, "year": 202004, "num": 36, "field": "law", "text": "性能検査を受ける目的として、適切なものは次のうちどれか。", "opts": ["水面計の色を決めるため。", "燃料を購入するため。", "作業服を決めるため。", "継続使用に必要な性能を確認するため。", "煙突を塗るため。"], "ans": 3, "exp": "性能検査は検査証の有効期間更新と関連する。"},
  {"id": 20200437, "year": 202004, "num": 37, "field": "law", "text": "変更検査の対象となりやすいものとして、適切なものは次のうちどれか。", "opts": ["作業者の昼食変更。", "机の配置変更。", "胴やドラムなど主要部分の変更。", "床の色変更。", "燃料販売店の広告変更。"], "ans": 2, "exp": "主要構造部分の変更は変更検査の典型論点である。"},
  {"id": 20200438, "year": 202004, "num": 38, "field": "law", "text": "廃止届の問題で読み落としやすいものとして、適切なものは次のうちどれか。", "opts": ["水面計の色。", "作業者の趣味。", "燃料販売店の看板。", "床の模様。", "届出先、期限、検査証の扱い。"], "ans": 4, "exp": "廃止・休止・再使用は手続と期限の読み取りが重要である。"},
  {"id": 20200439, "year": 202004, "num": 39, "field": "law", "text": "休止中の保存状態で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["安全弁を外して放置する。", "雨水を入れる。", "腐食を防ぎ、再使用時の安全を確保する。", "検査証を破棄する。", "燃料漏れを放置する。"], "ans": 2, "exp": "休止中も腐食や劣化を防ぐ管理が必要である。"},
  {"id": 20200440, "year": 202004, "num": 40, "field": "law", "text": "作業主任者の職務でないものとして、適切なものは次のうちどれか。", "opts": ["燃焼状態に注意する。", "水位を監視する。", "圧力を監視する。", "安全装置を無効化して運転する。", "急激な負荷変動を避ける。"], "ans": 3, "exp": "作業主任者は安全運転を確保する立場であり、安全装置の無効化は不適切である。"},
  {"id": 20201001, "year": 202010, "num": 1, "field": "structure", "text": "給水ポンプの吐出圧力が不足すると起こり得ることとして、適切なものは次のうちどれか。", "opts": ["安全弁が不要になる。", "燃料の発熱量が上がる。", "排ガス中酸素が必ずゼロになる。", "ボイラーへ十分に給水できない。", "蒸気乾き度が必ず1になる。"], "ans": 3, "exp": "給水圧力不足は給水不能や低水位につながる。"},
  {"id": 20201002, "year": 202010, "num": 2, "field": "structure", "text": "給水逆止め弁が必要な理由として、適切なものは次のうちどれか。", "opts": ["ボイラー水や蒸気の逆流を防ぐため。", "燃料を霧化するため。", "排ガスを分析するため。", "水面計を照明するため。", "煙突を支えるため。"], "ans": 0, "exp": "逆止め弁はボイラー側から給水系統への逆流を防ぐ。"},
  {"id": 20201003, "year": 202010, "num": 3, "field": "structure", "text": "安全弁が開いた後に確実に閉じることが必要な理由として、適切なものは次のうちどれか。", "opts": ["低温腐食を必ず起こすため。", "給水の硬度を上げるため。", "燃料を霧化するため。", "水面計を不要にするため。", "不要な蒸気漏れと圧力低下を防ぐため。"], "ans": 4, "exp": "安全弁の弁座漏れは蒸気損失と機能不良につながる。"},
  {"id": 20201004, "year": 202010, "num": 4, "field": "structure", "text": "水面計に照明を設ける目的として、適切なものは次のうちどれか。", "opts": ["燃料を加熱するため。", "水位を確実に読み取るため。", "圧力を下げるため。", "蒸気を乾かすため。", "排ガスを冷却するため。"], "ans": 1, "exp": "水位確認は安全運転の基本であり、見やすさの確保が重要である。"},
  {"id": 20201005, "year": 202010, "num": 5, "field": "structure", "text": "圧力計のサイホン管内に水を保つ目的として、適切なものは次のうちどれか。", "opts": ["通風を増やすため。", "燃料をろ過するため。", "水質を軟化するため。", "高温蒸気が圧力計へ直接入るのを防ぐため。", "安全弁を閉じるため。"], "ans": 3, "exp": "サイホン管は水封により圧力計を高温蒸気から保護する。"},
  {"id": 20201006, "year": 202010, "num": 6, "field": "structure", "text": "燃焼安全装置で点火確認が重要な理由として、適切なものは次のうちどれか。", "opts": ["排ガス温度を上げるため。", "水質を硬くするため。", "給水を止めるため。", "火炎がないまま燃料を供給し続けるのを防ぐため。", "煙突を短くするため。"], "ans": 3, "exp": "失火時の燃料供給継続は未燃燃料蓄積を招き危険である。"},
  {"id": 20201007, "year": 202010, "num": 7, "field": "structure", "text": "水位制御が不良な場合に最も注意すべき事故は次のうちどれか。", "opts": ["低水位による過熱。", "燃料価格の上昇。", "検査証の汚れ。", "煙突の変色。", "照明のちらつきだけ。"], "ans": 0, "exp": "水位制御不良は低水位や高水位を招き、安全運転に直結する。"},
  {"id": 20201008, "year": 202010, "num": 8, "field": "structure", "text": "燃焼制御で燃料量だけを増やし空気量が不足した場合に起こり得ることとして、適切なものは次のうちどれか。", "opts": ["蒸気圧力の完全安定。", "水質改善。", "安全弁増設。", "給水軟化。", "不完全燃焼。"], "ans": 4, "exp": "燃料と空気の比率が崩れると不完全燃焼になりやすい。"},
  {"id": 20201009, "year": 202010, "num": 9, "field": "structure", "text": "節炭器で給水を加熱しすぎる場合に注意すべきこととして、適切なものは次のうちどれか。", "opts": ["燃料をなくす。", "沸騰や水撃など運転上の不安定を避ける。", "安全弁を固定する。", "水面計を閉じる。", "通風を止める。"], "ans": 1, "exp": "節炭器出口での沸騰や水撃は運転障害につながる。"},
  {"id": 20201010, "year": 202010, "num": 10, "field": "structure", "text": "蒸気配管にドレン抜きを設ける理由として、適切なものは次のうちどれか。", "opts": ["煙突を支えるため。", "燃料を霧化するため。", "給水を軟化するため。", "圧力計を保護しないため。", "復水を排出しウォータハンマを防ぐため。"], "ans": 4, "exp": "蒸気配管中の復水はウォータハンマの原因となる。"},
  {"id": 20201011, "year": 202010, "num": 11, "field": "handling", "text": "停止後の冷却を急ぎすぎることが適切でない理由として、適切なものは次のうちどれか。", "opts": ["安全弁を閉じるため。", "燃料を増やすため。", "水質を悪化させるため。", "熱応力による損傷を避けるため。", "通風を止めるため。"], "ans": 3, "exp": "急冷は部材に大きな温度差を生じさせる。"},
  {"id": 20201012, "year": 202010, "num": 12, "field": "handling", "text": "内部清掃でスラッジを除去する理由として、適切なものは次のうちどれか。", "opts": ["水面計を隠すため。", "燃料を霧化するため。", "排ガスを分析するため。", "安全弁を固定するため。", "腐食や伝熱障害を防ぐため。"], "ans": 4, "exp": "スラッジ堆積は腐食や過熱障害につながる。"},
  {"id": 20201013, "year": 202010, "num": 13, "field": "handling", "text": "異常消火時に直ちに再点火してはならない理由として、適切なものは次のうちどれか。", "opts": ["給水硬度が下がるから。", "水位が必ず高いから。", "未燃燃料やガスが残っているおそれがあるため。", "安全弁が増えるから。", "検査証が消えるから。"], "ans": 2, "exp": "失火後は燃料遮断、換気、原因確認が必要である。"},
  {"id": 20201014, "year": 202010, "num": 14, "field": "handling", "text": "プレパージ不足の危険として、適切なものは次のうちどれか。", "opts": ["水面計照明改善。", "給水硬度低下。", "炉内の未燃ガス爆発。", "安全弁の正常増加。", "煙突高さ上昇。"], "ans": 2, "exp": "プレパージ不足では未燃ガスが残り点火時に危険である。"},
  {"id": 20201015, "year": 202010, "num": 15, "field": "handling", "text": "圧力計が異常を示す場合の対応として、適切なものは次のうちどれか。", "opts": ["指針を固定する。", "必ず無視する。", "他の状況と照合し、安全側に運転を調整する。", "燃料を最大にする。", "水位を見ない。"], "ans": 2, "exp": "圧力計異常は過圧や誤操作につながるため確認が必要である。"},
  {"id": 20201016, "year": 202010, "num": 16, "field": "handling", "text": "給水ポンプから異音がする場合に疑うものとして、適切なものは次のうちどれか。", "opts": ["燃料の完全燃焼。", "キャビテーションや軸受異常。", "検査証更新。", "水面計照明。", "煙突の塗色。"], "ans": 1, "exp": "ポンプ異音はキャビテーション、空気かみ、軸受異常などの兆候である。"},
  {"id": 20201017, "year": 202010, "num": 17, "field": "handling", "text": "煙道から異常なにおいや煙が出る場合の確認事項として、適切なものは次のうちどれか。", "opts": ["作業服の色。", "検査証の紙質。", "水面計メーカー。", "燃焼状態、通風、燃料状態。", "ボイラー室の机の数。"], "ans": 3, "exp": "煙やにおいは燃焼不良や漏れなどの異常兆候になり得る。"},
  {"id": 20201018, "year": 202010, "num": 18, "field": "handling", "text": "運転中に常時注意すべき主要項目として、適切なものは次のうちどれか。", "opts": ["床の模様だけ。", "圧力、水位、燃焼状態。", "燃料販売店の看板だけ。", "検査証の紙色だけ。", "照明器具の型番だけ。"], "ans": 1, "exp": "圧力、水位、燃焼状態は運転監視の基本である。"},
  {"id": 20201019, "year": 202010, "num": 19, "field": "handling", "text": "排ガス温度の記録が役立つ理由として、適切なものは次のうちどれか。", "opts": ["水位を直接測るため。", "作業者の人数を決めるため。", "検査証を印刷するため。", "伝熱面汚れや燃焼状態の変化を把握できる。", "安全弁を固定するため。"], "ans": 3, "exp": "排ガス温度の上昇は伝熱不良や燃焼状態変化のサインになる。"},
  {"id": 20201020, "year": 202010, "num": 20, "field": "handling", "text": "油ストレーナ差圧の増加が示す可能性として、適切なものは次のうちどれか。", "opts": ["水位の上昇だけ。", "ストレーナの詰まり。", "安全弁の開放だけ。", "検査証の更新だけ。", "煙突の伸長だけ。"], "ans": 1, "exp": "ストレーナ詰まりは燃料供給不良につながる。"},
  {"id": 20201021, "year": 202010, "num": 21, "field": "fuel", "text": "通風抵抗が増加する原因として、適切なものは次のうちどれか。", "opts": ["水面計の照明。", "給水の軟化。", "検査証の更新。", "安全弁の封印。", "煙道や伝熱面へのすす・灰の付着。"], "ans": 4, "exp": "すすや灰の付着はガス流路を狭め、通風抵抗を増やす。"},
  {"id": 20201022, "year": 202010, "num": 22, "field": "fuel", "text": "煙突による自然通風が強くなる条件として、一般に適切なものは次のうちどれか。", "opts": ["温度差が全くない。", "煙突内外の温度差や高さが大きい。", "煙突がない。", "燃焼ガスが冷え切っている。", "給水圧が高いだけ。"], "ans": 1, "exp": "自然通風力は煙突高さと内外ガス密度差に関係する。"},
  {"id": 20201023, "year": 202010, "num": 23, "field": "fuel", "text": "過剰空気が多すぎる場合の代表的な損失として、適切なものは次のうちどれか。", "opts": ["水位上昇。", "給水硬度低下。", "安全弁口径増加。", "排ガス熱損失。", "検査証再発行。"], "ans": 3, "exp": "過剰空気が多いと加熱されて排出されるガス量が増える。"},
  {"id": 20201024, "year": 202010, "num": 24, "field": "fuel", "text": "COが多く検出された場合の基本対応として、適切なものは次のうちどれか。", "opts": ["必ず放置する。", "空気量、燃料量、混合、通風を確認する。", "空気をさらに減らすだけにする。", "水位計を閉じる。", "安全装置を外す。"], "ans": 1, "exp": "COは不完全燃焼の指標であり燃焼調整が必要である。"},
  {"id": 20201025, "year": 202010, "num": 25, "field": "fuel", "text": "完全燃焼時の炭素の主な生成物として、適切なものは次のうちどれか。", "opts": ["一酸化炭素だけ。", "二酸化炭素。", "硫酸。", "水素。", "窒素だけ。"], "ans": 1, "exp": "炭素の完全燃焼ではCO2が生じる。"},
  {"id": 20201026, "year": 202010, "num": 26, "field": "fuel", "text": "不完全燃焼の防止に有効なものとして、適切なものは次のうちどれか。", "opts": ["火炎を確認しない。", "空気をゼロにする。", "燃料を塊のまま供給する。", "通風を止める。", "適正な空気量と良好な混合。"], "ans": 4, "exp": "完全燃焼には空気量、混合、温度、時間が必要である。"},
  {"id": 20201027, "year": 202010, "num": 27, "field": "fuel", "text": "燃焼用空気を予熱した場合の効果として、適切なものは次のうちどれか。", "opts": ["給水硬度を下げる。", "燃料を不要にする。", "水位を測る。", "安全弁を閉じる。", "燃焼温度や効率向上に寄与する。"], "ans": 4, "exp": "空気予熱は排熱回収と燃焼改善に役立つ。"},
  {"id": 20201028, "year": 202010, "num": 28, "field": "fuel", "text": "排ガス中O2が高くCOも高い場合に疑えるものとして、適切なものは次のうちどれか。", "opts": ["完全な理想燃焼だけ。", "空気の偏りや混合不良。", "水質管理の成功だけ。", "安全弁の正常作動だけ。", "検査証更新だけ。"], "ans": 1, "exp": "O2があっても混合不良ではCOが残ることがある。"},
  {"id": 20201029, "year": 202010, "num": 29, "field": "fuel", "text": "ばいじんを減らすための燃焼管理として、適切なものは次のうちどれか。", "opts": ["空気を常にゼロにする。", "燃料の霧化、空気量、混合を適正にする。", "燃料を水で薄めるだけにする。", "通風を止める。", "火炎を見ない。"], "ans": 1, "exp": "ばいじんは燃焼不良や燃料性状に左右される。"},
  {"id": 20201030, "year": 202010, "num": 30, "field": "fuel", "text": "高発熱量と低発熱量の差に主に関係するものとして、適切なものは次のうちどれか。", "opts": ["水面計の高さ。", "生成水蒸気の凝縮潜熱。", "安全弁の個数。", "煙突の塗色。", "給水ポンプの色。"], "ans": 1, "exp": "低発熱量は水蒸気の凝縮潜熱を含まない。"},
  {"id": 20201031, "year": 202010, "num": 31, "field": "law", "text": "取扱資格の問題で『伝熱面積』が出た場合の注意として、適切なものは次のうちどれか。", "opts": ["燃料価格だけで代用する。", "常に無視してよい。", "資格で扱える範囲の判定に関係することがある。", "作業者の年齢だけで決める。", "水面計の色で決める。"], "ans": 2, "exp": "取扱資格はボイラーの種類や規模条件と結び付く。"},
  {"id": 20201032, "year": 202010, "num": 32, "field": "law", "text": "安全弁を針金などで固定してはならない理由として、適切なものは次のうちどれか。", "opts": ["煙突が高くなるから。", "燃料を節約しすぎるから。", "水位が見えすぎるから。", "検査証が汚れるから。", "過圧時に作動できず危険だから。"], "ans": 4, "exp": "安全弁の固定は過圧事故につながる。"},
  {"id": 20201033, "year": 202010, "num": 33, "field": "law", "text": "圧力計のコックを閉じたままにすると危険な理由として、適切なものは次のうちどれか。", "opts": ["燃料が霧化しすぎるため。", "実際の圧力を示さないおそれがあるため。", "水質が改善しすぎるため。", "煙突が伸びるため。", "検査証が更新されるため。"], "ans": 1, "exp": "圧力計がボイラーと連通していないと圧力判断を誤る。"},
  {"id": 20201034, "year": 202010, "num": 34, "field": "law", "text": "水面計を閉じたまま運転してはならない理由として、適切なものは次のうちどれか。", "opts": ["通風が強くなるため。", "燃料価格が上がるため。", "実際の水位を確認できないため。", "検査証が増えるため。", "煙突が短くなるため。"], "ans": 2, "exp": "水面計の連絡が閉じていると水位誤認の危険がある。"},
  {"id": 20201035, "year": 202010, "num": 35, "field": "law", "text": "定期自主検査で燃焼装置を見る理由として、適切なものは次のうちどれか。", "opts": ["煙突の色を決めるため。", "検査証を印刷するため。", "作業者の服装を決めるため。", "水面計を隠すため。", "燃料漏れやバーナ異常を早期に見つけるため。"], "ans": 4, "exp": "燃焼装置の異常は火災や不完全燃焼につながる。"},
  {"id": 20201036, "year": 202010, "num": 36, "field": "law", "text": "定期自主検査記録を保存する意義として、適切なものは次のうちどれか。", "opts": ["安全弁を閉じるため。", "燃料を増やすため。", "水位を隠すため。", "異常履歴や補修状況を後から確認できる。", "煙突を支えるため。"], "ans": 3, "exp": "検査記録は保全管理と法令遵守に関係する。"},
  {"id": 20201037, "year": 202010, "num": 37, "field": "law", "text": "『以上』を読み違えた場合に起こることとして、適切なものは次のうちどれか。", "opts": ["燃料性状が変わる。", "境界値を含むかの判断を誤る。", "水位が自動で上がる。", "安全弁が開く。", "検査証が消える。"], "ans": 1, "exp": "以上はその数値を含む。"},
  {"id": 20201038, "year": 202010, "num": 38, "field": "law", "text": "『未満』を読み違えた場合に起こることとして、適切なものは次のうちどれか。", "opts": ["境界値を含まない点を誤る。", "燃料が燃えなくなる。", "水位が必ず下がる。", "安全弁が増える。", "煙突がなくなる。"], "ans": 0, "exp": "未満はその数値を含まない。"},
  {"id": 20201039, "year": 202010, "num": 39, "field": "law", "text": "法令問題で『ただし』以下を読む理由として、適切なものは次のうちどれか。", "opts": ["燃料の種類を示すだけだから。", "必ず無意味だから。", "例外条件が正誤を左右することがあるため。", "水位を示すだけだから。", "安全弁の色を示すだけだから。"], "ans": 2, "exp": "ただし書きは例外や条件を示すため必ず確認する。"},
  {"id": 20201040, "year": 202010, "num": 40, "field": "law", "text": "届出問題で間違えやすい点として、適切なものは次のうちどれか。", "opts": ["燃料の発熱量だけ。", "届出先、期限、添付書類の混同。", "床の色だけ。", "水面計の照明だけ。", "煙突の方角だけ。"], "ans": 1, "exp": "法令の手続問題では相手先、期限、書類の読み分けが重要である。"},
  {"id": 20210401, "year": 202104, "num": 1, "field": "structure", "text": "温度及び圧力に関する記述として、適切でないものは次のうちどれか。", "opts": ["セルシウス温度は、水の氷点と沸点を基準に定められた温度である。", "絶対温度は、セルシウス温度に約273を加えた値で表される。", "圧力計に示される圧力は、一般にゲージ圧力である。", "絶対圧力は、ゲージ圧力から大気圧を差し引いた圧力である。", "標準大気圧は、約0.101MPaである。"], "ans": 3, "exp": "絶対圧力は、ゲージ圧力に大気圧を加えた圧力である。"},
  {"id": 20210402, "year": 202104, "num": 2, "field": "structure", "text": "蒸気の性質に関する記述として、適切なものは次のうちどれか。", "opts": ["蒸気表では、圧力は常にゲージ圧力だけで表示される。", "乾き飽和蒸気は、必ず水滴を大量に含む蒸気である。", "過熱蒸気は、飽和温度より低い温度の蒸気である。", "飽和水を同じ圧力の乾き飽和蒸気にする熱を蒸発潜熱という。", "水の比熱は、圧力に関係なく0である。"], "ans": 3, "exp": "蒸発潜熱は、飽和水を同圧の乾き飽和蒸気に変えるための熱である。"},
  {"id": 20210403, "year": 202104, "num": 3, "field": "structure", "text": "ボイラー効率に関する記述として、適切でないものは次のうちどれか。", "opts": ["燃料の発熱量は、ボイラー効率の算定に関係する。", "ボイラー効率は、燃料を多く消費するほど必ず高くなる。", "排ガス熱損失は、効率低下の一因となる。", "発生蒸気に与えた熱量と燃料が供給した熱量との関係で評価される。", "給水温度の上昇は、効率改善に寄与することがある。"], "ans": 1, "exp": "燃料消費量が増えるだけで効率が高くなるわけではない。"},
  {"id": 20210404, "year": 202104, "num": 4, "field": "structure", "text": "換算蒸発量に関する記述として、適切なものは次のうちどれか。", "opts": ["送風機の風量を示す値である。", "燃料タンクの容量を示す値である。", "実際蒸発量を一定条件の蒸発量に換算したものである。", "水面計の長さを示す値である。", "安全弁の吹出し圧力を示す値である。"], "ans": 2, "exp": "換算蒸発量は、ボイラー容量を比較しやすくするための換算値である。"},
  {"id": 20210405, "year": 202104, "num": 5, "field": "structure", "text": "燃焼室及び伝熱面に関する記述として、適切でないものは次のうちどれか。", "opts": ["燃焼装置は、燃料の種類に関係なく常に同一構造である。", "燃焼室は、火炉とも呼ばれる。", "燃焼室に面する伝熱面では、放射による熱の授受が行われる。", "燃焼室は、燃料を燃焼させて熱を発生させる部分である。", "燃焼室では、燃料と空気の混合状態が燃焼に影響する。"], "ans": 0, "exp": "燃焼装置は、液体燃料、気体燃料、固体燃料などで構造が異なる。"},
  {"id": 20210406, "year": 202104, "num": 6, "field": "structure", "text": "伝熱面に関する記述として、適切なものは次のうちどれか。", "opts": ["高温ガスから水又は蒸気へ熱を伝える面である。", "燃料を貯蔵するタンクの内面だけをいう。", "燃焼に必要な酸素量を測定する計器である。", "安全弁のばねを支える部品である。", "ボイラー水の硬度を下げる薬剤である。"], "ans": 0, "exp": "伝熱面は、燃焼ガスなどの熱をボイラー水又は蒸気へ伝える面である。"},
  {"id": 20210407, "year": 202104, "num": 7, "field": "structure", "text": "ボイラーの水循環に関する記述として、適切でないものは次のうちどれか。", "opts": ["温度が上がり気泡を含む水は、上昇しやすい。", "温度の低い水は、下降しやすい。", "水循環が良いほど、伝熱面温度は必ず無限に上昇する。", "自然循環は、水と蒸気の密度差を利用する。", "水循環が悪いと、伝熱面の過熱につながることがある。"], "ans": 2, "exp": "水循環が良いと熱が水へ伝わりやすく、伝熱面の過熱防止に役立つ。"},
  {"id": 20210408, "year": 202104, "num": 8, "field": "structure", "text": "水管ボイラーに関する記述として、適切なものは次のうちどれか。", "opts": ["蒸気ドラムを持つ形式は存在しない。", "煙管だけで構成されるボイラーである。", "必ず低圧小容量にしか用いられない。", "水管内の水又は蒸気を外部から加熱する構造である。", "高圧化すると必ず使用できなくなる。"], "ans": 3, "exp": "水管ボイラーは、水管内の水又は蒸気を加熱する構造で、高圧大容量にも適する。"},
  {"id": 20210409, "year": 202104, "num": 9, "field": "structure", "text": "強制循環式水管ボイラーに関する記述として、適切なものは次のうちどれか。", "opts": ["水循環を全く行わない。", "循環ポンプによりボイラー水を循環させる。", "蒸気だけを燃料として燃焼させる。", "給水を行わずに運転する。", "水面計を取り付けることができない。"], "ans": 1, "exp": "強制循環式では、循環系路中のポンプで水を循環させる。"},
  {"id": 20210410, "year": 202104, "num": 10, "field": "structure", "text": "炉筒煙管ボイラーに関する記述として、適切でないものは次のうちどれか。", "opts": ["保有水量が比較的多い。", "負荷変動による圧力変動が比較的小さい。", "煙管内を燃焼ガスが通る。", "高圧大容量ボイラーとして水管ボイラーより常に有利である。", "戻り燃焼方式を採用するものがある。"], "ans": 3, "exp": "高圧大容量には、水管ボイラーが一般に適している。"},
  {"id": 20210411, "year": 202104, "num": 11, "field": "handling", "text": "油だきボイラーの点火前に行う事項として、適切でないものは次のうちどれか。", "opts": ["炉内を換気する。", "水位を確認する。", "未燃ガスが残っていても直ちに点火する。", "燃料漏れを確認する。", "燃焼装置を点検する。"], "ans": 2, "exp": "未燃ガスが残ったまま点火すると逆火や爆発の危険がある。"},
  {"id": 20210412, "year": 202104, "num": 12, "field": "handling", "text": "ボイラーのたき始めに関する記述として、適切なものは次のうちどれか。", "opts": ["れんが積みの状態は無視してよい。", "急激な燃焼量増加は避ける。", "水位確認は昇圧後だけでよい。", "圧力計の動きは確認しなくてよい。", "燃焼開始直後に主蒸気弁を急開する。"], "ans": 1, "exp": "急激なたき上げは本体やれんが積みに悪影響を与えることがある。"},
  {"id": 20210413, "year": 202104, "num": 13, "field": "handling", "text": "逆火の原因として、適切でないものは次のうちどれか。", "opts": ["着火遅れがある。", "炉内に未燃ガスが滞留している。", "空気より先に燃料を供給する。", "煙道の通風が不足している。", "点火前に十分な換気を行う。"], "ans": 4, "exp": "十分な換気は逆火防止に有効であり、原因ではない。"},
  {"id": 20210414, "year": 202104, "num": 14, "field": "handling", "text": "ボイラー水位の異常低下の原因として、適切でないものは次のうちどれか。", "opts": ["給水装置の故障", "吹出し弁の閉止不完全", "蒸気の大量消費", "給水が正常に連続して行われている状態", "水面計の閉塞による誤認"], "ans": 3, "exp": "正常な給水は水位低下の原因ではない。"},
  {"id": 20210415, "year": 202104, "num": 15, "field": "handling", "text": "低水位を発見した場合の対応として、適切でないものは次のうちどれか。", "opts": ["燃焼を停止する。", "水位計の状態を確認する。", "状況に応じて責任者へ連絡する。", "原因を確認する。", "赤熱している可能性があっても大量の冷水を急に入れる。"], "ans": 4, "exp": "過熱状態への急給水は危険であり、所定手順に従う必要がある。"},
  {"id": 20210416, "year": 202104, "num": 16, "field": "handling", "text": "水面計の取扱いに関する記述として、適切なものは次のうちどれか。", "opts": ["閉塞すると水位を誤認するおそれがある。", "運転中は絶対に点検してはならない。", "水面計は圧力計の代わりに使用する。", "水面計が2個ある場合は、片方の表示だけを常に信じればよい。", "水面計の機能試験は不要である。"], "ans": 0, "exp": "水面計の閉塞は重大事故につながるため、機能確認が重要である。"},
  {"id": 20210417, "year": 202104, "num": 17, "field": "handling", "text": "ボイラー水の吹出しに関する記述として、適切なものは次のうちどれか。", "opts": ["不純物濃度の低下やスラッジ排出を目的とする。", "燃料の発熱量を高めるためだけに行う。", "安全弁の設定圧力を変えるために行う。", "常に水位を確認せず最大量行う。", "給水ポンプの代わりに行う。"], "ans": 0, "exp": "吹出しは水質管理のための操作であり、過度な吹出しは熱損失となる。"},
  {"id": 20210418, "year": 202104, "num": 18, "field": "handling", "text": "ボイラー水のpHに関する記述として、適切でないものは次のうちどれか。", "opts": ["腐食やスケール管理に関係する。", "酸性・アルカリ性の指標である。", "pHはボイラー水の状態と無関係である。", "水管理上、一定範囲に保つことが重要である。", "薬品処理で調整する場合がある。"], "ans": 2, "exp": "pHは水管理上の重要な指標である。"},
  {"id": 20210419, "year": 202104, "num": 19, "field": "handling", "text": "軟化装置に関する記述として、適切なものは次のうちどれか。", "opts": ["燃焼用空気の温度を上げる。", "カルシウムやマグネシウムなどの硬度成分を低減する。", "蒸気圧力を直接下げる安全弁である。", "燃料油を噴霧する装置である。", "煙道内のすすを除去する装置である。"], "ans": 1, "exp": "軟化装置は給水中の硬度成分を除去し、スケール防止に役立つ。"},
  {"id": 20210420, "year": 202104, "num": 20, "field": "handling", "text": "脱酸素剤の使用目的として、適切なものは次のうちどれか。", "opts": ["安全弁の吹出し量を測定する。", "燃料油の粘度を上げる。", "燃焼用空気量を増やす。", "給水中の溶存酸素による腐食を抑える。", "水面計のガラスを着色する。"], "ans": 3, "exp": "溶存酸素は腐食原因となるため、脱酸素剤で除去することがある。"},
  {"id": 20210421, "year": 202104, "num": 21, "field": "fuel", "text": "高発熱量と低発熱量に関する記述として、適切でないものは次のうちどれか。", "opts": ["高発熱量は水蒸気の凝縮潜熱を含む。", "低発熱量は高発熱量より小さい。", "燃料中の水素分は両者の差に影響する。", "低発熱量は高発熱量に凝縮潜熱を加えたものである。", "ボイラー効率計算では発熱量を用いる。"], "ans": 3, "exp": "低発熱量は、高発熱量から凝縮潜熱相当分を差し引く考え方である。"},
  {"id": 20210422, "year": 202104, "num": 22, "field": "fuel", "text": "引火点に関する記述として、適切なものは次のうちどれか。", "opts": ["水の比熱を示す値である。", "燃料が自然に燃え始める最低温度である。", "燃焼ガスの露点と同じ意味である。", "燃料中の灰分量を示す値である。", "液体燃料から発生した蒸気に小火炎を近づけたとき、瞬間的に燃え始める最低温度である。"], "ans": 4, "exp": "引火点は、液体燃料蒸気が小火炎で引火する最低温度である。自然発火温度とは異なる。"},
  {"id": 20210423, "year": 202104, "num": 23, "field": "fuel", "text": "燃料中の灰分に関する記述として、適切でないものは次のうちどれか。", "opts": ["多いと灰や付着物の原因となる。", "伝熱障害の原因となることがある。", "燃焼後に残る無機質分に関係する。", "多いほど常にボイラー効率が向上する。", "燃料管理上の性質の一つである。"], "ans": 3, "exp": "灰分が多いと付着や伝熱障害の原因となり、効率向上とは限らない。"},
  {"id": 20210424, "year": 202104, "num": 24, "field": "fuel", "text": "液体燃料の性質として、適切なものは次のうちどれか。", "opts": ["粘度は温度の影響を受ける。", "温度が変わっても粘度は全く変化しない。", "水分が混入しても燃焼には一切影響しない。", "引火点は燃料管理に無関係である。", "比重や密度は常に0である。"], "ans": 0, "exp": "重油などの粘度は温度により変化し、燃焼や噴霧状態に影響する。"},
  {"id": 20210425, "year": 202104, "num": 25, "field": "fuel", "text": "重油に含まれる硫黄分の影響として、適切なものは次のうちどれか。", "opts": ["ボイラー水位を直接上げる。", "燃焼に全く関係しない。", "水の硬度を下げる。", "硫黄酸化物や低温腐食に関係する。", "安全弁の作動圧力を自動調整する。"], "ans": 3, "exp": "硫黄分はSOxや低温腐食に関係する重要な成分である。"},
  {"id": 20210426, "year": 202104, "num": 26, "field": "fuel", "text": "低温腐食の抑制方法として、適切でないものは次のうちどれか。", "opts": ["硫黄分の少ない燃料を用いる。", "空気漏入を防止する。", "排ガス温度が露点以下になりにくいよう管理する。", "燃焼ガス中の酸素濃度を必要以上に高くしてSO3生成を促進する。", "添加剤を使用することがある。"], "ans": 3, "exp": "SO3生成や露点上昇につながる管理は低温腐食抑制として不適切である。"},
  {"id": 20210427, "year": 202104, "num": 27, "field": "fuel", "text": "重油中の水分及びスラッジに関する記述として、適切でないものは次のうちどれか。", "opts": ["多いほど燃焼状態は必ず安定する。", "配管やストレーナの詰まりに関係することがある。", "貯蔵管理上注意が必要である。", "燃焼不良の原因となることがある。", "燃料タンクの管理に関係する。"], "ans": 0, "exp": "水分やスラッジは燃焼や供給系統の障害になることがある。"},
  {"id": 20210428, "year": 202104, "num": 28, "field": "fuel", "text": "圧力噴霧式バーナに関する記述として、適切なものは次のうちどれか。", "opts": ["必ず蒸気だけを霧化媒体にする。", "燃料を霧化せず塊のまま燃やす。", "燃料油に圧力を加え、ノズルから噴霧する。", "空気を全く必要としない。", "燃焼量調節が不可能である。"], "ans": 2, "exp": "圧力噴霧式は、加圧した燃料油をノズルで霧化する方式である。"},
  {"id": 20210429, "year": 202104, "num": 29, "field": "fuel", "text": "戻り油式圧力噴霧バーナに関する記述として、適切なものは次のうちどれか。", "opts": ["燃料をすべて燃焼室外へ排出する方式である。", "一部の油を戻すことで燃焼量調節範囲を広げる。", "燃焼量調節が全くできない。", "水だけを噴霧するバーナである。", "ガス専焼バーナの一種である。"], "ans": 1, "exp": "戻り油式は、戻り油量を調整して噴射量を変え、ターンダウン範囲を広げる。"},
  {"id": 20210430, "year": 202104, "num": 30, "field": "fuel", "text": "回転式バーナに関する記述として、適切なものは次のうちどれか。", "opts": ["燃焼用空気を完全に不要にする。", "水管内で蒸気を凝縮させる装置である。", "安全弁の一種である。", "燃料油を加熱せず固体のまま供給する。", "回転カップなどの遠心力を利用して燃料を微粒化する。"], "ans": 4, "exp": "回転式バーナは、遠心力を利用して油を微粒化する。"},
  {"id": 20210431, "year": 202104, "num": 31, "field": "law", "text": "ボイラーの伝熱面積に関する記述として、法令上、適切なものは次のうちどれか。", "opts": ["伝熱面積は法令上全く意味を持たない。", "すべての附属配管の外面積を必ず算入する。", "エコノマイザは常に本体伝熱面積に算入する。", "伝熱面積は燃料タンク容量だけで決まる。", "伝熱面積は、ボイラーの区分や取扱資格に関係することがある。"], "ans": 4, "exp": "伝熱面積はボイラーの規模判断や法令適用に関係する。"},
  {"id": 20210432, "year": 202104, "num": 32, "field": "law", "text": "水管ボイラーの伝熱面積に関する記述として、法令上、適切でないものは次のうちどれか。", "opts": ["水管の伝熱面は算定対象となる。", "耐火れんがで覆われた部分の扱いには注意を要する。", "管寄せなどの扱いは法令上の定めに従う。", "どの部分も名称に関係なくすべて二倍して算入する。", "ボイラー種別により算定方法が異なることがある。"], "ans": 3, "exp": "伝熱面積は種類や部位ごとの算定方法に従って扱う。"},
  {"id": 20210433, "year": 202104, "num": 33, "field": "law", "text": "貫流ボイラーに関する法令上の扱いとして、適切なものは次のうちどれか。", "opts": ["伝熱面積や附属品に関する規定が問題となることがある。", "法令上は常にボイラーではない。", "給水装置に関する規定は全くない。", "安全装置は不要である。", "検査や届出の対象になることはない。"], "ans": 0, "exp": "貫流ボイラーも、規模や用途により法令上の規定対象となる。"},
  {"id": 20210434, "year": 202104, "num": 34, "field": "law", "text": "鋳鉄製温水ボイラーに関する法令問題で問われやすいものは次のうちどれか。", "opts": ["水の比熱だけ", "燃料の総発熱量だけ", "煙突内ガスの密度だけ", "取り付ける附属品", "油バーナのターンダウン比だけ"], "ans": 3, "exp": "鋳鉄製温水ボイラーでは、附属品や取扱資格などが頻出である。"},
  {"id": 20210435, "year": 202104, "num": 35, "field": "law", "text": "ボイラー設置に関する記述として、法令上、適切なものは次のうちどれか。", "opts": ["一定のボイラーでは、設置届や落成検査が関係する。", "設置手続は一切不要である。", "ボイラー室の構造は法令上問われない。", "検査は常に使用後10年経ってから初めて行う。", "設置者ではなく燃料販売店だけが手続を行う。"], "ans": 0, "exp": "ボイラーの種類や規模により、設置届や落成検査などが関係する。"},
  {"id": 20210436, "year": 202104, "num": 36, "field": "law", "text": "ボイラー室に関する記述として、法令上、適切でないものは次のうちどれか。", "opts": ["ボイラーの周囲には点検や取扱いに必要な空間が求められる。", "出入口や構造に関する規定が問題となることがある。", "必要な場合、専用の建物又は区画が求められることがある。", "ボイラー室の安全確保は重要である。", "どのようなボイラーでも住居の寝室内に自由に設置できる。"], "ans": 4, "exp": "ボイラー室や設置場所には法令上の制限がある。"},
  {"id": 20210437, "year": 202104, "num": 37, "field": "law", "text": "落成検査に関する記述として、適切なものは次のうちどれか。", "opts": ["設置後、使用前に受ける検査として問われることがある。", "燃料購入量を確認するだけの検査である。", "ボイラー検査証と一切関係しない。", "どのボイラーにも一律に不要である。", "運転者が任意に省略できる。"], "ans": 0, "exp": "落成検査は、設置後の使用前検査として出題されることが多い。"},
  {"id": 20210438, "year": 202104, "num": 38, "field": "law", "text": "使用を廃止したボイラーを再び設置する場合の手続に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料を入れれば直ちに使用できる。", "過去に使っていれば検査は永久に不要である。", "使用検査や設置届などが関係する場合がある。", "法令手続は取扱作業主任者の口頭確認だけで足りる。", "検査証の有無は全く関係しない。"], "ans": 2, "exp": "廃止後の再設置では、使用検査や設置届などの手続が問われることがある。"},
  {"id": 20210439, "year": 202104, "num": 39, "field": "law", "text": "ボイラー検査証に関する記述として、適切なものは次のうちどれか。", "opts": ["検査証は燃料タンクにだけ交付される。", "一度交付されれば永久に更新不要である。", "紛失しても再交付制度はない。", "有効期間があり、更新には性能検査が関係する。", "検査証の有効期間は事業者が自由に決める。"], "ans": 3, "exp": "ボイラー検査証には有効期間があり、更新には性能検査が関係する。"},
  {"id": 20210440, "year": 202104, "num": 40, "field": "law", "text": "性能検査に関する記述として、適切なものは次のうちどれか。", "opts": ["取扱作業主任者の年齢だけを確認する。", "燃料の銘柄を決める検査である。", "水の比熱を測定するだけの検査である。", "検査証とは無関係である。", "検査証の有効期間更新に関係する。"], "ans": 4, "exp": "性能検査は、検査証の有効期間更新と関係する重要な検査である。"},
  {"id": 20211001, "year": 202110, "num": 1, "field": "structure", "text": "貫流ボイラーに関する記述として、適切なものは次のうちどれか。", "opts": ["給水処理は不要である。", "必ず大きな蒸気ドラムと水ドラムを持つ。", "管系の一端から給水し、他端から蒸気を取り出す。", "起動に非常に長時間を要することだけが特徴である。", "水循環を良くするため大きな胴を必要とする。"], "ans": 2, "exp": "貫流ボイラーは、管系を水が一方向に流れながら蒸発する形式である。"},
  {"id": 20211002, "year": 202110, "num": 2, "field": "structure", "text": "鋳鉄製ボイラーに関する記述として、適切でないものは次のうちどれか。", "opts": ["セクションを組み合わせて構成されるものがある。", "主に暖房用などで用いられる。", "鋳鉄は衝撃や急激な温度変化に対して注意を要する。", "鋼製ボイラーと同様に、どのような高圧にも制限なく使用できる。", "組立てや増設に特徴を持つ形式がある。"], "ans": 3, "exp": "鋳鉄製ボイラーは、構造・材料上の制限があり、高圧用途に無制限に使えるわけではない。"},
  {"id": 20211003, "year": 202110, "num": 3, "field": "structure", "text": "パッケージボイラーに関する記述として、適切なものは次のうちどれか。", "opts": ["安全装置を省略するための形式である。", "現地で必ず炉筒を鍛造して作る。", "燃焼装置を備えないものだけをいう。", "ボイラー水を全く使わない形式である。", "工場で本体、燃焼装置、附属品などを一体的に組み立てたものが多い。"], "ans": 4, "exp": "パッケージボイラーは、工場組立てにより現地据付を容易にした形式が多い。"},
  {"id": 20211004, "year": 202110, "num": 4, "field": "structure", "text": "安全弁に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料油を加熱するための装置である。", "給水中の硬度成分を除去する薬剤である。", "圧力が所定値を超えたとき蒸気を逃がす安全装置である。", "燃焼用空気を送るファンである。", "ボイラー水を濃縮するためだけに用いる弁である。"], "ans": 2, "exp": "安全弁は過圧防止のための重要な安全装置である。"},
  {"id": 20211005, "year": 202110, "num": 5, "field": "structure", "text": "水面計に関する記述として、適切でないものは次のうちどれか。", "opts": ["水面計は燃料の発熱量を測定する計器である。", "水側及び蒸気側の連絡状態が重要である。", "水面計の機能試験は重要である。", "水面計が閉塞すると正しい水位が分からなくなる。", "蒸気ボイラーの水位を確認するために用いる。"], "ans": 0, "exp": "水面計は水位確認のための装置であり、燃料発熱量の測定器ではない。"},
  {"id": 20211006, "year": 202110, "num": 6, "field": "structure", "text": "圧力計に関する記述として、適切なものは次のうちどれか。", "opts": ["ボイラー水の硬度を下げる装置である。", "ボイラーの圧力を監視する計器である。", "燃料を霧化するバーナである。", "蒸気中のドレンを排出する弁である。", "水面計の水位を必ず低く表示する装置である。"], "ans": 1, "exp": "圧力計は圧力を監視するための基本的な計測器である。"},
  {"id": 20211007, "year": 202110, "num": 7, "field": "structure", "text": "エコノマイザに関する記述として、適切なものは次のうちどれか。", "opts": ["燃料タンク内の水分を除去する。", "排ガスの熱を利用して給水を加熱する。", "炉内に二次空気を吹き込むバーナである。", "安全弁の吹出し量を測定する計器である。", "ボイラー水のpHを直接表示する水面計である。"], "ans": 1, "exp": "エコノマイザは排ガス余熱で給水を加熱し、効率向上に役立つ。"},
  {"id": 20211008, "year": 202110, "num": 8, "field": "structure", "text": "空気予熱器に関する記述として、適切でないものは次のうちどれか。", "opts": ["燃焼用空気を予熱する。", "排ガスの熱を利用するものがある。", "燃焼効率の向上に寄与することがある。", "水面計の代わりに水位を直接表示する装置である。", "低品位燃料の燃焼改善に役立つ場合がある。"], "ans": 3, "exp": "空気予熱器は燃焼用空気を加熱する装置であり、水位表示装置ではない。"},
  {"id": 20211009, "year": 202110, "num": 9, "field": "structure", "text": "蒸気トラップに関する記述として、適切なものは次のうちどれか。", "opts": ["燃料油を微粒化する。", "給水中の酸素を化学的に除去する。", "蒸気配管や装置に生じたドレンを排出する。", "ボイラー室の換気量を直接測定する。", "燃焼ガス中のNOxを生成する。"], "ans": 2, "exp": "蒸気トラップは蒸気をできるだけ逃がさず、ドレンを排出する装置である。"},
  {"id": 20211010, "year": 202110, "num": 10, "field": "structure", "text": "温水ボイラーの逃がし弁に関する記述として、適切なものは次のうちどれか。", "opts": ["給水中の硬度成分を再生する。", "燃料の粘度を下げるために用いる。", "蒸気中の乾き度を直接測定する。", "燃焼用空気を圧縮する。", "水の膨張などで圧力が設定値を超えた場合に水を逃がす。"], "ans": 4, "exp": "逃がし弁は温水ボイラーの過圧を防ぐために用いられる。"},
  {"id": 20211011, "year": 202110, "num": 11, "field": "handling", "text": "キャリオーバの影響として、適切でないものは次のうちどれか。", "opts": ["蒸気純度の低下", "過熱器への悪影響", "配管や機器への障害", "蒸気の純度が必ず向上すること", "水位の確認が困難になること"], "ans": 3, "exp": "キャリオーバは蒸気純度を低下させる。"},
  {"id": 20211012, "year": 202110, "num": 12, "field": "handling", "text": "キャリオーバ発生時の処置として、適切なものは次のうちどれか。", "opts": ["燃焼量を下げるなど、状態を安定させる。", "主蒸気弁を急開して一気に圧力を下げる。", "水質確認を行わない。", "水位が高くても吹出しをしない。", "原因を確認せず運転を続ける。"], "ans": 0, "exp": "キャリオーバ時は燃焼量や水位、水質を確認し、急操作を避ける。"},
  {"id": 20211013, "year": 202110, "num": 13, "field": "handling", "text": "スートブローに関する記述として、適切でないものは次のうちどれか。", "opts": ["伝熱面に付着したすすを除去する。", "ドレンを抜いた蒸気を用いることが望ましい。", "燃焼状態に注意して行う。", "一箇所に長時間吹き付け続けるのがよい。", "実施後の排ガス温度や通風状態を確認することがある。"], "ans": 3, "exp": "一箇所への長時間吹付けは損傷の原因となる。"},
  {"id": 20211014, "year": 202110, "num": 14, "field": "handling", "text": "ボイラー停止時の操作として、適切でないものは次のうちどれか。", "opts": ["燃料供給を停止する。", "圧力が残っていても直ちにマンホールを開ける。", "蒸気弁や給水弁の状態を確認する。", "炉内換気や冷却状態に注意する。", "必要に応じて水位を確認する。"], "ans": 1, "exp": "圧力が残っている状態で開放するのは危険である。"},
  {"id": 20211015, "year": 202110, "num": 15, "field": "handling", "text": "満水保存法に関する記述として、適切なものは次のうちどれか。", "opts": ["安全弁のばねを交換する方法である。", "ボイラーを完全に乾燥させる保存法である。", "燃料タンク内の水分を抜く方法である。", "運転中に常時行う燃焼調整法である。", "休止中の腐食防止を目的として行う保存法の一つである。"], "ans": 4, "exp": "満水保存法は休止中の内面腐食防止を目的とする保存法である。"},
  {"id": 20211016, "year": 202110, "num": 16, "field": "handling", "text": "酸洗浄に関する記述として、適切でないものは次のうちどれか。", "opts": ["スケール除去のために行われる。", "腐食防止のため抑制剤を用いることがある。", "洗浄後には水洗や中和防錆処理を行う。", "作業中に発生するガス等への安全対策が必要である。", "どのような状態でも、抑制剤や後処理なしで行えばよい。"], "ans": 4, "exp": "酸洗浄は腐食やガス発生などの危険を伴うため、適切な薬品管理と後処理が必要である。"},
  {"id": 20211017, "year": 202110, "num": 17, "field": "handling", "text": "燃焼安全装置の燃料遮断弁が作動する原因として、適切でないものは次のうちどれか。", "opts": ["異常消火", "低水位", "送風量低下", "正常な水位で安定燃焼していること", "油圧異常"], "ans": 3, "exp": "正常運転状態は燃料遮断弁作動の原因ではない。"},
  {"id": 20211018, "year": 202110, "num": 18, "field": "handling", "text": "安全弁の試験に関する記述として、適切なものは次のうちどれか。", "opts": ["吹出し圧力や吹止まり圧力を確認する。", "作動しない場合は圧力をさらに無制限に上げる。", "調整後の確認は不要である。", "安全弁は一度取り付ければ永久に点検不要である。", "逃がし弁は燃料流量調節だけに用いる。"], "ans": 0, "exp": "安全弁は設定どおり作動するか確認することが重要である。"},
  {"id": 20211019, "year": 202110, "num": 19, "field": "handling", "text": "内面腐食の原因として、適切なものは次のうちどれか。", "opts": ["蒸気配管の保温材の色", "水面計の照明色", "燃料タンクの外面塗装", "煙突の高さだけ", "給水中の溶存酸素"], "ans": 4, "exp": "溶存酸素や不適切な水質は内面腐食の原因となる。"},
  {"id": 20211020, "year": 202110, "num": 20, "field": "handling", "text": "ガラス水面計の機能試験を行う時期として、適切なものは次のうちどれか。", "opts": ["一度取り付けた直後だけでよい。", "補修後や運転開始時など、機能確認が必要なとき。", "異常水位が疑われるときでも行ってはならない。", "水面計は試験できない装置である。", "燃料タンクの清掃時だけ行う。"], "ans": 1, "exp": "水面計は水位確認の重要装置であり、必要な時期に機能試験を行う。"},
  {"id": 20211021, "year": 202110, "num": 21, "field": "fuel", "text": "ガンタイプバーナに関する記述として、適切でないものは次のうちどれか。", "opts": ["小容量ボイラーに用いられることが多い。", "燃焼用空気を全く送らない方式だけをいう。", "自動制御に適したものがある。", "ファンと圧力噴霧式バーナを組み合わせたものがある。", "油だき小形ボイラーに見られる形式である。"], "ans": 1, "exp": "ガンタイプバーナは、ファンで燃焼用空気を供給する形式が多い。"},
  {"id": 20211022, "year": 202110, "num": 22, "field": "fuel", "text": "気体燃料の燃焼に関する記述として、適切なものは次のうちどれか。", "opts": ["漏えいしても安全管理は不要である。", "霧化媒体が必ず必要である。", "空気との混合が比較的容易である。", "点火及び消火が油燃料より必ず困難である。", "燃焼制御ができない。"], "ans": 2, "exp": "気体燃料は空気と混合しやすいが、漏えい対策など安全管理が重要である。"},
  {"id": 20211023, "year": 202110, "num": 23, "field": "fuel", "text": "ガス燃焼方式に関する記述として、適切でないものは次のうちどれか。", "opts": ["予混合燃焼では、燃料ガスと空気をあらかじめ混合する。", "拡散燃焼では、燃焼しながら燃料と空気が混合する。", "燃焼方式により火炎の形状や安定性が変わる。", "ガス燃焼では爆発範囲や漏えいに注意する。", "ガス燃焼では燃料と空気の混合状態は全く影響しない。"], "ans": 4, "exp": "ガス燃焼では燃料と空気の混合状態が燃焼に大きく影響する。"},
  {"id": 20211024, "year": 202110, "num": 24, "field": "fuel", "text": "気体燃料を用いる場合の安全管理として、適切なものは次のうちどれか。", "opts": ["燃焼安全装置は不要である。", "配管の気密は確認しなくてよい。", "点火前換気は不要である。", "漏えい検知や換気に注意する。", "ガス圧の異常は燃焼に影響しない。"], "ans": 3, "exp": "気体燃料では漏えい、換気、ガス圧、燃焼安全装置の管理が重要である。"},
  {"id": 20211025, "year": 202110, "num": 25, "field": "fuel", "text": "通風に関する記述として、適切でないものは次のうちどれか。", "opts": ["自然通風は煙突内外の密度差を利用する。", "押込通風は燃焼用空気を押し込む。", "通風方式は燃焼状態に一切影響しない。", "平衡通風は押込と誘引を組み合わせる。", "誘引通風は燃焼ガスを引き出す。"], "ans": 2, "exp": "通風方式は燃焼状態、炉内圧、必要動力などに影響する。"},
  {"id": 20211026, "year": 202110, "num": 26, "field": "fuel", "text": "多翼形ファンに関する記述として、適切なものは次のうちどれか。", "opts": ["前向きの羽根を多数設けたファンである。", "燃料油を加熱する装置である。", "水面計の一種である。", "安全弁のばねである。", "給水中の硬度を除去する薬剤である。"], "ans": 0, "exp": "多翼形ファンは、多数の前向き羽根を持つ遠心ファンである。"},
  {"id": 20211027, "year": 202110, "num": 27, "field": "fuel", "text": "誘引通風に関する記述として、適切なものは次のうちどれか。", "opts": ["燃焼ガスをファンで引き出す。", "燃焼用空気を炉内に押し込むだけの方式である。", "煙突を全く必要としない化学薬品である。", "給水を加熱する装置である。", "燃料タンクの水抜き方式である。"], "ans": 0, "exp": "誘引通風は、誘引ファンで燃焼ガスを吸い出す方式である。"},
  {"id": 20211028, "year": 202110, "num": 28, "field": "fuel", "text": "平衡通風に関する記述として、適切でないものは次のうちどれか。", "opts": ["押込ファンと誘引ファンを併用する。", "炉内圧を調整しやすい。", "通風抵抗が大きいボイラーに用いられることがある。", "燃焼調節に関係する。", "燃焼用空気も燃焼ガスも全く動かさない方式である。"], "ans": 4, "exp": "平衡通風は押込ファンと誘引ファンにより空気と燃焼ガスの流れを調整する。"},
  {"id": 20211029, "year": 202110, "num": 29, "field": "fuel", "text": "空気比に関する記述として、適切なものは次のうちどれか。", "opts": ["燃焼とは無関係である。", "常に0でなければならない。", "実際空気量を理論空気量で除した値である。", "排ガス中酸素濃度とは関係しない。", "燃料の種類にかかわらず常に同じ値で固定する。"], "ans": 2, "exp": "空気比は実際空気量/理論空気量で表す。過大な空気比は熱損失増加につながる。"},
  {"id": 20211030, "year": 202110, "num": 30, "field": "fuel", "text": "NOx抑制方法として、適切なものは次のうちどれか。", "opts": ["燃焼管理を行わない。", "炉内酸素濃度を必要以上に高くする。", "窒素分の多い燃料だけを選ぶ。", "排ガス再循環を必ず禁止する。", "燃焼温度を局所的に高くしすぎない。"], "ans": 4, "exp": "NOx抑制では、局所高温域の抑制や低NOx燃焼などが有効である。"},
  {"id": 20211031, "year": 202110, "num": 31, "field": "law", "text": "変更検査に関する記述として、適切でないものは次のうちどれか。", "opts": ["主要部分の変更で必要となる場合がある。", "どのような変更でも、検査や届出の対象になることは絶対にない。", "胴や過熱器などの変更が問題となることがある。", "所轄労働基準監督署長が関係する場合がある。", "変更内容により手続が異なることがある。"], "ans": 1, "exp": "主要部分や設備の変更では、届出や変更検査が必要となる場合がある。"},
  {"id": 20211032, "year": 202110, "num": 32, "field": "law", "text": "ボイラー検査証の再交付又は書替えに関する記述として、適切なものは次のうちどれか。", "opts": ["事業者変更があっても常に何も必要ない。", "検査証は一切書替えできない。", "紛失や記載事項変更などで手続が必要となる場合がある。", "検査証は水面計に貼れば法令手続は不要になる。", "再交付は燃料販売店だけが行う。"], "ans": 2, "exp": "検査証の滅失や記載事項変更では、再交付・書替えが問題となる。"},
  {"id": 20211033, "year": 202110, "num": 33, "field": "law", "text": "ボイラー取扱作業主任者の職務として、適切なものは次のうちどれか。", "opts": ["急激な負荷変動を積極的に与える。", "安全弁の状態を一切見ない。", "圧力、水位及び燃焼状態を監視する。", "水面計を取り外して運転する。", "燃料遮断弁を常に無効化する。"], "ans": 2, "exp": "作業主任者は、圧力、水位、燃焼状態などを監視し、安全運転に努める。"},
  {"id": 20211034, "year": 202110, "num": 34, "field": "law", "text": "二級ボイラー技士を作業主任者に選任できる範囲に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料が重油なら必ず選任不要である。", "すべてのボイラーで無制限に選任できる。", "法令上、二級ボイラー技士は作業主任者になれない。", "ボイラーの種類や伝熱面積により制限を受ける。", "水管ボイラーでは伝熱面積に関係しない。"], "ans": 3, "exp": "作業主任者に選任できる資格範囲は、ボイラーの種類や規模により異なる。"},
  {"id": 20211035, "year": 202110, "num": 35, "field": "law", "text": "ボイラー取扱作業主任者の職務として、適切でないものは次のうちどれか。", "opts": ["安全装置を取り外して運転するよう指示する。", "安全弁の機能保持に注意する。", "燃焼状態を監視する。", "ボイラー排水や水質管理に注意する。", "急激な負荷変動を避けるよう努める。"], "ans": 0, "exp": "安全装置を取り外して運転することは不適切である。"},
  {"id": 20211036, "year": 202110, "num": 36, "field": "law", "text": "鋼製蒸気ボイラーの圧力計に関する記述として、適切でないものは次のうちどれか。", "opts": ["圧力を確認しやすいように取り付ける。", "目盛りを隠し、圧力を読めないようにする。", "著しい振動を避ける。", "内部が凍結しないようにする。", "コック又は弁の開閉状態が分かるようにする。"], "ans": 1, "exp": "圧力計は見やすく、圧力を確実に確認できるようにする。"},
  {"id": 20211037, "year": 202110, "num": 37, "field": "law", "text": "安全弁に関する法令上の記述として、適切なものは次のうちどれか。", "opts": ["給水中の硬度を除去する装置である。", "燃焼用空気量を増やすファンである。", "ボイラーの過圧を防ぐ重要な附属品である。", "水位を表示するガラス管である。", "燃料の引火点を測定する器具である。"], "ans": 2, "exp": "安全弁は過圧防止のための重要な附属品である。"},
  {"id": 20211038, "year": 202110, "num": 38, "field": "law", "text": "温水ボイラーの返り管に関する記述として、適切なものは次のうちどれか。", "opts": ["必ず蒸気を過熱するためだけに用いる。", "水道など圧力を有する水源との接続が法令問題で問われることがある。", "燃料油を霧化するノズルである。", "煙突の通風力を測定する計器である。", "ボイラー水とは無関係の部品である。"], "ans": 1, "exp": "温水ボイラーや鋳鉄製ボイラーでは、返り管や給水源との関係が問われる。"},
  {"id": 20211039, "year": 202110, "num": 39, "field": "law", "text": "鋳鉄製温水ボイラーに取り付ける附属品として、法令問題で問われやすいものは次のうちどれか。", "opts": ["燃料販売契約書", "燃料の総発熱量表だけ", "通勤経路図", "作業者の身長計", "温度計又は水高計などの計器類"], "ans": 4, "exp": "鋳鉄製温水ボイラーでは、温度計、水高計、逃がし管などの附属品が問われやすい。"},
  {"id": 20211040, "year": 202110, "num": 40, "field": "law", "text": "貫流ボイラーの附属品に関する記述として、適切でないものは次のうちどれか。", "opts": ["安全弁などの安全装置が問われる。", "法令上、附属品に関する規定は一切存在しない。", "過熱器がある場合、ドレン抜きが問題となることがある。", "燃焼安全装置が問題となることがある。", "給水装置に関する規定が問われることがある。"], "ans": 1, "exp": "貫流ボイラーにも附属品や安全装置に関する規定がある。"},
  {"id": 20220401, "year": 202204, "num": 1, "field": "structure", "text": "飽和蒸気に関する記述として、適切なものは次のうちどれか。", "opts": ["圧力が変わっても飽和温度は全く変わらない。", "必ず飽和温度より低い温度で存在する。", "同じ圧力で水と蒸気が平衡している状態の蒸気である。", "水分を含む蒸気はすべて過熱蒸気である。", "蒸気表では扱われない。"], "ans": 2, "exp": "飽和蒸気は、同じ圧力で水と蒸気が平衡している状態の蒸気である。"},
  {"id": 20220402, "year": 202204, "num": 2, "field": "structure", "text": "過熱蒸気に関する記述として、適切でないものは次のうちどれか。", "opts": ["飽和温度を超えて加熱された蒸気である。", "蒸気タービンなどで利用されることがある。", "乾き飽和蒸気をさらに加熱して得られる。", "過熱器でつくられることがある。", "同じ圧力の飽和蒸気より温度が低い。"], "ans": 4, "exp": "過熱蒸気は同じ圧力の飽和温度より高温の蒸気である。"},
  {"id": 20220403, "year": 202204, "num": 3, "field": "structure", "text": "仕事率及び熱量に関する記述として、適切なものは次のうちどれか。", "opts": ["kJは長さの単位である。", "1kWhは1Jより小さい。", "仕事率は温度の単位である。", "熱量は圧力計だけで直接読む。", "1Wは1J/sである。"], "ans": 4, "exp": "Wは仕事率の単位で、1W=1J/sである。"},
  {"id": 20220404, "year": 202204, "num": 4, "field": "structure", "text": "放射伝熱面に関する記述として、適切なものは次のうちどれか。", "opts": ["水面計のガラス管をいう。", "給水ポンプの羽根車をいう。", "燃料タンクの底板だけをいう。", "火炎や高温ガスからの放射熱を受ける伝熱面である。", "安全弁のばねをいう。"], "ans": 3, "exp": "燃焼室に面する水冷壁などは放射熱を多く受ける。"},
  {"id": 20220405, "year": 202204, "num": 5, "field": "structure", "text": "接触伝熱面に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料を貯蔵する面だけをいう。", "燃焼ガスとの接触により熱を受ける伝熱面である。", "空気予熱器の送風機だけをいう。", "安全弁の吹出し管だけをいう。", "圧力計の目盛盤だけをいう。"], "ans": 1, "exp": "煙管など、ガスとの接触で熱を受ける面は接触伝熱面として扱われる。"},
  {"id": 20220406, "year": 202204, "num": 6, "field": "structure", "text": "自然循環式ボイラーの循環力に関する記述として、適切なものは次のうちどれか。", "opts": ["循環力は燃料タンクの色だけで決まる。", "水と蒸気を含む水との密度差が循環力に関係する。", "密度差は循環に関係しない。", "常に給水ポンプを使わなければ循環しない。", "水位がなくても循環は安全に維持される。"], "ans": 1, "exp": "自然循環は水と気泡を含む水との密度差を利用する。"},
  {"id": 20220407, "year": 202204, "num": 7, "field": "structure", "text": "水管ボイラーの特徴として、適切でないものは次のうちどれか。", "opts": ["高圧大容量に適した形式がある。", "必ず煙管だけで構成される。", "炉壁を水冷壁にできる形式がある。", "水管を通る水又は蒸気が加熱される。", "自然循環式や強制循環式がある。"], "ans": 1, "exp": "煙管だけで構成されるのは水管ボイラーの説明ではない。"},
  {"id": 20220408, "year": 202204, "num": 8, "field": "structure", "text": "貫流ボイラーの給水処理に関する記述として、適切なものは次のうちどれか。", "opts": ["給水中の不純物は燃焼用空気に変わる。", "給水処理は絶対に不要である。", "硬度成分が多いほど常に安全である。", "スケールは発生しない構造なので管理不要である。", "細い管内で蒸発が進むため、十分な給水処理が重要である。"], "ans": 4, "exp": "貫流ボイラーでは管内で蒸発が進むため、給水処理が重要である。"},
  {"id": 20220409, "year": 202204, "num": 9, "field": "structure", "text": "炉筒煙管ボイラーの保有水量に関する記述として、適切なものは次のうちどれか。", "opts": ["保有水量が多いほど起動は必ず瞬時に完了する。", "保有水量は常にゼロである。", "水管ボイラーに比べて保有水量が多いものが多く、圧力変動が比較的小さい。", "負荷変動と圧力変動は全く関係しない。", "保有水量は燃料中の硫黄分で決まる。"], "ans": 2, "exp": "炉筒煙管ボイラーは保有水量が多く、圧力変動が比較的小さい傾向がある。"},
  {"id": 20220410, "year": 202204, "num": 10, "field": "structure", "text": "鋳鉄製ボイラーの取扱いで注意すべき事項として、適切なものは次のうちどれか。", "opts": ["高圧大容量専用である。", "どのような急冷にも強く、注意は不要である。", "急激な温度変化や衝撃に注意する。", "水を使わない形式である。", "附属品は取り付けられない。"], "ans": 2, "exp": "鋳鉄は衝撃や急激な温度変化に注意が必要である。"},
  {"id": 20220411, "year": 202204, "num": 11, "field": "handling", "text": "プレパージの目的として、適切なものは次のうちどれか。", "opts": ["燃料の発熱量を測定する。", "ボイラー水の硬度を下げる。", "安全弁のばねを強くする。", "炉内や煙道内の未燃ガスを排出する。", "水面計のガラスを洗浄するだけである。"], "ans": 3, "exp": "プレパージは点火前に未燃ガスを排出し、逆火や爆発を防ぐために行う。"},
  {"id": 20220412, "year": 202204, "num": 12, "field": "handling", "text": "たき始め時の水位変化に関する記述として、適切なものは次のうちどれか。", "opts": ["水位計は点火後すぐ取り外す。", "水位は絶対に変動しない。", "水温上昇や蒸気発生により水位が変動するため注意して監視する。", "水位が見えなくても運転を続ける。", "水位は燃料タンクの色で判断する。"], "ans": 2, "exp": "たき始め時は水位が変動しやすく、複数の水面計の一致などを確認する。"},
  {"id": 20220413, "year": 202204, "num": 13, "field": "handling", "text": "ボイラー昇圧時の圧力計の確認として、適切なものは次のうちどれか。", "opts": ["圧力計は水位確認にだけ用いる。", "指針が動かない方が安全である。", "圧力計は昇圧時に隠しておく。", "指針の上昇が円滑か確認する。", "圧力計は燃焼用空気の湿度を示す。"], "ans": 3, "exp": "昇圧時には圧力計の指針が円滑に動くか確認する。"},
  {"id": 20220414, "year": 202204, "num": 14, "field": "handling", "text": "水面計の吹出し操作に関する記述として、適切なものは次のうちどれか。", "opts": ["安全弁のばねを交換するために行う。", "燃料油の粘度を下げるために行う。", "煙突の高さを調整するために行う。", "燃焼用空気を加熱するために行う。", "水側・蒸気側の連絡を確認し、閉塞を防ぐ目的で行う。"], "ans": 4, "exp": "水面計の吹出しは連絡管の閉塞確認・排出のために行う。"},
  {"id": 20220415, "year": 202204, "num": 15, "field": "handling", "text": "験水コックがある場合の確認として、適切なものは次のうちどれか。", "opts": ["水部のコックから水が出ることを確認する。", "蒸気部のコックから燃料油が出ることを確認する。", "すべてのコックを溶接で閉じる。", "確認せずに水面計を外す。", "水が出ないほど正常である。"], "ans": 0, "exp": "験水コックは水位確認の補助として用いられ、水部から水が出ることを確認する。"},
  {"id": 20220416, "year": 202204, "num": 16, "field": "handling", "text": "給水内管の穴が閉塞した場合に起こり得ることとして、適切なものは次のうちどれか。", "opts": ["安全弁が不要になる。", "燃料の硫黄分がゼロになる。", "給水分布が悪くなり、水位管理に支障を生じる。", "空気比が必ず1になる。", "煙突の高さが変わる。"], "ans": 2, "exp": "給水内管の閉塞は給水状態を悪化させる。"},
  {"id": 20220417, "year": 202204, "num": 17, "field": "handling", "text": "ボイラー水の濃縮が進みすぎた場合の影響として、適切なものは次のうちどれか。", "opts": ["キャリオーバやスケール障害につながることがある。", "蒸気の純度が必ず向上する。", "燃料消費が必ずゼロになる。", "安全弁が作動しなくてもよくなる。", "水面計が不要になる。"], "ans": 0, "exp": "ボイラー水の過度な濃縮は障害の原因となる。"},
  {"id": 20220418, "year": 202204, "num": 18, "field": "handling", "text": "酸消費量に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料タンク容量の単位である。", "ボイラー水の水質管理指標の一つである。", "煙突の通風力を直接表す。", "安全弁の吹出し量を表す。", "水面計の長さだけを示す。"], "ans": 1, "exp": "酸消費量は水質管理で扱う指標である。"},
  {"id": 20220419, "year": 202204, "num": 19, "field": "handling", "text": "硬度成分に関する記述として、適切でないものは次のうちどれか。", "opts": ["多いほど常に伝熱が良くなる。", "スケール発生の原因となる。", "軟化処理で低減する。", "カルシウムやマグネシウムが関係する。", "給水管理で重要である。"], "ans": 0, "exp": "硬度成分はスケールの原因となり、伝熱を悪化させることがある。"},
  {"id": 20220420, "year": 202204, "num": 20, "field": "handling", "text": "清缶剤の目的として、適切でないものは次のうちどれか。", "opts": ["スケールの付着防止", "腐食の抑制", "硬度成分の処理", "ボイラー水の適切な管理", "燃料中の硫黄分を燃焼前に完全除去することだけ"], "ans": 4, "exp": "清缶剤はボイラー水側の障害防止に使われ、燃料硫黄分の完全除去だけを目的とするものではない。"},
  {"id": 20220421, "year": 202204, "num": 21, "field": "fuel", "text": "燃料の真発熱量に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料の水素分とは関係しない。", "高発熱量より常に大きい。", "水蒸気の凝縮潜熱を含めない発熱量として扱われる。", "水面計の長さで決まる。", "煙突の高さだけで決まる。"], "ans": 2, "exp": "真発熱量は低発熱量とも呼ばれ、水蒸気の凝縮潜熱を含めない。"},
  {"id": 20220422, "year": 202204, "num": 22, "field": "fuel", "text": "燃料の着火温度に関する記述として、適切なものは次のうちどれか。", "opts": ["水が沸騰する温度である。", "小火炎で瞬間的に燃え始める最低温度である。", "外部から点火しなくても自然に燃え始める最低温度である。", "燃料の灰分量である。", "空気比と同じ意味である。"], "ans": 2, "exp": "自然に燃え始める温度は着火温度で、引火点とは異なる。"},
  {"id": 20220423, "year": 202204, "num": 23, "field": "fuel", "text": "燃料中の水分に関する記述として、適切でないものは次のうちどれか。", "opts": ["燃焼に必要な熱を奪うことがある。", "発熱量に影響する。", "燃焼状態に影響することがある。", "多いほど常に発熱量が大きくなる。", "燃料管理上注意が必要である。"], "ans": 3, "exp": "水分が多いと発熱量の低下や燃焼不良につながる。"},
  {"id": 20220424, "year": 202204, "num": 24, "field": "fuel", "text": "重油の加熱に関する記述として、適切なものは次のうちどれか。", "opts": ["ベーパロックとは無関係である。", "軽油でも必ず高温加熱が必要である。", "加熱温度は高いほど無制限に良い。", "粘度を下げ、噴霧を良くするために行うことがある。", "加熱は燃料中の硫黄を完全に消す。"], "ans": 3, "exp": "重油は粘度を下げて噴霧を良くするため加熱することがあるが、過熱には注意が必要である。"},
  {"id": 20220425, "year": 202204, "num": 25, "field": "fuel", "text": "重油タンクの油取出し管に関する記述として、適切なものは次のうちどれか。", "opts": ["煙突の上端に取り付ける。", "必ずタンク底面ぴったりに取り付ける。", "タンク底部の水分やスラッジを吸い込みにくい位置に設ける。", "水面計の代わりに用いる。", "ボイラー室の出入口に設ける。"], "ans": 2, "exp": "油取出し管は水分やスラッジを吸い込みにくいよう底部から少し上に設ける。"},
  {"id": 20220426, "year": 202204, "num": 26, "field": "fuel", "text": "燃料油のサービスタンクに関する記述として、適切なものは次のうちどれか。", "opts": ["バーナ近くへ安定して燃料を供給するために用いられる。", "ボイラー水の硬度を下げる装置である。", "燃焼ガス中のNOxを測る計器である。", "安全弁の吹出し管である。", "水面計のガラス管である。"], "ans": 0, "exp": "サービスタンクはバーナへ燃料を安定供給するために用いられる。"},
  {"id": 20220427, "year": 202204, "num": 27, "field": "fuel", "text": "蒸気噴霧式バーナに関する記述として、適切なものは次のうちどれか。", "opts": ["ボイラー室の壁材料である。", "燃料を霧化しない。", "水面計の一種である。", "安全弁のばねである。", "蒸気を霧化媒体として油を微粒化する。"], "ans": 4, "exp": "蒸気噴霧式バーナでは、蒸気を用いて油を微粒化する。"},
  {"id": 20220428, "year": 202204, "num": 28, "field": "fuel", "text": "油バーナのターンダウン比に関する記述として、適切なものは次のうちどれか。", "opts": ["水面計の長さを示す値である。", "燃料中の水分量を示す値である。", "煙突内の自然通風力を示す値である。", "最大燃焼量と最小燃焼量の調節範囲を示す指標である。", "ボイラー検査証の有効期間である。"], "ans": 3, "exp": "ターンダウン比は燃焼量調節範囲を示す。"},
  {"id": 20220429, "year": 202204, "num": 29, "field": "fuel", "text": "油バーナの噴霧不良の影響として、適切なものは次のうちどれか。", "opts": ["圧力計が不要になる。", "必ず燃焼効率が100%になる。", "NOxが完全にゼロになる。", "水位が自動的に上がる。", "燃焼不良やすすの発生につながる。"], "ans": 4, "exp": "噴霧不良は燃焼不良、すす、未燃分の原因となる。"},
  {"id": 20220430, "year": 202204, "num": 30, "field": "fuel", "text": "都市ガスなどの気体燃料に関する記述として、適切でないものは次のうちどれか。", "opts": ["配管からの漏えいに注意する。", "漏えいしても爆発のおそれは全くない。", "加熱や霧化媒体が不要な場合が多い。", "点火前の換気が重要である。", "燃焼用空気との混合が重要である。"], "ans": 1, "exp": "気体燃料は漏えい時に爆発・火災の危険がある。"},
  {"id": 20220431, "year": 202204, "num": 31, "field": "law", "text": "伝熱面積の算定に関する記述として、適切でないものは次のうちどれか。", "opts": ["ボイラーの種類により算定方法が異なる。", "水管や煙管のどちら側で算定するかが問われる。", "すべての面積を無条件に二重算入する。", "法令上の区分に関係する。", "過熱器やエコノマイザの扱いが問われることがある。"], "ans": 2, "exp": "伝熱面積は法令上の算定方法に従い、無条件に二重算入しない。"},
  {"id": 20220432, "year": 202204, "num": 32, "field": "law", "text": "炉筒煙管ボイラーの伝熱面積に関する問題で問われやすいものは次のうちどれか。", "opts": ["作業者の年齢", "燃料販売店の名称", "煙管の内径側など、算定面の扱い", "ボイラー室の床色", "煙突の塗装色"], "ans": 2, "exp": "炉筒煙管ボイラーでは煙管などの伝熱面積算定方法が問われる。"},
  {"id": 20220433, "year": 202204, "num": 33, "field": "law", "text": "小型ボイラーを除く鋳鉄製温水ボイラーで問われやすい事項は次のうちどれか。", "opts": ["燃料の総発熱量だけ", "附属品や取扱資格の範囲", "空気比だけ", "バーナのターンダウン比だけ", "スートブロー蒸気の乾き度だけ"], "ans": 1, "exp": "鋳鉄製温水ボイラーでは附属品や取扱資格などが問われやすい。"},
  {"id": 20220434, "year": 202204, "num": 34, "field": "law", "text": "ボイラー室の構造に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料を室内に無制限に散布する。", "出入口を完全にふさいで運転する。", "換気を一切行わない。", "点検や取扱いに必要な空間を確保する。", "安全表示をすべて隠す。"], "ans": 3, "exp": "ボイラー室は安全な取扱い、点検、換気を考慮する必要がある。"},
  {"id": 20220435, "year": 202204, "num": 35, "field": "law", "text": "ボイラー設置届に関する記述として、適切なものは次のうちどれか。", "opts": ["安全弁のばね材料である。", "どのボイラーにも届出は絶対に不要である。", "燃料販売店だけが任意で作成する広告である。", "水面計の吹出し操作名である。", "一定のボイラーの設置では、所定の届出が必要となる。"], "ans": 4, "exp": "ボイラーの種類・規模により、設置届が必要となる場合がある。"},
  {"id": 20220436, "year": 202204, "num": 36, "field": "law", "text": "ボイラー及び配管の配置に関する法令問題で問われやすい事項は次のうちどれか。", "opts": ["煙突の色", "燃料販売価格", "作業者の通勤時間", "外壁や構造物との距離", "水の比熱"], "ans": 3, "exp": "本体外壁から構造物までの距離など、配置基準が問われる。"},
  {"id": 20220437, "year": 202204, "num": 37, "field": "law", "text": "使用検査に関する記述として、適切なものは次のうちどれか。", "opts": ["水面計の長さを測るだけである。", "燃料の色を確認するだけの検査である。", "使用を廃止したボイラーを再び設置する場合などに関係する。", "ボイラー検査証とは無関係である。", "作業主任者が任意に省略できる。"], "ans": 2, "exp": "使用検査は、再設置などの手続で問われる。"},
  {"id": 20220438, "year": 202204, "num": 38, "field": "law", "text": "構造検査に関する記述として、適切なものは次のうちどれか。", "opts": ["安全弁を使わないための検査である。", "燃料中の水分だけを測る検査である。", "ボイラー室の照明色だけを決める検査である。", "製造又は輸入等の段階で構造の適合を確認する検査として問われる。", "検査証とは全く関係しない広告である。"], "ans": 3, "exp": "構造検査はボイラーの構造に関する検査である。"},
  {"id": 20220439, "year": 202204, "num": 39, "field": "law", "text": "ボイラー検査証の有効期間に関する記述として、適切でないものは次のうちどれか。", "opts": ["原則として有効期間が定められる。", "性能検査により更新される。", "検査結果により期間が定められることがある。", "運転継続には有効期間の管理が必要である。", "一度交付されると法令上永久に更新不要である。"], "ans": 4, "exp": "ボイラー検査証には有効期間があり、更新管理が必要である。"},
  {"id": 20220440, "year": 202204, "num": 40, "field": "law", "text": "作業主任者の掲示に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料の発熱量だけを掲示する。", "掲示は常に禁止されている。", "資格及び氏名などを見やすい箇所に掲示することが問われる。", "水面計のメーカー名だけを掲示する。", "作業主任者の趣味を掲示する。"], "ans": 2, "exp": "作業主任者の資格・氏名などの掲示は法令問題で問われる。"},
  {"id": 20230401, "year": 202304, "num": 1, "field": "structure", "text": "二色水面計に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料の硫黄分を色で測定する方式である。", "水部と蒸気部を色の違いで見分ける方式である。", "圧力計の一種である。", "給水ポンプの形式である。", "通風力を測るU字管である。"], "ans": 1, "exp": "二色水面計は、光の性質を利用して水部と蒸気部を判別しやすくする水面計である。"},
  {"id": 20230402, "year": 202304, "num": 2, "field": "structure", "text": "ブルドン管圧力計の取扱いとして、適切なものは次のうちどれか。", "opts": ["高温蒸気が直接入らないようサイホン管などを用いる。", "蒸気を直接ブルドン管へ常に流し込む。", "水面計の代わりに水位を測る。", "燃料油を霧化する。", "ボイラー水の硬度を下げる。"], "ans": 0, "exp": "圧力計保護のため、サイホン管などで蒸気が直接入るのを防ぐ。"},
  {"id": 20230403, "year": 202304, "num": 3, "field": "structure", "text": "水高計に関する記述として、適切なものは次のうちどれか。", "opts": ["ボイラー水の硬度を除去する装置である。", "蒸気の乾き度を測定する計器である。", "燃料の引火点を測る計器である。", "煙突の高さを自動調整する装置である。", "温水ボイラーの圧力又は水頭を示す計器として扱われる。"], "ans": 4, "exp": "水高計は温水ボイラーの圧力状態を把握するために用いられる。"},
  {"id": 20230404, "year": 202304, "num": 4, "field": "structure", "text": "給水内管に関する記述として、適切なものは次のうちどれか。", "opts": ["煙道ガスを排出する煙突である。", "燃料を霧化するためのノズルである。", "給水をボイラー内に分配するため、多数の穴を設けるものがある。", "安全弁のばねである。", "通風計の液柱である。"], "ans": 2, "exp": "給水内管は給水を胴又はドラム内に分配するために設けられる。"},
  {"id": 20230405, "year": 202304, "num": 5, "field": "structure", "text": "給水逆止め弁に関する記述として、適切でないものは次のうちどれか。", "opts": ["ボイラー水の逆流を防止する。", "給水管に設けられる。", "燃焼ガス中のNOxを除去する薬剤である。", "逆流防止に関係する。", "給水弁と組み合わせて設けられることがある。"], "ans": 2, "exp": "給水逆止め弁は逆流防止の弁であり、NOx除去薬剤ではない。"},
  {"id": 20230406, "year": 202304, "num": 6, "field": "structure", "text": "エコノマイザの取扱いで注意する事項として、適切なものは次のうちどれか。", "opts": ["燃料タンクの水分を測定する。", "水面計を不要にするために設ける。", "安全弁の吹出し圧力を直接決める。", "給水の加熱により効率向上を図るが、低温腐食などにも注意する。", "蒸気トラップの代わりにドレンだけを排出する。"], "ans": 3, "exp": "エコノマイザは給水加熱に有効だが、排ガス温度低下による腐食にも注意が必要である。"},
  {"id": 20230407, "year": 202304, "num": 7, "field": "structure", "text": "オンオフ動作に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料の硫黄分を除去する方式である。", "偏差に比例して連続的に操作量だけを変える方式である。", "必ず手動操作だけで行う。", "水面計の色を変える方式である。", "制御対象の状態により燃焼と停止などを切り替える。"], "ans": 4, "exp": "オンオフ動作は、設定値を境に燃焼・停止などを切り替える制御である。"},
  {"id": 20230408, "year": 202304, "num": 8, "field": "structure", "text": "燃焼安全装置の構成機器として、適切なものは次のうちどれか。", "opts": ["作業主任者名簿", "水処理用食塩槽", "煙突の避雷針だけ", "火炎検出器", "燃料販売伝票"], "ans": 3, "exp": "火炎検出器は異常消火などを検出する燃焼安全装置の重要機器である。"},
  {"id": 20230409, "year": 202304, "num": 9, "field": "structure", "text": "蒸気圧力調節器に関する記述として、適切なものは次のうちどれか。", "opts": ["煙管内のすすだけを排出する装置である。", "給水中の硬度を除去する薬品である。", "蒸気圧力に応じて燃焼量を制御するために用いられる。", "ボイラー室の照明器具である。", "燃料の灰分を測る容器である。"], "ans": 2, "exp": "蒸気圧力調節器は蒸気圧力制御に用いられる。"},
  {"id": 20230410, "year": 202304, "num": 10, "field": "structure", "text": "水位検出器に関する記述として、適切でないものは次のうちどれか。", "opts": ["水位の異常を検出する。", "低水位時に燃焼停止などに関係する。", "水側・蒸気側連絡管の状態が重要である。", "複数方式を用いる場合がある。", "燃料の発熱量を直接高くする薬剤である。"], "ans": 4, "exp": "水位検出器は水位異常検出のための装置であり、燃料発熱量を変えるものではない。"},
  {"id": 20230411, "year": 202304, "num": 11, "field": "handling", "text": "プライミングに関する記述として、適切なものは次のうちどれか。", "opts": ["煙突内の自然通風力を測る単位である。", "燃料油を加熱する装置である。", "安全弁の設定圧力を下げる操作である。", "ボイラー水が激しく泡立ち、蒸気に水分が混入しやすくなる現象である。", "給水ポンプの羽根車形状である。"], "ans": 3, "exp": "プライミングは水分の蒸気への混入を招き、キャリオーバの原因となる。"},
  {"id": 20230412, "year": 202304, "num": 12, "field": "handling", "text": "フォーミングに関する記述として、適切なものは次のうちどれか。", "opts": ["圧力計の目盛盤の直径である。", "燃料中の灰分を測定する試験である。", "安全弁のばね材料である。", "煙道ガスを冷却する装置である。", "ボイラー水面に泡が発生し、水位確認や蒸気純度に影響する。"], "ans": 4, "exp": "フォーミングは泡立ちにより水位確認や蒸気純度に影響を与える。"},
  {"id": 20230413, "year": 202304, "num": 13, "field": "handling", "text": "スートブロー時の注意として、適切なものは次のうちどれか。", "opts": ["安全弁を取り外してから行う。", "燃焼停止直後に必ず水を噴射する。", "ドレンを多く含む蒸気を積極的に使う。", "ドレンを抜いた蒸気を用い、一箇所に長く吹き付けない。", "水面計を閉じたまま長時間行う。"], "ans": 3, "exp": "スートブローは乾いた蒸気を用い、損傷を避けるため一箇所への長時間吹付けを避ける。"},
  {"id": 20230414, "year": 202304, "num": 14, "field": "handling", "text": "乾燥保存法に関する記述として、適切なものは次のうちどれか。", "opts": ["ボイラー内部を乾燥状態に保ち、腐食を防ぐ保存法である。", "ボイラー内を水で満たす保存法である。", "運転中の水位調整法である。", "燃料油の引火点測定法である。", "安全弁の吹出し試験である。"], "ans": 0, "exp": "乾燥保存法は休止中の内部腐食を防ぐために乾燥状態を保つ。"},
  {"id": 20230415, "year": 202304, "num": 15, "field": "handling", "text": "長期休止中のボイラー管理として、適切でないものは次のうちどれか。", "opts": ["腐食防止を考慮する。", "保存法を休止期間に応じて選ぶ。", "内部状態を確認する。", "水や湿気の影響に注意する。", "休止中は腐食が絶対に起こらないので管理不要である。"], "ans": 4, "exp": "休止中も湿気や溶存酸素により腐食が起こるため管理が必要である。"},
  {"id": 20230416, "year": 202304, "num": 16, "field": "handling", "text": "酸洗浄作業で注意すべき事項として、適切なものは次のうちどれか。", "opts": ["薬品、発生ガス、腐食防止、後処理に注意する。", "抑制剤は常に不要である。", "水洗や中和は行ってはならない。", "火気管理は不要である。", "作業中の安全確認は不要である。"], "ans": 0, "exp": "酸洗浄では薬品管理、抑制剤、換気、火気管理、後処理が重要である。"},
  {"id": 20230417, "year": 202304, "num": 17, "field": "handling", "text": "燃料遮断弁に関する記述として、適切なものは次のうちどれか。", "opts": ["煙突の上部に取り付ける避雷針である。", "ボイラー水を軟化する薬品である。", "水面計のガラスである。", "異常時に燃料供給を遮断する。", "通風力を測るU字管である。"], "ans": 3, "exp": "燃料遮断弁は異常時に燃料供給を止める安全装置である。"},
  {"id": 20230418, "year": 202304, "num": 18, "field": "handling", "text": "燃焼安全装置が関係する異常として、適切でないものは次のうちどれか。", "opts": ["異常消火", "低水位", "ボイラー室の掲示文字が読みやすいこと", "燃料圧力異常", "送風量低下"], "ans": 2, "exp": "掲示文字の読みやすさは燃料遮断弁作動の異常原因ではない。"},
  {"id": 20230419, "year": 202304, "num": 19, "field": "handling", "text": "安全弁の調整試験として、適切でないものは次のうちどれか。", "opts": ["作動圧力を確認する。", "吹止まり圧力を確認する。", "作動しない場合は圧力を無制限に上げ続ける。", "調整後に再確認する。", "設定に応じて慎重に昇圧する。"], "ans": 2, "exp": "安全弁が作動しない場合に無制限に圧力を上げるのは危険である。"},
  {"id": 20230420, "year": 202304, "num": 20, "field": "handling", "text": "ボイラーの内面清掃の目的として、適切なものは次のうちどれか。", "opts": ["燃料タンクの容量を増やす。", "スケールやスラッジによる障害を防ぐ。", "煙突の高さを変える。", "作業主任者の資格を更新する。", "水面計の色を変えるだけである。"], "ans": 1, "exp": "内面清掃はスケールやスラッジによる過熱、腐食、効率低下を防ぐ目的で行う。"},
  {"id": 20230421, "year": 202304, "num": 21, "field": "fuel", "text": "予混合燃焼に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料と空気を絶対に接触させない。", "燃焼しながら初めて空気と混ざる方式だけをいう。", "燃焼前に燃料ガスと空気を混合する。", "水面計の吹出し方式である。", "重油タンクの水抜き方式である。"], "ans": 2, "exp": "予混合燃焼は燃焼前に燃料と空気を混合する。"},
  {"id": 20230422, "year": 202304, "num": 22, "field": "fuel", "text": "拡散燃焼に関する記述として、適切なものは次のうちどれか。", "opts": ["ボイラー検査証の更新手続である。", "燃料と空気を燃焼前に完全混合する方式だけをいう。", "水を電気分解する方式である。", "燃焼しながら燃料と空気が混合する。", "水面計の色を変える方式である。"], "ans": 3, "exp": "拡散燃焼は、燃焼しながら燃料と空気が混合する方式である。"},
  {"id": 20230423, "year": 202304, "num": 23, "field": "fuel", "text": "自然通風力に影響する要素として、適切なものは次のうちどれか。", "opts": ["燃料タンクの塗色だけ", "水面計の長さだけ", "安全弁の個数だけ", "煙突高さと内外ガス密度差", "作業主任者の人数だけ"], "ans": 3, "exp": "自然通風力は煙突高さと煙突内外のガス密度差に関係する。"},
  {"id": 20230424, "year": 202304, "num": 24, "field": "fuel", "text": "後向き形ファンに関する記述として、適切なものは次のうちどれか。", "opts": ["圧力計のサイホン管である。", "燃料油を加熱する装置である。", "給水を軟化する薬剤である。", "高温・大容量の用途で用いられることがある。", "安全弁の吹出し管である。"], "ans": 3, "exp": "後向き形ファンは効率が比較的高く、大容量用途で用いられる。"},
  {"id": 20230425, "year": 202304, "num": 25, "field": "fuel", "text": "ラジアル形ファンに関する記述として、適切なものは次のうちどれか。", "opts": ["ボイラー水を軟化する装置である。", "放射状の羽根を持ち、構造が比較的簡単である。", "燃料中の硫黄を化学的に除去する薬剤である。", "水面計のガラスである。", "検査証を更新する手続名である。"], "ans": 1, "exp": "ラジアル形ファンは放射状の羽根を持つ。"},
  {"id": 20230426, "year": 202304, "num": 26, "field": "fuel", "text": "押込通風に関する記述として、適切でないものは次のうちどれか。", "opts": ["燃焼ガスをファンで吸い出す方式だけをいう。", "常温空気を扱うことが多い。", "油だきボイラーで用いられることがある。", "燃焼用空気を炉内に押し込む。", "通風方式の一つである。"], "ans": 0, "exp": "燃焼ガスを吸い出す方式は誘引通風である。"},
  {"id": 20230427, "year": 202304, "num": 27, "field": "fuel", "text": "過剰空気が多すぎる場合の影響として、適切なものは次のうちどれか。", "opts": ["排ガス熱損失が必ずゼロになる。", "排ガス量が増え、熱損失が増加することがある。", "燃料消費が必ずゼロになる。", "燃焼室熱負荷が必ず消滅する。", "空気予熱器が不要になる。"], "ans": 1, "exp": "過剰空気が多すぎると排ガス量が増え、熱損失が増加する。"},
  {"id": 20230428, "year": 202304, "num": 28, "field": "fuel", "text": "低NOx燃焼の考え方として、適切なものは次のうちどれか。", "opts": ["炉内酸素濃度を常に最大にする。", "燃焼温度を無制限に上げる。", "局所高温域を抑える。", "燃料中の窒素を増やす。", "排ガス再循環を必ず禁止する。"], "ans": 2, "exp": "局所高温域の抑制はNOx低減に有効である。"},
  {"id": 20230429, "year": 202304, "num": 29, "field": "fuel", "text": "不完全燃焼に関する記述として、適切なものは次のうちどれか。", "opts": ["常に理想的な完全燃焼である。", "一酸化炭素やすすの発生につながることがある。", "空気不足とは無関係である。", "燃料は全く消費されない。", "排ガス成分に影響しない。"], "ans": 1, "exp": "不完全燃焼ではCOやすす、未燃分が発生することがある。"},
  {"id": 20230430, "year": 202304, "num": 30, "field": "fuel", "text": "燃焼室熱負荷が高すぎる場合に注意すべきこととして、適切なものは次のうちどれか。", "opts": ["燃料は燃えなくなる。", "安全管理は不要になる。", "水面計が不要になる。", "燃焼室や伝熱面の過熱、燃焼状態の悪化に注意する。", "排ガスは必ず常温になる。"], "ans": 3, "exp": "燃焼室熱負荷が過大だと、燃焼状態や炉内温度に悪影響を与える。"},
  {"id": 20230431, "year": 202304, "num": 31, "field": "law", "text": "二級ボイラー技士が作業主任者になれない場合として問われやすい観点は次のうちどれか。", "opts": ["煙突の塗装方法", "燃料販売店の所在地", "水の色", "作業者の靴の種類", "ボイラーの種類及び伝熱面積の範囲"], "ans": 4, "exp": "資格ごとに作業主任者として選任できる範囲が定められる。"},
  {"id": 20230432, "year": 202304, "num": 32, "field": "law", "text": "ボイラー取扱作業主任者の職務として、適切でないものは次のうちどれか。", "opts": ["圧力を監視する。", "水位を監視する。", "安全装置を常に無効化して運転する。", "急激な負荷変動を避けるよう努める。", "燃焼状態を監視する。"], "ans": 2, "exp": "安全装置を無効化することは職務として不適切である。"},
  {"id": 20230433, "year": 202304, "num": 33, "field": "law", "text": "安全弁の吹出し量に関する記述として、適切なものは次のうちどれか。", "opts": ["ボイラーの最大蒸発量に応じた能力が求められる。", "任意に小さくしてよい。", "水面計の長さだけで決まる。", "燃料タンクの色で決まる。", "作業主任者の年齢で決まる。"], "ans": 0, "exp": "安全弁にはボイラーの蒸発量に対応する吹出し能力が必要である。"},
  {"id": 20230434, "year": 202304, "num": 34, "field": "law", "text": "圧力計の目盛盤に関する記述として、適切なものは次のうちどれか。", "opts": ["検査証の番号だけを表示する。", "必ず圧力が読めないようにする。", "燃料の灰分量を表示する。", "水位だけを表示する。", "常用圧力や最高使用圧力との関係で適切な範囲が求められる。"], "ans": 4, "exp": "圧力計は常用圧力や最高使用圧力との関係で適切に選定・表示される。"},
  {"id": 20230435, "year": 202304, "num": 35, "field": "law", "text": "温水ボイラーの逃がし管に関する記述として、適切なものは次のうちどれか。", "opts": ["安全弁のばねを締める工具である。", "燃料油を霧化する。", "水の膨張分を逃がすために用いられる。", "煙突内の煤を測定する。", "作業主任者の氏名を掲示する。"], "ans": 2, "exp": "逃がし管は温水ボイラーの水の膨張分を逃がすために用いられる。"},
  {"id": 20230436, "year": 202304, "num": 36, "field": "law", "text": "定期自主検査の項目として、適切でないものは次のうちどれか。", "opts": ["ボイラー本体", "作業者の昼食内容", "自動制御装置", "附属装置及び附属品", "燃焼装置"], "ans": 1, "exp": "昼食内容は定期自主検査の項目ではない。"},
  {"id": 20230437, "year": 202304, "num": 37, "field": "law", "text": "変更届が問題となる部分として、適切なものは次のうちどれか。", "opts": ["過熱器", "作業者の筆記用具", "事務所の椅子", "燃料販売店の看板", "通勤経路"], "ans": 0, "exp": "過熱器など主要部分の変更は届出・検査の対象として問われる。"},
  {"id": 20230438, "year": 202304, "num": 38, "field": "law", "text": "定期自主検査の記録保存に関する記述として、適切なものは次のうちどれか。", "opts": ["検査結果を記録し、一定期間保存する。", "記録は作成してはならない。", "異常があっても記録しない。", "燃料販売店だけが口頭で覚えておく。", "記録は運転前に必ず破棄する。"], "ans": 0, "exp": "定期自主検査の結果は記録し、保存する必要がある。"},
  {"id": 20230439, "year": 202304, "num": 39, "field": "law", "text": "法令問題を解く際の着眼点として、適切なものは次のうちどれか。", "opts": ["燃料タンクの色だけで判断する。", "選択肢の文字数だけで判断する。", "ボイラーの種類、小型か否か、伝熱面積、用途を確認する。", "問題文の年度だけで正答を決める。", "すべてのボイラーに同じ規定が無条件に適用されると考える。"], "ans": 2, "exp": "法令問題では、ボイラー種別、伝熱面積、小型ボイラー除外などの条件確認が重要である。"},
  {"id": 20230440, "year": 202304, "num": 40, "field": "law", "text": "小型ボイラーを除く、という条件が付く問題で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["燃料の種類だけで正答を決める。", "小型ボイラーも必ず同一扱いと決めつける。", "条件は正答に影響しない。", "対象範囲が限定されているため、問題文の条件を確認する。", "設問文を読まなくてよい。"], "ans": 3, "exp": "法令問題では『小型ボイラーを除く』などの条件が正答に影響する。"},
  {"id": 20231001, "year": 202310, "num": 1, "field": "structure", "text": "乾き度に関する記述として、適切なものは次のうちどれか。", "opts": ["空気予熱器の伝熱面積を表す。", "燃料油中の硫黄分の割合を表す。", "湿り蒸気中の蒸気分の質量割合を表す。", "水面計の目盛間隔を表す。", "煙突の高さを表す。"], "ans": 2, "exp": "乾き度は湿り蒸気中に含まれる乾き飽和蒸気の質量割合である。"},
  {"id": 20231002, "year": 202310, "num": 2, "field": "structure", "text": "蒸気のエンタルピに関する記述として、適切なものは次のうちどれか。", "opts": ["安全弁のばね材質を示す。", "水面計のガラス厚さを示す。", "燃料タンクの直径だけを示す。", "蒸気が持つ熱エネルギーの評価に用いられる。", "煙突の塗装色を示す。"], "ans": 3, "exp": "蒸気のエンタルピは蒸気が持つ熱量の評価に用いられ、効率計算にも関係する。"},
  {"id": 20231003, "year": 202310, "num": 3, "field": "structure", "text": "水の顕熱に関する記述として、適切なものは次のうちどれか。", "opts": ["水を蒸発させるためだけの熱である。", "水の温度上昇に伴って蓄えられる熱である。", "燃料の灰分量である。", "安全弁の作動圧である。", "煙突内の通風力である。"], "ans": 1, "exp": "顕熱は物質の温度変化として現れる熱である。"},
  {"id": 20231004, "year": 202310, "num": 4, "field": "structure", "text": "水冷壁に関する記述として、適切なものは次のうちどれか。", "opts": ["圧力計の目盛盤である。", "燃料油を貯蔵する壁である。", "炉壁に水管を配置し、放射熱を吸収する構造である。", "水面計のコックである。", "煙突の外装材だけをいう。"], "ans": 2, "exp": "水冷壁は炉壁に水管を配置して放射熱を吸収する。"},
  {"id": 20231005, "year": 202310, "num": 5, "field": "structure", "text": "燃焼室に求められる条件として、適切でないものは次のうちどれか。", "opts": ["燃料と空気の混合を良くする。", "燃料を速やかに着火・燃焼させる。", "完全燃焼に必要な空間を確保する。", "燃料と空気を絶対に接触させない。", "発生熱を伝熱面へ有効に伝える。"], "ans": 3, "exp": "燃焼室では燃料と空気を適切に混合し、完全燃焼を図る。"},
  {"id": 20231006, "year": 202310, "num": 6, "field": "structure", "text": "下降管に関する記述として、適切なものは次のうちどれか。", "opts": ["圧力計のサイホン管である。", "燃焼ガスだけを排出する通路である。", "燃料油を噴霧するノズルである。", "比較的温度の低い水が下降する通路である。", "安全弁の吹出し管である。"], "ans": 3, "exp": "水管ボイラーでは上昇管と下降管を区別して水循環を行うものがある。"},
  {"id": 20231007, "year": 202310, "num": 7, "field": "structure", "text": "上昇管に関する記述として、適切なものは次のうちどれか。", "opts": ["水面計の照明である。", "燃料タンクの油取出し管である。", "煙突上部の避雷針である。", "気泡を含む水や蒸気水混合物が上昇する管である。", "安全弁のばねである。"], "ans": 3, "exp": "加熱されて気泡を含む水は密度が小さくなり上昇する。"},
  {"id": 20231008, "year": 202310, "num": 8, "field": "structure", "text": "波形炉筒に関する記述として、適切なものは次のうちどれか。", "opts": ["水面計の一種である。", "燃料を化学的に脱硫する装置である。", "熱膨張による応力を緩和し、強度上も有利な形状である。", "給水中の酸素を除去する薬剤である。", "煙突の通風力を測定する器具である。"], "ans": 2, "exp": "波形炉筒は熱膨張への追従性や強度面で利点がある。"},
  {"id": 20231009, "year": 202310, "num": 9, "field": "structure", "text": "貫流ボイラーの負荷変動に関する記述として、適切なものは次のうちどれか。", "opts": ["保有水量が非常に多く、制御は不要である。", "保有水量が少なく、負荷変動に対する制御が重要である。", "蒸気発生は燃料と無関係である。", "給水ポンプを持つことはない。", "水処理は常に不要である。"], "ans": 1, "exp": "貫流ボイラーは保有水量が少ないため、給水量・燃料量の制御が重要である。"},
  {"id": 20231010, "year": 202310, "num": 10, "field": "structure", "text": "鋳鉄製ボイラーのセクションに関する記述として、適切なものは次のうちどれか。", "opts": ["セクションは水の比熱の単位である。", "セクションは燃料油の種類名である。", "セクションは圧力計の目盛である。", "セクションは煙突の高さだけを示す。", "セクションを組み合わせて容量を構成するものがある。"], "ans": 4, "exp": "鋳鉄製ボイラーには、セクションを組み合わせる構造のものがある。"},
  {"id": 20231011, "year": 202310, "num": 11, "field": "handling", "text": "点火時の着火遅れに関する記述として、適切でないものは次のうちどれか。", "opts": ["未燃ガスの蓄積につながることがある。", "安全上問題にならないので放置してよい。", "点火前換気が重要である。", "燃料と空気の供給順序に注意する。", "逆火の原因となることがある。"], "ans": 1, "exp": "着火遅れは逆火や爆発の危険があり、放置してはならない。"},
  {"id": 20231012, "year": 202310, "num": 12, "field": "handling", "text": "昇圧中に空気抜き弁を閉じる時期として、適切なものは次のうちどれか。", "opts": ["水面計を外した後に閉じる。", "点火前に永久に閉じる。", "燃料タンクが空になった後に閉じる。", "蒸気の発生を確認し、空気が抜けた後に閉じる。", "安全弁を取り外した後に閉じる。"], "ans": 3, "exp": "たき始めでは空気を排出し、蒸気の発生を確認して空気抜き弁を閉じる。"},
  {"id": 20231013, "year": 202310, "num": 13, "field": "handling", "text": "燃焼中の監視事項として、適切でないものは次のうちどれか。", "opts": ["監視を一切行わないこと", "煙の状態", "圧力及び水位", "燃料供給状態", "火炎の状態"], "ans": 0, "exp": "燃焼中は火炎、煙、圧力、水位、燃料供給状態を監視する。"},
  {"id": 20231014, "year": 202310, "num": 14, "field": "handling", "text": "水柱管の連絡管に関する記述として、適切なものは次のうちどれか。", "opts": ["給水中の酸素を除去する薬剤である。", "燃料タンクの油面だけを示す。", "煙突高さを自動調整する。", "燃焼用空気を加熱する。", "途中の弁の開閉状態や閉塞に注意する。"], "ans": 4, "exp": "水柱管の連絡管は水位表示に関係し、閉塞や弁の状態に注意が必要である。"},
  {"id": 20231015, "year": 202310, "num": 15, "field": "handling", "text": "水面計の水位が左右で一致しない場合の対応として、適切なものは次のうちどれか。", "opts": ["低い方だけを常に信じる。", "機能試験や吹出しにより異常の有無を確認する。", "高い方だけを常に信じる。", "両方を見ずに運転する。", "水面計を叩いて破損させる。"], "ans": 1, "exp": "水面計の表示に差がある場合は、閉塞などを疑い機能確認を行う。"},
  {"id": 20231016, "year": 202310, "num": 16, "field": "handling", "text": "給水ポンプ運転中の確認事項として、適切なものは次のうちどれか。", "opts": ["空気抜きは絶対に不要である。", "振動や異音は確認しない。", "吐出圧力、流量、電流などが適正か確認する。", "吐出弁を常に閉めたまま長時間運転する。", "水がなくても運転し続ける。"], "ans": 2, "exp": "給水ポンプでは圧力、流量、電流、振動、漏れなどを確認する。"},
  {"id": 20231017, "year": 202310, "num": 17, "field": "handling", "text": "間欠吹出しの操作として、適切でないものは次のうちどれか。", "opts": ["水位を確認して行う。", "急激な水位低下に注意する。", "所定の手順で弁を操作する。", "水位を見ずに最大開度で長時間行う。", "スラッジ排出の目的で行うことがある。"], "ans": 3, "exp": "吹出しは水位や圧力に注意して所定手順で行う。"},
  {"id": 20231018, "year": 202310, "num": 18, "field": "handling", "text": "連続吹出しに関する記述として、適切なものは次のうちどれか。", "opts": ["煙突の自然通風力を測る操作である。", "安全弁の吹出し試験である。", "燃料油を噴霧する方式である。", "ボイラー水の濃縮を連続的に調整するために行う。", "水面計を破損させるための操作である。"], "ans": 3, "exp": "連続吹出しはボイラー水濃度の管理に用いられる。"},
  {"id": 20231019, "year": 202310, "num": 19, "field": "handling", "text": "ボイラー水中のスラッジに関する記述として、適切なものは次のうちどれか。", "opts": ["安全弁のばねの名称である。", "燃料中の気体成分だけをいう。", "水処理によって生じた沈殿物などで、吹出しにより排出する。", "煙突内の自然通風力である。", "圧力計の目盛である。"], "ans": 2, "exp": "スラッジはボイラー水中に生じる沈殿物で、吹出しで排出する。"},
  {"id": 20231020, "year": 202310, "num": 20, "field": "handling", "text": "キャリオーバの原因として、適切でないものは次のうちどれか。", "opts": ["高水位", "ボイラー水の濃縮", "負荷の急変", "プライミング", "適正水位で安定した水質管理"], "ans": 4, "exp": "適正水位・適正水質で安定運転している状態はキャリオーバの原因ではない。"},
  {"id": 20231021, "year": 202310, "num": 21, "field": "fuel", "text": "燃料の固定炭素に関する記述として、適切なものは次のうちどれか。", "opts": ["給水ポンプの段数である。", "水面計の水位を示す目盛である。", "安全弁のばね材料である。", "固体燃料の燃焼性に関係する成分である。", "ボイラー検査証の有効期間である。"], "ans": 3, "exp": "固定炭素は固体燃料の性質を示す成分で、燃焼性に関係する。"},
  {"id": 20231022, "year": 202310, "num": 22, "field": "fuel", "text": "燃料の揮発分に関する記述として、適切なものは次のうちどれか。", "opts": ["圧力計の目盛である。", "水の比熱そのものである。", "加熱により発生する可燃性ガス分に関係する。", "安全弁の吹出し管である。", "水面計のコックである。"], "ans": 2, "exp": "揮発分は燃料を加熱したときに発生する可燃性ガス分に関係する。"},
  {"id": 20231023, "year": 202310, "num": 23, "field": "fuel", "text": "A重油とC重油の比較として、一般に適切なものは次のうちどれか。", "opts": ["A重油は必ず固体燃料である。", "C重油は粘度が高く、加熱を必要とする場合が多い。", "C重油は水そのものである。", "A重油は燃焼しない。", "C重油は硫黄分を全く含まないことが法令上常に保証される。"], "ans": 1, "exp": "C重油は粘度が高く、加熱して噴霧性を改善することが多い。"},
  {"id": 20231024, "year": 202310, "num": 24, "field": "fuel", "text": "硫酸露点に関する記述として、適切なものは次のうちどれか。", "opts": ["ボイラー水のpHを示す。", "水が凍る温度だけをいう。", "燃料の引火点と同じ意味である。", "硫酸蒸気が凝縮し始める温度で、低温腐食に関係する。", "安全弁の吹出し圧力を示す。"], "ans": 3, "exp": "重油燃焼ではSO3と水分により硫酸露点が問題となる。"},
  {"id": 20231025, "year": 202310, "num": 25, "field": "fuel", "text": "重油添加剤の目的として、適切なものは次のうちどれか。", "opts": ["燃焼用空気を完全にゼロにするために用いる。", "水面計を不要にするためだけに用いる。", "安全弁の個数を減らすためだけに用いる。", "低温腐食や灰付着の抑制を目的に用いられることがある。", "ボイラー検査証を更新するために用いる。"], "ans": 3, "exp": "添加剤は低温腐食や灰付着などの障害抑制に使われることがある。"},
  {"id": 20231026, "year": 202310, "num": 26, "field": "fuel", "text": "燃料油の水分混入時に起こり得ることとして、適切なものは次のうちどれか。", "opts": ["安全弁が不要になる。", "燃焼効率が必ず100%になる。", "NOxが必ずゼロになる。", "ボイラー水が自動で軟化される。", "燃焼不良やバーナの不調につながる。"], "ans": 4, "exp": "燃料油への水分混入は燃焼不良や供給障害の原因となる。"},
  {"id": 20231027, "year": 202310, "num": 27, "field": "fuel", "text": "バーナの霧化に関する記述として、適切なものは次のうちどれか。", "opts": ["安全弁の作動圧を下げる。", "燃料を大きな塊のまま落下させる。", "水面計の水位を測る。", "燃料を微粒化し、空気との混合を良くする。", "ボイラー検査証を発行する。"], "ans": 3, "exp": "霧化は燃料を微粒化して燃焼しやすくする操作である。"},
  {"id": 20231028, "year": 202310, "num": 28, "field": "fuel", "text": "蒸気噴霧式バーナの短所として、適切なものは次のうちどれか。", "opts": ["安全弁を不要にする。", "燃料を全く霧化できない。", "空気を全く必要としない。", "霧化用蒸気を消費する。", "水質管理を不要にする。"], "ans": 3, "exp": "蒸気噴霧式は霧化用蒸気を消費する点に注意が必要である。"},
  {"id": 20231029, "year": 202310, "num": 29, "field": "fuel", "text": "油バーナのノズル詰まりの影響として、適切なものは次のうちどれか。", "opts": ["蒸気圧力が常に一定になる。", "ボイラー水の硬度が下がる。", "噴霧状態が悪化し、燃焼不良につながる。", "排ガス熱損失が必ずゼロになる。", "安全弁が不要になる。"], "ans": 2, "exp": "ノズル詰まりは噴霧不良や燃焼不良の原因となる。"},
  {"id": 20231030, "year": 202310, "num": 30, "field": "fuel", "text": "ガスバーナの火炎安定に関する記述として、適切なものは次のうちどれか。", "opts": ["漏えい検知は不要である。", "ガス圧は火炎に関係しない。", "空気量は火炎に関係しない。", "火炎検出器は常に不要である。", "燃料ガス圧力や空気量の管理が重要である。"], "ans": 4, "exp": "ガス燃焼ではガス圧、空気量、火炎検出が重要である。"},
  {"id": 20231031, "year": 202310, "num": 31, "field": "law", "text": "伝熱面積の算入対象に関する問題で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["作業者の人数で決める。", "すべての面を無条件に算入する。", "燃料の種類だけで決める。", "ボイラー種別と部位ごとの規定を確認する。", "煙突の色で決める。"], "ans": 3, "exp": "伝熱面積は種類と部位ごとの算定方法を確認する必要がある。"},
  {"id": 20231032, "year": 202310, "num": 32, "field": "law", "text": "エコノマイザの伝熱面に関する法令問題で問われやすいことは次のうちどれか。", "opts": ["作業者の年齢", "燃料販売価格", "伝熱面積に算入するかどうか", "水の色", "煙突の塗色"], "ans": 2, "exp": "エコノマイザの伝熱面の扱いは伝熱面積問題で頻出である。"},
  {"id": 20231033, "year": 202310, "num": 33, "field": "law", "text": "過熱器に関する法令問題で問われやすいことは次のうちどれか。", "opts": ["水面計の照明色", "作業者の通勤手段", "燃料販売店の広告", "伝熱面積や変更検査、附属品の扱い", "煙突の塗装方法"], "ans": 3, "exp": "過熱器は伝熱面積、変更検査、附属品などで出題されやすい。"},
  {"id": 20231034, "year": 202310, "num": 34, "field": "law", "text": "ボイラー室の出入口に関する記述として、適切なものは次のうちどれか。", "opts": ["出入口は法令問題で全く扱われない。", "常に施錠して出入りできないようにする。", "燃料を積み上げてふさぐ。", "非常時の避難や取扱いに支障がないようにする。", "水面計の代わりに用いる。"], "ans": 3, "exp": "ボイラー室では出入口や避難の確保が重要である。"},
  {"id": 20231035, "year": 202310, "num": 35, "field": "law", "text": "ボイラー室内の可燃物管理として、適切なものは次のうちどれか。", "opts": ["油を床一面に散布する。", "可燃物を炉前に大量に積む。", "避難経路をふさぐ。", "燃料や可燃物の置き方に注意し、火災防止を図る。", "火気管理を行わない。"], "ans": 3, "exp": "ボイラー室では火災防止のため可燃物や燃料の管理が重要である。"},
  {"id": 20231036, "year": 202310, "num": 36, "field": "law", "text": "設置手続の順序問題で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["選択肢の長さだけで答える。", "検査名はすべて同じ意味と考える。", "問題文の条件を読まない。", "年度だけで答える。", "設置届、使用検査、落成検査などの検査名を区別する。"], "ans": 4, "exp": "法令問題では検査の種類と手続順を区別する。"},
  {"id": 20231037, "year": 202310, "num": 37, "field": "law", "text": "性能検査の結果により起こり得ることとして、適切なものは次のうちどれか。", "opts": ["水面計が不要になる。", "燃料の発熱量が必ず上がる。", "検査証の有効期間が定められて更新される。", "作業主任者資格が自動で上位になる。", "安全弁が不要になる。"], "ans": 2, "exp": "性能検査の結果により検査証の有効期間が更新される。"},
  {"id": 20231038, "year": 202310, "num": 38, "field": "law", "text": "変更検査を受ける場合として問われやすいものは次のうちどれか。", "opts": ["休憩室の椅子交換", "作業者の筆記具変更", "胴、ドラム、過熱器など主要部分の変更", "作業靴の色変更", "燃料販売店の電話番号変更"], "ans": 2, "exp": "主要部分の変更は変更検査の対象として問われる。"},
  {"id": 20231039, "year": 202310, "num": 39, "field": "law", "text": "ボイラー検査証の備付けに関する記述として、適切なものは次のうちどれか。", "opts": ["検査証は破棄してよい。", "使用するボイラーについて検査証を適切に備え付ける。", "検査証は燃料タンクに入れて燃やす。", "検査証は作業主任者の私物として持ち帰る。", "検査証は法令上存在しない。"], "ans": 1, "exp": "ボイラー検査証は適切に備え付け、管理する必要がある。"},
  {"id": 20231040, "year": 202310, "num": 40, "field": "law", "text": "ボイラー取扱技能講習修了者が扱える範囲に関する問題で注意すべきことは次のうちどれか。", "opts": ["水面計の数だけで決まる。", "どのボイラーでも無制限に扱える。", "法令上の区分は存在しない。", "燃料が重油なら全て同じ扱いである。", "ボイラーの種類や伝熱面積などの条件を確認する。"], "ans": 4, "exp": "取扱資格はボイラーの種類や規模によって範囲が異なる。"},
  {"id": 20240401, "year": 202404, "num": 1, "field": "structure", "text": "気水分離器に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料油を加熱する装置である。", "蒸気と水滴を分離するために用いられる。", "水の硬度を下げる薬剤である。", "通風力を測る計器である。", "安全弁のばねを締める工具である。"], "ans": 1, "exp": "気水分離器は、蒸気中の水滴を分離し、蒸気の乾き度向上に役立つ。"},
  {"id": 20240402, "year": 202404, "num": 2, "field": "structure", "text": "減圧弁に関する記述として、適切なものは次のうちどれか。", "opts": ["蒸気の使用圧力を所定の低い圧力に保つために用いられる。", "ボイラー水を軟化する装置である。", "燃料を微粒化する装置である。", "水面計のガラス管である。", "煙突内のすすを除去する装置である。"], "ans": 0, "exp": "減圧弁は、使用箇所に適した蒸気圧力に下げて保つために用いる。"},
  {"id": 20240403, "year": 202404, "num": 3, "field": "structure", "text": "主蒸気弁に関する記述として、適切なものは次のうちどれか。", "opts": ["給水を軟化する薬品である。", "燃料中の水分を測る計器である。", "ボイラーから蒸気を送り出す主配管に設けられる。", "空気比を直接表示する装置である。", "安全弁の代わりに過圧を逃がす唯一の装置である。"], "ans": 2, "exp": "主蒸気弁はボイラーから蒸気を送り出す主蒸気管に設けられる。"},
  {"id": 20240404, "year": 202404, "num": 4, "field": "structure", "text": "ディフューザポンプに関する記述として、適切なものは次のうちどれか。", "opts": ["煙突の内面に取り付ける保温材である。", "蒸気の噴射力だけで給水する装置である。", "水面計の一種である。", "燃料中の硫黄を除去する薬剤である。", "羽根車の周辺に案内羽根を持つ遠心ポンプである。"], "ans": 4, "exp": "ディフューザポンプは案内羽根を備えた遠心ポンプである。"},
  {"id": 20240405, "year": 202404, "num": 5, "field": "structure", "text": "インゼクタに関する記述として、適切なものは次のうちどれか。", "opts": ["水面計のガラス管である。", "電動機で羽根車を回す渦巻ポンプである。", "燃料油を加熱する装置である。", "煙道ガスを測定する計器である。", "蒸気の噴射力を利用して給水する装置である。"], "ans": 4, "exp": "インゼクタは蒸気の噴射力を利用する給水装置である。"},
  {"id": 20240406, "year": 202404, "num": 6, "field": "structure", "text": "比例動作に関する記述として、適切なものは次のうちどれか。", "opts": ["偏差があっても操作量を全く変えない。", "偏差の大きさに比例して操作量を変える。", "常に燃焼停止だけを行う。", "水面計の色を変える。", "燃料の灰分量を測定する。"], "ans": 1, "exp": "比例動作では偏差の大きさに応じて操作量を変える。"},
  {"id": 20240407, "year": 202404, "num": 7, "field": "structure", "text": "積分動作に関する記述として、適切なものは次のうちどれか。", "opts": ["必ず手動でしか行えない。", "偏差の変化速度だけに応じて操作する。", "偏差の時間積分に応じて操作量を変える。", "燃料の発熱量を直接増やす。", "水面計の閉塞を物理的に除去する。"], "ans": 2, "exp": "積分動作は偏差の累積に応じて操作量を変える。"},
  {"id": 20240408, "year": 202404, "num": 8, "field": "structure", "text": "微分動作に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料中の灰分を測定する。", "偏差の累積だけで操作する。", "水の硬度を除去する。", "偏差の変化速度に応じて操作量を変える。", "安全弁の吹出し量を増やす薬剤である。"], "ans": 3, "exp": "微分動作は偏差の変化速度に応じて操作量を変える。"},
  {"id": 20240409, "year": 202404, "num": 9, "field": "structure", "text": "火炎検出器に関する記述として、適切でないものは次のうちどれか。", "opts": ["火炎の有無を検出する。", "燃焼安全装置に関係する。", "ボイラー水の硬度を下げる薬剤である。", "燃焼監視に用いられる。", "異常消火時の燃料遮断に関係する。"], "ans": 2, "exp": "火炎検出器は火炎を検出する機器であり、水処理薬剤ではない。"},
  {"id": 20240410, "year": 202404, "num": 10, "field": "structure", "text": "圧力計のサイホン管に関する記述として、適切なものは次のうちどれか。", "opts": ["煙突の通風力を発生させる装置である。", "燃料油を霧化するために用いられる。", "給水を軟化するための装置である。", "蒸気の直接接触による圧力計の過熱を防ぐために用いられる。", "水面計のガラスを洗浄する薬剤である。"], "ans": 3, "exp": "圧力計のサイホン管は、水をたまりとして蒸気の熱が圧力計へ直接伝わるのを抑える。"},
  {"id": 20240411, "year": 202404, "num": 11, "field": "handling", "text": "スートブローの効果確認として、適切なものは次のうちどれか。", "opts": ["排ガス温度や通風損失の変化を見る。", "作業者の靴の色を見る。", "燃料販売店の所在地を見る。", "安全弁の塗色だけを見る。", "水面計を取り外す。"], "ans": 0, "exp": "スートブロー後は排ガス温度や通風損失の変化から効果を確認することがある。"},
  {"id": 20240412, "year": 202404, "num": 12, "field": "handling", "text": "停止後の排水に関する記述として、適切なものは次のうちどれか。", "opts": ["燃焼中に胴を空にする。", "高温高圧のまま急いで全量排水する。", "圧力を確認せずマンホールを開ける。", "ボイラー水温度が下がってから排水する。", "水位計を見ずに作業する。"], "ans": 3, "exp": "排水は温度や圧力が安全な状態になってから行う。"},
  {"id": 20240413, "year": 202404, "num": 13, "field": "handling", "text": "満水保存法で注意する事項として、適切なものは次のうちどれか。", "opts": ["ボイラー内を乾燥剤だけで満たす。", "空気を多量に入れて腐食を促進する。", "水中の溶存酸素を少なくし、腐食防止を図る。", "燃料油を満たす。", "安全弁を取り外して開放する。"], "ans": 2, "exp": "満水保存法では、酸素を少なくした水で満たして腐食を抑える。"},
  {"id": 20240414, "year": 202404, "num": 14, "field": "handling", "text": "乾燥保存法で用いられるものとして、適切なものは次のうちどれか。", "opts": ["排ガスだけ", "重油だけ", "燃焼用空気だけ", "乾燥剤", "蒸気トラップだけ"], "ans": 3, "exp": "乾燥保存では乾燥剤を用いて湿気を防ぐことがある。"},
  {"id": 20240415, "year": 202404, "num": 15, "field": "handling", "text": "火炎検出器の汚れや故障による影響として、適切なものは次のうちどれか。", "opts": ["水面計が不要になる。", "ボイラー水の硬度が必ず下がる。", "排ガス中の酸素がゼロになる。", "燃料の硫黄分がなくなる。", "火炎検出が不安定になり、燃焼安全装置の作動に影響する。"], "ans": 4, "exp": "火炎検出器の異常は、異常消火検出や燃料遮断に影響する。"},
  {"id": 20240416, "year": 202404, "num": 16, "field": "handling", "text": "燃料遮断弁の漏れ確認として、適切なものは次のうちどれか。", "opts": ["煙突の高さだけを測る。", "水面計の水位だけを見る。", "閉止時に燃料が漏れていないか確認する。", "給水中の硬度だけを測る。", "ボイラー室の床色を確認する。"], "ans": 2, "exp": "燃料遮断弁は閉止時に漏れがないことが重要である。"},
  {"id": 20240417, "year": 202404, "num": 17, "field": "handling", "text": "異常消火時の対応として、適切なものは次のうちどれか。", "opts": ["安全装置を取り外す。", "燃料をさらに多く供給する。", "換気せず直ちに再点火する。", "火炎検出器を無効化する。", "燃料供給を遮断し、原因を確認してから再点火する。"], "ans": 4, "exp": "異常消火時は燃料遮断、換気、原因確認を行い、安全に再点火する。"},
  {"id": 20240418, "year": 202404, "num": 18, "field": "handling", "text": "ボイラー内面腐食の防止として、適切なものは次のうちどれか。", "opts": ["酸素を多く溶かす。", "水質を全く管理しない。", "溶存酸素を少なくし、適切なpH管理を行う。", "スケールを厚く付着させる。", "腐食を確認しても放置する。"], "ans": 2, "exp": "腐食防止には脱酸素、pH、濃度管理などが重要である。"},
  {"id": 20240419, "year": 202404, "num": 19, "field": "handling", "text": "過熱による損傷防止として、適切なものは次のうちどれか。", "opts": ["伝熱面をすすで覆う。", "水位を常に安全低水面以下にする。", "水質管理を行わない。", "燃焼量を無制限に上げる。", "スケール付着や低水位を防止する。"], "ans": 4, "exp": "スケールや低水位は伝熱面過熱の原因となるため防止が必要である。"},
  {"id": 20240420, "year": 202404, "num": 20, "field": "handling", "text": "低水位を認めた場合の基本対応として、適切なものは次のうちどれか。", "opts": ["直ちに燃焼量を最大にする。", "燃焼を停止し、原因と水位を確認して安全を確かめる。", "水面計を見ないで運転を続ける。", "安全弁を固定して圧力を上げる。", "低水位警報を無効にする。"], "ans": 1, "exp": "低水位は伝熱面過熱や重大事故につながるため、燃焼停止と原因確認を基本とする。"},
  {"id": 20240421, "year": 202404, "num": 21, "field": "fuel", "text": "ガス燃料の長所として、適切なものは次のうちどれか。", "opts": ["燃焼制御が比較的容易で、燃料加熱や霧化媒体が不要な場合が多い。", "漏えい時にも危険が全くない。", "空気と混合できない。", "燃焼しない。", "必ず大量の灰を発生する。"], "ans": 0, "exp": "ガス燃料は制御しやすいが、漏えい時の安全管理が重要である。"},
  {"id": 20240422, "year": 202404, "num": 22, "field": "fuel", "text": "ガス燃料の漏えい対策として、適切でないものは次のうちどれか。", "opts": ["換気を行う。", "漏えい検知を行う。", "配管接続部を点検する。", "点火前に安全確認する。", "臭気や警報を無視して直ちに点火する。"], "ans": 4, "exp": "漏えいが疑われる場合に点火するのは危険である。"},
  {"id": 20240423, "year": 202404, "num": 23, "field": "fuel", "text": "押込ファンの取扱いとして、適切なものは次のうちどれか。", "opts": ["給水中の硬度を除去する。", "燃焼用空気量を適切に調整する。", "燃料中の硫黄を完全に除去する。", "安全弁の設定圧力を決める。", "水面計の水位を直接表示する。"], "ans": 1, "exp": "押込ファンは燃焼用空気を供給するため、空気量管理が重要である。"},
  {"id": 20240424, "year": 202404, "num": 24, "field": "fuel", "text": "誘引ファンの取扱いとして、適切でないものは次のうちどれか。", "opts": ["燃焼ガスと無関係なので点検不要である。", "通風状態を確認する。", "すすやダストの影響を受けることがある。", "燃焼ガスを扱うため、高温や腐食・摩耗に注意する。", "通風抵抗に応じた能力が必要である。"], "ans": 0, "exp": "誘引ファンは燃焼ガスを扱うため点検が重要である。"},
  {"id": 20240425, "year": 202404, "num": 25, "field": "fuel", "text": "通風不足の影響として、適切なものは次のうちどれか。", "opts": ["水面計が不要になる。", "燃焼状態が必ず改善する。", "排ガス熱損失が必ずゼロになる。", "NOxが常にゼロになる。", "不完全燃焼や逆火の原因となることがある。"], "ans": 4, "exp": "通風不足は燃焼不良や逆火の原因となる。"},
  {"id": 20240426, "year": 202404, "num": 26, "field": "fuel", "text": "排ガス熱損失を小さくする方法として、適切なものは次のうちどれか。", "opts": ["過剰空気を適正に保ち、排ガス温度を管理する。", "空気比を無制限に大きくする。", "排ガス温度を無制限に高くする。", "燃焼を常に不完全にする。", "エコノマイザを必ず取り外す。"], "ans": 0, "exp": "適正空気比や排熱回収により排ガス熱損失を抑える。"},
  {"id": 20240427, "year": 202404, "num": 27, "field": "fuel", "text": "ばいじんの発生に関する記述として、適切なものは次のうちどれか。", "opts": ["燃焼不良や燃料性状により増加することがある。", "燃焼状態とは無関係である。", "燃料中の残留炭素分とは無関係である。", "常にゼロである。", "水面計で直接測定する。"], "ans": 0, "exp": "ばいじんは燃焼状態や燃料性状に影響される。"},
  {"id": 20240428, "year": 202404, "num": 28, "field": "fuel", "text": "SOxに関する記述として、適切なものは次のうちどれか。", "opts": ["燃料中の窒素だけに由来する。", "燃料中の硫黄分に由来する。", "水の比熱の単位である。", "安全弁の種類である。", "給水ポンプの形式である。"], "ans": 1, "exp": "SOxは主に燃料中の硫黄分の燃焼により発生する。"},
  {"id": 20240429, "year": 202404, "num": 29, "field": "fuel", "text": "燃焼ガス分析の目的として、適切なものは次のうちどれか。", "opts": ["燃焼状態や空気比の管理に利用する。", "ボイラー検査証を印刷する。", "水面計の長さを決める。", "安全弁のばね材料を決める。", "作業主任者の氏名を表示する。"], "ans": 0, "exp": "燃焼ガス中のO2、CO2、COなどは燃焼管理に利用される。"},
  {"id": 20240430, "year": 202404, "num": 30, "field": "fuel", "text": "COが排ガス中に多い場合に疑われるものとして、適切なものは次のうちどれか。", "opts": ["安全弁の正常作動", "完全燃焼の証拠", "給水の軟化完了", "不完全燃焼", "ボイラー検査証の更新"], "ans": 3, "exp": "COの増加は不完全燃焼を示す重要なサインである。"},
  {"id": 20240431, "year": 202404, "num": 31, "field": "law", "text": "作業主任者の選任に関する記述として、適切なものは次のうちどれか。", "opts": ["一定のボイラー取扱作業では資格者から選任する。", "誰でも無資格で必ず選任できる。", "燃料販売店が自動的に選任される。", "水面計のメーカーが選任される。", "検査証があれば作業主任者は絶対に不要である。"], "ans": 0, "exp": "一定のボイラー取扱作業では、法令に基づき作業主任者を選任する。"},
  {"id": 20240432, "year": 202404, "num": 32, "field": "law", "text": "作業主任者の職務として、適切なものは次のうちどれか。", "opts": ["安全弁を常に固定して作動しないようにする。", "安全弁の機能保持に注意する。", "水位を見ない。", "燃焼状態を見ない。", "負荷変動をわざと急激にする。"], "ans": 1, "exp": "作業主任者は安全弁の機能保持、圧力・水位・燃焼状態の監視などを行う。"},
  {"id": 20240433, "year": 202404, "num": 33, "field": "law", "text": "圧力計のコック又は弁に関する記述として、適切なものは次のうちどれか。", "opts": ["開閉状態が絶対に分からないようにする。", "開閉状態を容易に知ることができるようにする。", "常に溶接して動かないようにする。", "燃料油を噴霧するために用いる。", "水面計の水位を隠すために用いる。"], "ans": 1, "exp": "圧力計のコック又は弁は開閉状態が分かるようにする。"},
  {"id": 20240434, "year": 202404, "num": 34, "field": "law", "text": "水高計の目盛りに関する記述として、適切なものは次のうちどれか。", "opts": ["煙突高さを表示する。", "必ず目盛りを消す。", "燃料の発熱量だけを表示する。", "常用水位などを示す位置に表示が求められる場合がある。", "作業主任者の氏名だけを表示する。"], "ans": 3, "exp": "水高計や水面計では、常用水位などの表示が問われる。"},
  {"id": 20240435, "year": 202404, "num": 35, "field": "law", "text": "返り管に水道等の水源を取り付ける規定で問われやすいボイラーは次のうちどれか。", "opts": ["鋳鉄製ボイラー", "燃料タンク", "煙突", "送風機だけ", "圧力計だけ"], "ans": 0, "exp": "鋳鉄製ボイラーでは返り管と水源接続に関する規定が問われる。"},
  {"id": 20240436, "year": 202404, "num": 36, "field": "law", "text": "定期自主検査で燃焼装置について確認する事項として、適切なものは次のうちどれか。", "opts": ["煙突の色だけ", "作業者の昼食内容", "燃料販売店の所在地", "ボイラー室の壁紙の柄", "バーナやストレーナなどの異常の有無"], "ans": 4, "exp": "燃焼装置ではバーナ、ストレーナなどの状態を確認する。"},
  {"id": 20240437, "year": 202404, "num": 37, "field": "law", "text": "自動制御装置の定期自主検査として、適切なものは次のうちどれか。", "opts": ["作業者の私物を点検する。", "火炎検出器や電気配線の異常の有無を確認する。", "燃料販売契約を点検する。", "作業靴の色を点検する。", "昼食時間を点検する。"], "ans": 1, "exp": "自動制御装置では火炎検出器や電気配線などの異常を確認する。"},
  {"id": 20240438, "year": 202404, "num": 38, "field": "law", "text": "附属装置及び附属品の定期自主検査として、適切なものは次のうちどれか。", "opts": ["燃料販売店の広告を確認する。", "作業者の年齢を確認する。", "机の配置だけを確認する。", "水処理装置やスートブロワなどの異常の有無を確認する。", "通勤経路を確認する。"], "ans": 3, "exp": "附属装置及び附属品では、水処理装置やスートブロワなどの状態を確認する。"},
  {"id": 20240439, "year": 202404, "num": 39, "field": "law", "text": "法令問題で『移動式ボイラーを除く』とある場合の注意として、適切なものは次のうちどれか。", "opts": ["選択肢番号だけで判断する。", "移動式ボイラーだけを対象にする。", "条件を無視してよい。", "燃料だけで判断する。", "対象から移動式ボイラーが除外されている前提で読む。"], "ans": 4, "exp": "除外条件は正答に影響するため、問題文の条件を必ず確認する。"},
  {"id": 20240440, "year": 202404, "num": 40, "field": "law", "text": "法令問題で『小型ボイラーを除く』とある場合の注意として、適切なものは次のうちどれか。", "opts": ["必ず燃料の種類だけで判断する。", "全て小型ボイラーとして扱う。", "問題文の条件は無意味である。", "小型ボイラーに関する別扱いを混同しない。", "解答番号は常に1である。"], "ans": 3, "exp": "小型ボイラー除外の条件は、適用条文や正答に影響する。"},
  {"id": 20241001, "year": 202410, "num": 1, "field": "structure", "text": "飽和水に関する記述として、適切なものは次のうちどれか。", "opts": ["煙道内の凝縮水だけをいう。", "常に0度の水である。", "過熱蒸気だけをいう。", "燃料油中の水分をいう。", "その圧力で沸騰を始める温度に達した水である。"], "ans": 4, "exp": "飽和水は、与えられた圧力で沸騰温度に達した水をいう。"},
  {"id": 20241002, "year": 202410, "num": 2, "field": "structure", "text": "潜熱に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料の灰分だけをいう。", "圧力計のばねに蓄えられる機械的エネルギーである。", "水位計の照明熱だけをいう。", "状態変化に伴って出入りする熱である。", "煙突の高さで決まる風圧だけをいう。"], "ans": 3, "exp": "潜熱は、温度変化を伴わない状態変化に必要な熱である。"},
  {"id": 20241003, "year": 202410, "num": 3, "field": "structure", "text": "過熱蒸気に関する記述として、適切なものは次のうちどれか。", "opts": ["水処理薬剤の名称である。", "水滴を多量に含む湿り蒸気だけをいう。", "常に大気圧の蒸気だけをいう。", "燃料油を加熱した気体である。", "飽和温度より高い温度に加熱された蒸気である。"], "ans": 4, "exp": "過熱蒸気は、同じ圧力の飽和温度を超えて加熱された蒸気である。"},
  {"id": 20241004, "year": 202410, "num": 4, "field": "structure", "text": "炉筒煙管ボイラーの特徴として、適切なものは次のうちどれか。", "opts": ["水管だけで構成され胴を持たない。", "胴内に炉筒や煙管を設け、燃焼ガスを通して加熱する。", "燃料を貯蔵するためだけの容器である。", "水面計を備えることができない。", "蒸気を発生しない。"], "ans": 1, "exp": "炉筒煙管ボイラーは、炉筒や煙管を通る燃焼ガスで胴内の水を加熱する。"},
  {"id": 20241005, "year": 202410, "num": 5, "field": "structure", "text": "立てボイラーに関する記述として、適切なものは次のうちどれか。", "opts": ["給水ポンプの羽根車である。", "燃料を縦に積む貯蔵棚である。", "安全弁の一形式だけをいう。", "胴を縦に置く構造のボイラーである。", "煙突の基礎だけをいう。"], "ans": 3, "exp": "立てボイラーは胴を縦方向に配置した構造で、小容量用途で扱われる。"},
  {"id": 20241006, "year": 202410, "num": 6, "field": "structure", "text": "自然循環式水管ボイラーの循環力に関する記述として、適切なものは次のうちどれか。", "opts": ["水面計の照明で循環する。", "燃料ポンプの吐出圧だけを利用する。", "煙突高さだけで給水する。", "安全弁の吹出し力で循環する。", "加熱された水と未加熱水の密度差を利用する。"], "ans": 4, "exp": "自然循環では、水と蒸気水混合物の密度差によって循環が生じる。"},
  {"id": 20241007, "year": 202410, "num": 7, "field": "structure", "text": "強制循環式ボイラーに関する記述として、適切なものは次のうちどれか。", "opts": ["ポンプなどでボイラー水を循環させる。", "循環を一切行わない。", "燃料油を自然落下だけで循環させる。", "水面計の上下コックで燃焼空気を循環させる。", "煙突の風だけで給水する。"], "ans": 0, "exp": "強制循環式では循環ポンプなどを用いて水を循環させる。"},
  {"id": 20241008, "year": 202410, "num": 8, "field": "structure", "text": "接触伝熱面に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料タンクの底面である。", "水面計の外面だけをいう。", "燃焼ガスとの接触により主に対流伝熱を受ける面である。", "安全弁の弁座面だけをいう。", "煙突外面の塗装面だけをいう。"], "ans": 2, "exp": "接触伝熱面では燃焼ガスとの接触による対流伝熱が主体となる。"},
  {"id": 20241009, "year": 202410, "num": 9, "field": "structure", "text": "放射伝熱面に関する記述として、適切なものは次のうちどれか。", "opts": ["水処理装置の樹脂面である。", "火炎からの放射熱を主に受ける伝熱面である。", "圧力計の文字盤である。", "燃料計の目盛である。", "安全弁の銘板である。"], "ans": 1, "exp": "炉内の水冷壁などは火炎からの放射熱を受ける代表的な伝熱面である。"},
  {"id": 20241010, "year": 202410, "num": 10, "field": "structure", "text": "給水内管に関する記述として、適切なものは次のうちどれか。", "opts": ["煙突内のすすを吹き飛ばす管である。", "燃料油を加熱する専用管である。", "給水を胴内に分散させ、局部的な温度差を小さくする目的で設けられることがある。", "安全弁の吹出し管である。", "水面計のガラス保護管である。"], "ans": 2, "exp": "給水内管は給水を胴内へ適切に導き、熱応力の軽減などに役立つ。"},
  {"id": 20241011, "year": 202410, "num": 11, "field": "handling", "text": "点火前換気の目的として、適切なものは次のうちどれか。", "opts": ["燃料の発熱量を増やす。", "給水の硬度を下げる。", "安全弁の設定圧力を上げる。", "炉内や煙道に残った未燃ガスを排出する。", "水面計の目盛を消す。"], "ans": 3, "exp": "点火前換気は未燃ガスを排出し、着火時の爆発を防ぐために行う。"},
  {"id": 20241012, "year": 202410, "num": 12, "field": "handling", "text": "たき始め時の昇圧に関する記述として、適切なものは次のうちどれか。", "opts": ["空気抜きを一切行わない。", "安全弁を固定して急速に昇圧する。", "水位を確認せずに燃焼量を最大にする。", "急激な昇圧を避け、各部の膨張や漏れを確認する。", "圧力計を取り外して運転する。"], "ans": 3, "exp": "たき始めでは急熱を避け、圧力、水位、漏れ、膨張状態を確認する。"},
  {"id": 20241013, "year": 202410, "num": 13, "field": "handling", "text": "バーナ点火時に失火した場合の対応として、適切なものは次のうちどれか。", "opts": ["水位計を閉じたまま運転する。", "直ちに燃料を多くして再点火する。", "火炎検出器を無効にする。", "燃料を遮断し、換気してから原因を確認する。", "安全装置を取り外す。"], "ans": 3, "exp": "失火時は未燃燃料の蓄積を防ぎ、換気と原因確認を行ってから再点火する。"},
  {"id": 20241014, "year": 202410, "num": 14, "field": "handling", "text": "水面計の吹出し操作の目的として、適切なものは次のうちどれか。", "opts": ["ボイラー検査証を更新する。", "燃料を霧化する。", "排ガス中の酸素を測る。", "安全弁のばねを洗う。", "連絡管やコックの閉塞を確認し、機能を保つ。"], "ans": 4, "exp": "水面計の吹出しは水位表示の信頼性確認と閉塞防止のために行う。"},
  {"id": 20241015, "year": 202410, "num": 15, "field": "handling", "text": "水位が急に上昇した場合に疑うべき事項として、適切なものは次のうちどれか。", "opts": ["安全弁の銘板だけを見る。", "燃料発熱量の低下だけを確認する。", "煙突の色だけを確認する。", "給水弁の漏れや自動制御の異常などを確認する。", "作業主任者名札だけを確認する。"], "ans": 3, "exp": "水位異常では給水系統、制御装置、水面計の異常を確認する。"},
  {"id": 20241016, "year": 202410, "num": 16, "field": "handling", "text": "低水位警報が作動した場合の対応として、適切なものは次のうちどれか。", "opts": ["警報を無視せず、燃焼停止や原因確認を行う。", "警報音を止めるためだけに電源を切る。", "水位を確認せず燃焼を続ける。", "安全弁を固定する。", "吹出し弁を長時間全開にする。"], "ans": 0, "exp": "低水位警報は重大事故を防ぐ重要な警報であり、直ちに安全確認を行う。"},
  {"id": 20241017, "year": 202410, "num": 17, "field": "handling", "text": "吹出しを行う際の注意として、適切なものは次のうちどれか。", "opts": ["水位と圧力を確認し、急激な水位低下を避ける。", "水位を見ずに長時間行う。", "燃焼量を必ず最大にする。", "吹出し配管の安全を確認しない。", "水面計を閉じたまま行う。"], "ans": 0, "exp": "吹出しは水位低下や熱衝撃に注意し、手順に従って行う。"},
  {"id": 20241018, "year": 202410, "num": 18, "field": "handling", "text": "ボイラー水の濃縮が進みすぎた場合に起こり得る障害として、適切なものは次のうちどれか。", "opts": ["泡立ちやキャリオーバが生じやすくなる。", "必ず燃焼効率が100%になる。", "安全弁が不要になる。", "水面計が自動で清掃される。", "給水ポンプが燃料ポンプになる。"], "ans": 0, "exp": "ボイラー水の過濃縮は泡立ち、プライミング、キャリオーバの原因となる。"},
  {"id": 20241019, "year": 202410, "num": 19, "field": "handling", "text": "スケール付着による影響として、適切なものは次のうちどれか。", "opts": ["燃料中の硫黄分を除去する。", "伝熱を必ず良くする。", "伝熱を妨げ、伝熱面の過熱を招く。", "水位を正確に表示する。", "排ガス中の酸素をゼロにする。"], "ans": 2, "exp": "スケールは熱伝導を悪くし、燃料消費増加や伝熱面過熱につながる。"},
  {"id": 20241020, "year": 202410, "num": 20, "field": "handling", "text": "溶存酸素がボイラーに及ぼす影響として、適切なものは次のうちどれか。", "opts": ["燃料を霧化する。", "スケールを完全に除去する。", "腐食の原因となる。", "安全弁の吹出し量を増やす。", "水面計の目盛を自動で読む。"], "ans": 2, "exp": "給水中の溶存酸素は腐食原因となるため、脱気や薬注管理が行われる。"},
  {"id": 20241021, "year": 202410, "num": 21, "field": "fuel", "text": "高発熱量に関する記述として、適切なものは次のうちどれか。", "opts": ["燃焼で生じる水蒸気の凝縮潜熱を含めた発熱量である。", "水蒸気の凝縮潜熱を含めない発熱量である。", "燃料の粘度だけを示す値である。", "燃焼用空気の温度だけを示す値である。", "安全弁の吹出し量である。"], "ans": 0, "exp": "高発熱量は、生成水蒸気が凝縮して放出する熱を含む。"},
  {"id": 20241022, "year": 202410, "num": 22, "field": "fuel", "text": "低発熱量に関する記述として、適切なものは次のうちどれか。", "opts": ["安全弁の設定圧力である。", "常に高発熱量より大きい。", "燃料の密度だけを示す。", "水面計の水位である。", "燃焼で生じる水蒸気の凝縮潜熱を含めない発熱量である。"], "ans": 4, "exp": "低発熱量は、生成水蒸気の凝縮潜熱を差し引いた発熱量である。"},
  {"id": 20241023, "year": 202410, "num": 23, "field": "fuel", "text": "燃料の灰分が多い場合に起こり得ることとして、適切なものは次のうちどれか。", "opts": ["燃焼用空気が不要になる。", "伝熱面への付着やばいじん増加の原因となる。", "NOxが必ずゼロになる。", "水処理が不要になる。", "安全弁が不要になる。"], "ans": 1, "exp": "灰分は燃焼後の残留物で、付着やばいじんの原因となる。"},
  {"id": 20241024, "year": 202410, "num": 24, "field": "fuel", "text": "燃料中の水分が多い場合の影響として、適切なものは次のうちどれか。", "opts": ["安全装置が不要になる。", "発熱量が必ず増加する。", "燃焼用空気が不要になる。", "硫黄分が必ずゼロになる。", "有効発熱量が低下し、燃焼状態が悪くなることがある。"], "ans": 4, "exp": "水分が多い燃料では、水分の加熱・蒸発に熱を奪われる。"},
  {"id": 20241025, "year": 202410, "num": 25, "field": "fuel", "text": "重油の粘度管理に関する記述として、適切なものは次のうちどれか。", "opts": ["安全弁で粘度を下げる。", "粘度は燃焼に全く関係しない。", "粘度は高いほど常に完全燃焼する。", "水面計で粘度を測る。", "適切に加熱して噴霧しやすい粘度に調整する。"], "ans": 4, "exp": "重油は粘度が高いと霧化が悪くなるため、加熱管理が重要である。"},
  {"id": 20241026, "year": 202410, "num": 26, "field": "fuel", "text": "燃料油ストレーナの目的として、適切なものは次のうちどれか。", "opts": ["水面計の水をろ過する。", "空気中の酸素を除去する。", "燃料中のごみを除去し、バーナ詰まりを防ぐ。", "安全弁の吹出しを止める。", "排ガス温度を下げる薬剤である。"], "ans": 2, "exp": "ストレーナは燃料中の異物を取り除き、ポンプやバーナを保護する。"},
  {"id": 20241027, "year": 202410, "num": 27, "field": "fuel", "text": "燃料油加熱温度が高すぎる場合に起こり得ることとして、適切なものは次のうちどれか。", "opts": ["安全弁が不要になる。", "燃焼用空気が不要になる。", "水位が自動で安定する。", "硫黄分が完全に消える。", "気化やポンプ障害などを招くことがある。"], "ans": 4, "exp": "燃料油は適正温度に保ち、過熱や粘度不足にも注意する。"},
  {"id": 20241028, "year": 202410, "num": 28, "field": "fuel", "text": "圧力噴霧式バーナに関する記述として、適切なものは次のうちどれか。", "opts": ["蒸気だけで燃料を全く使わず燃焼する。", "燃料油に圧力をかけ、ノズルから噴出させて霧化する。", "水面計を使って霧化する。", "安全弁の吹出しで霧化する。", "煙突の自然通風だけで燃料を分解する。"], "ans": 1, "exp": "圧力噴霧式バーナは燃料油の圧力を利用して霧化する。"},
  {"id": 20241029, "year": 202410, "num": 29, "field": "fuel", "text": "戻り油式バーナに関する記述として、適切なものは次のうちどれか。", "opts": ["余分な燃料油を戻し、噴霧量を調整する方式である。", "燃料を全量炉内に戻す方式である。", "空気を全く使わない方式である。", "水処理用の方式である。", "安全弁の一種である。"], "ans": 0, "exp": "戻り油式では、戻り油量を変えて燃焼量を調整する。"},
  {"id": 20241030, "year": 202410, "num": 30, "field": "fuel", "text": "バーナの空気レジスタに関する記述として、適切なものは次のうちどれか。", "opts": ["水面計の水位を表示する。", "給水の硬度を下げる。", "燃料中の灰分を測定する。", "燃焼用空気の流れや量を調整する。", "ボイラー検査証を保管する。"], "ans": 3, "exp": "空気レジスタは、燃焼用空気の供給状態を整える部品である。"},
  {"id": 20241031, "year": 202410, "num": 31, "field": "law", "text": "小型ボイラーに関する法令問題で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["水面計のメーカーで判断する。", "すべて通常のボイラーと全く同じ手続と考える。", "燃料の色だけで判断する。", "通常のボイラーとの適用範囲や手続の違いを確認する。", "選択肢番号だけで判断する。"], "ans": 3, "exp": "法令問題では、小型ボイラー、簡易ボイラー、通常のボイラーの区分が重要である。"},
  {"id": 20241032, "year": 202410, "num": 32, "field": "law", "text": "簡易ボイラーに関する問題で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["伝熱面積を無視してよい。", "必ず作業主任者選任が同じになる。", "適用除外や区分を通常のボイラーと混同しない。", "水処理だけで区分する。", "煙突高さだけで区分する。"], "ans": 2, "exp": "簡易ボイラーは法令上の扱いが異なるため、区分の混同に注意する。"},
  {"id": 20241033, "year": 202410, "num": 33, "field": "law", "text": "ボイラー室の整理整頓に関する記述として、適切なものは次のうちどれか。", "opts": ["運転や避難に支障がないよう通路や周囲を確保する。", "炉前に可燃物を積み上げる。", "出入口を資材でふさぐ。", "燃料漏れを放置する。", "照明を常に消して点検しにくくする。"], "ans": 0, "exp": "ボイラー室では取扱い、点検、避難に支障がない環境を保つ。"},
  {"id": 20241034, "year": 202410, "num": 34, "field": "law", "text": "ボイラー室の換気に関する記述として、適切なものは次のうちどれか。", "opts": ["換気は燃焼に関係しない。", "燃焼用空気の確保や室温上昇防止のため重要である。", "常に密閉するほど安全である。", "燃料漏れ時も換気してはならない。", "水面計の代わりになる。"], "ans": 1, "exp": "ボイラー室の換気は燃焼、安全、作業環境の面で重要である。"},
  {"id": 20241035, "year": 202410, "num": 35, "field": "law", "text": "使用検査に関する問題で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["性能検査と常に同じ意味である。", "輸入や一定の設置前使用など、検査の目的と場面を区別する。", "定期自主検査と常に同じ意味である。", "燃料検査のことだけをいう。", "水質検査だけをいう。"], "ans": 1, "exp": "法令では検査名ごとに場面や目的が異なるため、名称の混同に注意する。"},
  {"id": 20241036, "year": 202410, "num": 36, "field": "law", "text": "落成検査に関する記述として、適切なものは次のうちどれか。", "opts": ["安全弁の購入手続だけをいう。", "毎日行う燃焼点検だけをいう。", "燃料販売時の品質検査である。", "水面計の吹出しだけをいう。", "設置後、使用前に受ける検査として問われる。"], "ans": 4, "exp": "落成検査は設置後の使用開始前に関連して出題される。"},
  {"id": 20241037, "year": 202410, "num": 37, "field": "law", "text": "性能検査に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料油の粘度測定だけをいう。", "点火前換気の別名である。", "継続使用のため、一定期間ごとに受ける検査として問われる。", "水面計の清掃だけをいう。", "安全弁を固定する検査である。"], "ans": 2, "exp": "性能検査はボイラー検査証の有効期間更新と関連して問われる。"},
  {"id": 20241038, "year": 202410, "num": 38, "field": "law", "text": "ボイラー検査証の有効期間に関する問題で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["作業者の人数だけで決まる。", "有効期間は一切存在しない。", "燃料価格で有効期間が決まる。", "性能検査や有効期間更新の扱いを確認する。", "水面計の本数だけで決まる。"], "ans": 3, "exp": "検査証の有効期間は性能検査と結び付けて問われやすい。"},
  {"id": 20241039, "year": 202410, "num": 39, "field": "law", "text": "ボイラーを休止する場合の法令問題で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["燃料を入れたままなら手続は関係ない。", "休止すればすべての手続が永久に不要になる。", "休止期間や再使用時の手続を確認する。", "水面計の本数だけで判断する。", "煙突を外せば必ず検査不要である。"], "ans": 2, "exp": "休止や再使用に関する問題では、条件と必要手続を整理して読む。"},
  {"id": 20241040, "year": 202410, "num": 40, "field": "law", "text": "ボイラーの主要部分を変更する場合に注意すべきこととして、適切なものは次のうちどれか。", "opts": ["塗装色だけで変更検査が決まる。", "どの変更も必ず手続不要である。", "変更届や変更検査の要否を確認する。", "作業者の好みで判断する。", "燃料販売店が自動的に判断する。"], "ans": 2, "exp": "胴、ドラム、過熱器など主要部分の変更は法令問題で頻出である。"},
  {"id": 20250401, "year": 202504, "num": 1, "field": "structure", "text": "逆止め弁に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料を完全燃焼させる触媒である。", "圧力を必ず大気圧まで下げる。", "流体の逆流を防止するために用いられる。", "水の硬度を取り除く薬剤である。", "火炎を検出するセンサである。"], "ans": 2, "exp": "逆止め弁は、給水などの逆流を防ぐ目的で設けられる。"},
  {"id": 20250402, "year": 202504, "num": 2, "field": "structure", "text": "連成計に関する記述として、適切なものは次のうちどれか。", "opts": ["水の硬度だけを測る計器である。", "正圧と負圧の両方を測定できる計器である。", "燃料の硫黄分だけを測る計器である。", "火炎の色だけを測る計器である。", "煙突高さを自動変更する装置である。"], "ans": 1, "exp": "連成計は圧力と真空の両側を測れる計器である。"},
  {"id": 20250403, "year": 202504, "num": 3, "field": "structure", "text": "温度計の取付けに関する記述として、適切なものは次のうちどれか。", "opts": ["安全弁の代わりに取り付ける。", "必ず燃料タンクの外側だけに取り付ける。", "水位を測るためだけに取り付ける。", "測定対象の温度を代表できる位置に取り付ける。", "煙突を支えるために取り付ける。"], "ans": 3, "exp": "温度計は、給水、蒸気、排ガスなど目的に応じた代表位置に設ける。"},
  {"id": 20250404, "year": 202504, "num": 4, "field": "structure", "text": "オンオフ制御に関する記述として、適切なものは次のうちどれか。", "opts": ["水質を自動で完全に純水化する制御である。", "操作量を連続的に微分だけで決める制御である。", "操作量を全開又は全閉など二位置で切り替える制御である。", "安全弁のばねを交換する制御である。", "煙突の高さを自動で変える制御である。"], "ans": 2, "exp": "オンオフ制御は、設定値を境に操作を入切する単純な制御方式である。"},
  {"id": 20250405, "year": 202504, "num": 5, "field": "structure", "text": "低水位燃料遮断装置の目的として、適切なものは次のうちどれか。", "opts": ["排ガス温度を測定する。", "燃料の硫黄分を除去する。", "水面計のガラスを着色する。", "低水位時に燃料供給を遮断して過熱を防ぐ。", "蒸気の乾き度を上げる薬剤である。"], "ans": 3, "exp": "低水位燃料遮断装置は、低水位による伝熱面過熱を防ぐための安全装置である。"},
  {"id": 20250406, "year": 202504, "num": 6, "field": "structure", "text": "蒸気トラップに関する記述として、適切なものは次のうちどれか。", "opts": ["燃料油を霧化する。", "蒸気配管などから復水を自動的に排出する。", "ボイラー水の硬度を測定する。", "水面計の代わりに水位を表示する。", "安全弁の吹出し圧力を設定する。"], "ans": 1, "exp": "蒸気トラップは蒸気の漏れを抑えながら復水を排出する装置である。"},
  {"id": 20250407, "year": 202504, "num": 7, "field": "structure", "text": "気水分離器を設ける主な目的として、適切なものは次のうちどれか。", "opts": ["安全弁の作動を妨げる。", "燃料中の灰分を燃やす。", "煙突の通風を止める。", "給水の硬度を高くする。", "蒸気中の水滴を取り除き乾き度を高める。"], "ans": 4, "exp": "気水分離器はキャリオーバした水分を分離し、蒸気の質を改善する。"},
  {"id": 20250408, "year": 202504, "num": 8, "field": "structure", "text": "節炭器で起こり得る低温腐食に関する記述として、適切なものは次のうちどれか。", "opts": ["給水温度を上げるほど必ず腐食が増える。", "排ガス温度が酸露点以下になると腐食のおそれがある。", "硫黄分は腐食に関係しない。", "水面計の閉塞だけが原因である。", "安全弁の吹出しだけで発生する。"], "ans": 1, "exp": "重油燃焼などでは、排ガスが酸露点以下になると低温腐食が問題になる。"},
  {"id": 20250409, "year": 202504, "num": 9, "field": "structure", "text": "鋳鉄製ボイラーの特徴として、適切でないものは次のうちどれか。", "opts": ["セクションを組み合わせる構造のものがある。", "高圧大容量発電用に常に最も適している。", "鋳鉄は急熱急冷や衝撃に注意を要する。", "低圧暖房用などに用いられる。", "返り管や水源接続が法令で問われることがある。"], "ans": 1, "exp": "鋳鉄製ボイラーは低圧用途で扱われることが多く、高圧大容量用途に常に最適というわけではない。"},
  {"id": 20250410, "year": 202504, "num": 10, "field": "structure", "text": "逃がし管に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料油をバーナへ戻すためだけの管である。", "安全弁などから吹き出した蒸気を安全な場所へ導くために設ける。", "給水を軟化するための管である。", "水面計の照明を支える管である。", "煙突の通風を止めるための管である。"], "ans": 1, "exp": "逃がし管は、安全弁などの吹出し蒸気を安全に処理するための配管である。"},
  {"id": 20250411, "year": 202504, "num": 11, "field": "handling", "text": "水処理でpH管理が重要な理由として、適切なものは次のうちどれか。", "opts": ["安全弁のばね定数を決める。", "燃料の発熱量だけを決める。", "煙突高さだけを決める。", "腐食やスケール障害の防止に関係する。", "ボイラー室の照度だけを決める。"], "ans": 3, "exp": "pH管理は腐食抑制や水処理薬品の効果に関係する。"},
  {"id": 20250412, "year": 202504, "num": 12, "field": "handling", "text": "プライミングに関する記述として、適切なものは次のうちどれか。", "opts": ["安全弁の分解整備である。", "燃料を予熱する操作である。", "ボイラー水が泡立ち、蒸気に水分が混入しやすくなる現象である。", "水面計を照明する装置である。", "煙突の通風力測定である。"], "ans": 2, "exp": "プライミングは泡立ちなどにより蒸気側へ水分が運ばれる現象である。"},
  {"id": 20250413, "year": 202504, "num": 13, "field": "handling", "text": "スートブロー実施時の注意として、適切なものは次のうちどれか。", "opts": ["燃料漏れを放置して行う。", "必ず水位を見ずに行う。", "炉内圧を無視する。", "安全弁を固定して行う。", "燃焼状態や通風、周囲の安全に注意して行う。"], "ans": 4, "exp": "スートブローはすす除去に有効だが、炉内圧や火炎、作業安全に注意が必要である。"},
  {"id": 20250414, "year": 202504, "num": 14, "field": "handling", "text": "運転停止時の燃料遮断に関する記述として、適切なものは次のうちどれか。", "opts": ["火炎確認を行わない。", "燃料弁を開けたまま放置する。", "所定の手順で燃料を遮断し、残火や漏れを確認する。", "水位を見ずに胴を空にする。", "安全装置を取り外す。"], "ans": 2, "exp": "停止時は燃料遮断、火炎消失、漏れの有無などを確認する。"},
  {"id": 20250415, "year": 202504, "num": 15, "field": "handling", "text": "乾燥保存を行う場合の注意として、適切なものは次のうちどれか。", "opts": ["水を満たしたまま乾燥剤を入れるだけでよい。", "内部を乾燥させ、乾燥剤の状態を定期的に確認する。", "腐食確認を行わない。", "燃料油を内部に満たす。", "マンホールを開けたまま雨水を入れる。"], "ans": 1, "exp": "乾燥保存では湿気を避け、乾燥剤の吸湿状態を確認する。"},
  {"id": 20250416, "year": 202504, "num": 16, "field": "handling", "text": "プレパージに関する記述として、適切なものは次のうちどれか。", "opts": ["安全弁を封印する作業である。", "停止後に給水を全量排出する操作である。", "ボイラー水を軟化する薬剤である。", "点火前に炉内を換気する操作である。", "煙突を塗装する作業である。"], "ans": 3, "exp": "プレパージは点火前換気のことで、未燃ガスを排出する。"},
  {"id": 20250417, "year": 202504, "num": 17, "field": "handling", "text": "ポストパージに関する記述として、適切なものは次のうちどれか。", "opts": ["安全弁を作動不能にする操作である。", "点火前に燃料を多量に送る操作である。", "水面計を閉じる操作である。", "燃焼停止後に炉内を換気する操作である。", "給水を完全に止める薬剤処理である。"], "ans": 3, "exp": "ポストパージは燃焼停止後の未燃ガス排出や炉内換気に関係する。"},
  {"id": 20250418, "year": 202504, "num": 18, "field": "handling", "text": "圧力が異常に上昇した場合の対応として、適切なものは次のうちどれか。", "opts": ["圧力計を外して運転する。", "燃焼量をさらに上げる。", "安全弁を固定する。", "燃焼を弱め又は停止し、安全弁や圧力計の状態を確認する。", "水位を確認しない。"], "ans": 3, "exp": "圧力異常では燃焼制御、安全弁、圧力計、負荷側の状態を確認する。"},
  {"id": 20250419, "year": 202504, "num": 19, "field": "handling", "text": "給水ができない場合の対応として、適切なものは次のうちどれか。", "opts": ["吹出しを長時間行う。", "水位を見ずに運転を続ける。", "燃焼を停止し、給水系統や水位を確認する。", "燃料量を最大にする。", "低水位警報を無効にする。"], "ans": 2, "exp": "給水不能は低水位に直結するため、燃焼停止と原因確認が重要である。"},
  {"id": 20250420, "year": 202504, "num": 20, "field": "handling", "text": "異音や異常振動を認めた場合の対応として、適切なものは次のうちどれか。", "opts": ["負荷を下げる、停止するなどして原因を確認する。", "異常を無視して運転を続ける。", "安全装置を取り外す。", "水面計を閉じる。", "燃料漏れを放置する。"], "ans": 0, "exp": "異音や振動は機器異常の兆候であり、早期確認が必要である。"},
  {"id": 20250421, "year": 202504, "num": 21, "field": "fuel", "text": "気体燃料の燃焼で特に注意すべきこととして、適切なものは次のうちどれか。", "opts": ["空気と混合しない。", "漏えいしても危険はない。", "漏えい時の爆発・火災危険に注意する。", "火炎検出が不要である。", "換気は常に不要である。"], "ans": 2, "exp": "気体燃料は混合気を形成しやすく、漏えい検知や換気が重要である。"},
  {"id": 20250422, "year": 202504, "num": 22, "field": "fuel", "text": "予混合燃焼に関する記述として、適切なものは次のうちどれか。", "opts": ["煙突内だけで燃焼させる方式である。", "燃料と空気を絶対に混ぜない。", "水を燃料に混ぜる方式である。", "安全弁を予熱する方式である。", "燃料と空気をあらかじめ混合して燃焼させる。"], "ans": 4, "exp": "予混合燃焼では、燃料と空気を燃焼前に混合する。"},
  {"id": 20250423, "year": 202504, "num": 23, "field": "fuel", "text": "拡散燃焼に関する記述として、適切なものは次のうちどれか。", "opts": ["ボイラー水の循環方式である。", "燃料と空気をあらかじめ完全混合してからだけ燃やす。", "水中でのみ行う燃焼である。", "安全弁の作動方式である。", "燃料と空気が燃焼しながら混合する燃焼である。"], "ans": 4, "exp": "拡散燃焼では燃料と空気が接触・混合しながら燃焼が進む。"},
  {"id": 20250424, "year": 202504, "num": 24, "field": "fuel", "text": "自然通風に関する記述として、適切なものは次のうちどれか。", "opts": ["安全弁の吹出しだけで通風する。", "必ず押込ファンだけを用いる。", "給水ポンプの圧力で通風する。", "煙突内外の温度差による密度差を利用する。", "水面計の水位で通風量を決める。"], "ans": 3, "exp": "自然通風は、煙突の内外温度差による浮力を利用する。"},
  {"id": 20250425, "year": 202504, "num": 25, "field": "fuel", "text": "平衡通風に関する記述として、適切なものは次のうちどれか。", "opts": ["給水ポンプだけで通風する方式である。", "ファンを一切使わない方式である。", "押込ファンと誘引ファンを用いて炉内圧を調整する方式である。", "安全弁で空気量を調整する方式である。", "水面計で排ガスを吸引する方式である。"], "ans": 2, "exp": "平衡通風では押込と誘引の両方を使い、炉内圧を適切に保つ。"},
  {"id": 20250426, "year": 202504, "num": 26, "field": "fuel", "text": "空気過剰が大きすぎる場合の影響として、適切なものは次のうちどれか。", "opts": ["燃料消費が必ずゼロになる。", "排ガス量が増え、排ガス熱損失が増加しやすい。", "燃焼用空気が不要になる。", "水位が自動で一定になる。", "安全弁が不要になる。"], "ans": 1, "exp": "過剰空気が多すぎると、加熱されて捨てられる排ガス量が増える。"},
  {"id": 20250427, "year": 202504, "num": 27, "field": "fuel", "text": "NOx発生の抑制に関する記述として、適切なものは次のうちどれか。", "opts": ["不完全燃焼を常に発生させる。", "空気比を常に無限大にする。", "燃焼温度や空気比を適切に管理する。", "水面計を閉じる。", "安全弁を固定する。"], "ans": 2, "exp": "NOxは高温燃焼や空気比に関係するため、燃焼管理が重要である。"},
  {"id": 20250428, "year": 202504, "num": 28, "field": "fuel", "text": "排ガス中の酸素濃度が高すぎる場合に疑われることとして、適切なものは次のうちどれか。", "opts": ["過剰空気が多い可能性がある。", "空気不足が必ず起きている。", "COが必ずゼロである。", "燃料が全く供給されていないことだけを示す。", "水処理が完了したことを示す。"], "ans": 0, "exp": "O2濃度は空気比判断の手掛かりとなり、高すぎる場合は過剰空気を疑う。"},
  {"id": 20250429, "year": 202504, "num": 29, "field": "fuel", "text": "完全燃焼に必要な条件として、適切でないものは次のうちどれか。", "opts": ["適切な空気量", "燃料と空気の良好な混合", "十分な燃焼温度", "燃料と空気を接触させないこと", "十分な燃焼時間"], "ans": 3, "exp": "完全燃焼には、空気量、混合、温度、時間が重要である。"},
  {"id": 20250430, "year": 202504, "num": 30, "field": "fuel", "text": "黒煙が発生している場合に疑われることとして、適切なものは次のうちどれか。", "opts": ["ボイラー検査証の更新", "完全燃焼が常に最良である証拠", "水処理の完了", "安全弁の正常作動だけ", "空気不足や噴霧不良などによる不完全燃焼"], "ans": 4, "exp": "黒煙は燃焼不良、空気不足、霧化不良などを示すことが多い。"},
  {"id": 20250431, "year": 202504, "num": 31, "field": "law", "text": "ボイラー取扱作業主任者の選任に関する記述として、適切なものは次のうちどれか。", "opts": ["一定のボイラー取扱作業では資格を有する者から選任する。", "誰でも無条件に選任できる。", "燃料販売店が必ず選任される。", "水処理薬剤の納入者が自動で選任される。", "検査証があれば選任は常に不要である。"], "ans": 0, "exp": "作業主任者は法令に基づき、資格者から選任する必要がある。"},
  {"id": 20250432, "year": 202504, "num": 32, "field": "law", "text": "作業主任者の職務として、適切でないものは次のうちどれか。", "opts": ["圧力、水位、燃焼状態を監視する。", "安全装置を取り外して運転を続ける。", "安全弁の機能を保持する。", "低水位などの異常を防止する。", "急激な負荷変動を避けるよう注意する。"], "ans": 1, "exp": "作業主任者は安全装置の機能保持や異常防止を図る立場である。"},
  {"id": 20250433, "year": 202504, "num": 33, "field": "law", "text": "取扱資格の問題で読み落としやすい条件として、適切なものは次のうちどれか。", "opts": ["燃料販売店の名称", "選択肢の文字数", "問題番号の偶奇", "ボイラーの種類、伝熱面積、圧力などの条件", "ボイラー室の床色"], "ans": 3, "exp": "取扱資格は種類や規模の条件によって範囲が異なる。"},
  {"id": 20250434, "year": 202504, "num": 34, "field": "law", "text": "安全弁に関する記述として、適切なものは次のうちどれか。", "opts": ["ボイラーの圧力上昇を防ぐ重要な安全装置である。", "水位を測る計器である。", "燃料を霧化するノズルである。", "排ガスを分析する装置である。", "給水を軟化する薬剤である。"], "ans": 0, "exp": "安全弁は過圧防止のために設けられる代表的な安全装置である。"},
  {"id": 20250435, "year": 202504, "num": 35, "field": "law", "text": "圧力計に関する法令問題で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["圧力計は法令問題で一切扱われない。", "最高使用圧力や目盛、取付状態に関する規定を確認する。", "水面計と同じものとして扱う。", "燃料の種類だけで目盛が決まる。", "作業者の年齢で目盛が決まる。"], "ans": 1, "exp": "圧力計は最高使用圧力との関係や取付方法が問われやすい。"},
  {"id": 20250436, "year": 202504, "num": 36, "field": "law", "text": "水面測定装置に関する記述として、適切なものは次のうちどれか。", "opts": ["排ガス中のCOを測る装置である。", "燃料中の硫黄分を測る装置である。", "煙突の高さを測る装置である。", "ボイラーの安全運転に必要な水位確認のために設けられる。", "安全弁のばねを作る装置である。"], "ans": 3, "exp": "水位確認は低水位事故防止の基本であり、水面計などが重要である。"},
  {"id": 20250437, "year": 202504, "num": 37, "field": "law", "text": "定期自主検査の記録に関する問題で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["水面計の色だけを記録する。", "記録は一切不要である。", "燃料価格だけを記録する。", "作業者の趣味だけを記録する。", "検査項目、結果、補修内容などの記録保存を確認する。"], "ans": 4, "exp": "定期自主検査では実施内容や結果の記録が問われやすい。"},
  {"id": 20250438, "year": 202504, "num": 38, "field": "law", "text": "定期自主検査で自動制御装置を点検する理由として、適切なものは次のうちどれか。", "opts": ["煙突を自動で撤去するため。", "燃料販売価格を決めるため。", "作業者の資格を自動で更新するため。", "ボイラー室の色を決めるため。", "燃焼や水位の安全制御が正常に働くか確認するため。"], "ans": 4, "exp": "自動制御装置は異常時の安全確保に関係するため、点検が重要である。"},
  {"id": 20250439, "year": 202504, "num": 39, "field": "law", "text": "定期自主検査で水処理装置を確認する理由として、適切なものは次のうちどれか。", "opts": ["スケールや腐食障害の防止に関係するため。", "燃料の色を変えるため。", "安全弁を不要にするため。", "作業主任者を不要にするため。", "検査証を自動発行するため。"], "ans": 0, "exp": "水処理装置の異常はスケール、腐食、キャリオーバなどにつながる。"},
  {"id": 20250440, "year": 202504, "num": 40, "field": "law", "text": "法令問題を解く際に最も重要な読み方として、適切なものは次のうちどれか。", "opts": ["問題文の条件語を無視する。", "『除く』『以上』『未満』などの条件語を正確に読む。", "選択肢の長さだけで判断する。", "必ず選択肢1を選ぶ。", "科目名だけで判断する。"], "ans": 1, "exp": "法令問題では、対象範囲や数値条件を示す語句が正答を左右する。"},
  {"id": 20251001, "year": 202510, "num": 1, "field": "structure", "text": "水の比熱に関する記述として、適切なものは次のうちどれか。", "opts": ["安全弁の吹出し圧力を表す。", "水1kgの温度を1K上げるのに必要な熱量に関係する。", "燃料油の粘度だけを表す。", "煙突の高さを表す。", "水面計のガラス長さを表す。"], "ans": 1, "exp": "比熱は単位質量の物質の温度を単位温度上げるために必要な熱量である。"},
  {"id": 20251002, "year": 202510, "num": 2, "field": "structure", "text": "絶対圧力に関する記述として、適切なものは次のうちどれか。", "opts": ["大気圧を基準にした圧力である。", "安全弁の口径だけを示す。", "燃料の発熱量である。", "水位の高さだけを示す。", "真空を基準にした圧力である。"], "ans": 4, "exp": "絶対圧力は完全真空を基準とする圧力で、ゲージ圧とは区別する。"},
  {"id": 20251003, "year": 202510, "num": 3, "field": "structure", "text": "圧力が高くなると水の沸点は一般にどうなるか。", "opts": ["高くなる。", "変わらない。", "低くなる。", "必ず0度になる。", "燃料の種類だけで決まる。"], "ans": 0, "exp": "飽和温度は圧力が高くなるほど高くなる。"},
  {"id": 20251004, "year": 202510, "num": 4, "field": "structure", "text": "湿り蒸気に関する記述として、適切なものは次のうちどれか。", "opts": ["水面計の内部水だけをいう。", "必ず過熱蒸気である。", "燃料ガスだけをいう。", "乾き飽和蒸気と水滴が混じった蒸気である。", "圧力計内の空気だけをいう。"], "ans": 3, "exp": "湿り蒸気は蒸気中に水滴を含む状態で、乾き度が1未満である。"},
  {"id": 20251005, "year": 202510, "num": 5, "field": "structure", "text": "伝熱面にすすが付着した場合の影響として、適切なものは次のうちどれか。", "opts": ["安全弁が不要になる。", "伝熱が必ず良くなる。", "水位が自動で安定する。", "燃料中の硫黄分が消える。", "熱伝達が悪くなり、排ガス温度が上がることがある。"], "ans": 4, "exp": "すすは断熱層となり、熱効率低下や排ガス温度上昇の原因となる。"},
  {"id": 20251006, "year": 202510, "num": 6, "field": "structure", "text": "炉壁の耐火材に関する記述として、適切なものは次のうちどれか。", "opts": ["圧力計の目盛を増やす。", "燃料を自動で脱硫する。", "水の硬度を下げる。", "高温ガスから外壁を保護し、熱損失を抑える。", "水面計の代わりに水位を表示する。"], "ans": 3, "exp": "耐火材や保温材は高温部の保護と熱損失低減に役立つ。"},
  {"id": 20251007, "year": 202510, "num": 7, "field": "structure", "text": "水循環が悪くなると起こり得る障害として、適切なものは次のうちどれか。", "opts": ["水面計の不要化。", "燃料の発熱量増加。", "安全弁の自動増設。", "伝熱面の過熱や焼損。", "煙突高さの低下。"], "ans": 3, "exp": "水循環不良は冷却不足を招き、伝熱面の過熱につながる。"},
  {"id": 20251008, "year": 202510, "num": 8, "field": "structure", "text": "ドラムに関する記述として、適切なものは次のうちどれか。", "opts": ["煙突の先端部である。", "燃料だけを貯蔵する。", "蒸気と水を分離し、水管群の水循環にも関係する。", "安全弁のばねである。", "給水ポンプの羽根車である。"], "ans": 2, "exp": "ドラムは気水分離や給水・蒸気の集まり、水循環に関係する主要部である。"},
  {"id": 20251009, "year": 202510, "num": 9, "field": "structure", "text": "貫流ボイラーで水質管理が重要な理由として、適切なものは次のうちどれか。", "opts": ["保有水量が少なく、管内でのスケールや腐食の影響を受けやすい。", "水を全く使わないため。", "燃料だけで蒸気を直接作るため。", "安全弁を設けないため。", "水面計が常に不要なため。"], "ans": 0, "exp": "貫流ボイラーは保有水量が少なく、給水管理と制御が重要である。"},
  {"id": 20251010, "year": 202510, "num": 10, "field": "structure", "text": "丸ボイラーの特徴として、適切なものは次のうちどれか。", "opts": ["胴内に比較的多くの水を保有するものがある。", "必ず水を保有しない。", "燃料ガスだけを貯蔵する。", "安全弁を設けることができない。", "蒸気を発生できない。"], "ans": 0, "exp": "丸ボイラーは胴に水を保有し、炉筒煙管式などが代表例である。"},
  {"id": 20251011, "year": 202510, "num": 11, "field": "handling", "text": "点火前に燃料漏れを確認する理由として、適切なものは次のうちどれか。", "opts": ["漏れた燃料への着火や爆発を防ぐため。", "給水を軟化するため。", "蒸気の乾き度を上げるためだけ。", "安全弁の口径を測るため。", "水面計の色を変えるため。"], "ans": 0, "exp": "燃料漏れは火災や爆発の原因となるため、点火前確認が必要である。"},
  {"id": 20251012, "year": 202510, "num": 12, "field": "handling", "text": "冷たいボイラーを急激にたき上げることが適切でない理由として、適切なものは次のうちどれか。", "opts": ["燃料が必ず不要になるため。", "熱応力や漏れを生じやすいため。", "水位が見えなくなる法令があるため。", "安全弁が増えるため。", "煙突が短くなるため。"], "ans": 1, "exp": "急熱は部材の温度差を大きくし、熱応力や漏れの原因となる。"},
  {"id": 20251013, "year": 202510, "num": 13, "field": "handling", "text": "水面計の水側連絡管が詰まった場合に起こり得ることとして、適切なものは次のうちどれか。", "opts": ["排ガス中の酸素がゼロになる。", "燃料発熱量が上がる。", "安全弁が不要になる。", "給水ポンプの能力が必ず向上する。", "実際より水位が高く見えるなど誤表示の原因となる。"], "ans": 4, "exp": "水面計連絡管の閉塞は誤水位表示につながるため危険である。"},
  {"id": 20251014, "year": 202510, "num": 14, "field": "handling", "text": "水面計の蒸気側連絡管が詰まった場合の注意として、適切なものは次のうちどれか。", "opts": ["表示は必ず正確になる。", "水位表示が不正確になるため機能試験で確認する。", "燃焼状態だけが改善する。", "安全弁の作動圧が下がる。", "燃料中の水分が消える。"], "ans": 1, "exp": "蒸気側、水側いずれの連絡管閉塞も水位誤認の原因となる。"},
  {"id": 20251015, "year": 202510, "num": 15, "field": "handling", "text": "水位が見えなくなったときの対応として、適切なものは次のうちどれか。", "opts": ["燃焼を停止し、水位確認と原因確認を行う。", "水位を確認せず燃焼を続ける。", "燃焼量を最大にする。", "安全弁を固定する。", "低水位警報を外す。"], "ans": 0, "exp": "水位不明のまま運転することは危険であり、まず安全側に停止する。"},
  {"id": 20251016, "year": 202510, "num": 16, "field": "handling", "text": "ボイラー水の電気伝導率を測る目的として、適切なものは次のうちどれか。", "opts": ["燃料の発熱量を直接測るため。", "溶解固形分の濃縮状態を推定するため。", "安全弁のばね力を測るため。", "火炎の明るさを測るため。", "煙突高さを測るため。"], "ans": 1, "exp": "電気伝導率はボイラー水の濃縮管理の指標として用いられる。"},
  {"id": 20251017, "year": 202510, "num": 17, "field": "handling", "text": "りん酸塩処理に関する記述として、適切なものは次のうちどれか。", "opts": ["水位を直接表示する。", "燃料の硫黄分を除去する。", "安全弁の吹出し圧力を上げる。", "煙突内のすすを燃やす。", "硬度成分を軟らかいスラッジとして処理する目的で用いられることがある。"], "ans": 4, "exp": "りん酸塩処理は硬度成分によるスケール障害の防止に関係する。"},
  {"id": 20251018, "year": 202510, "num": 18, "field": "handling", "text": "脱酸素剤を用いる目的として、適切なものは次のうちどれか。", "opts": ["安全弁を固定する。", "燃料の粘度を上げる。", "排ガス中の酸素を増やす。", "水面計を不要にする。", "給水中の溶存酸素を減らし腐食を抑える。"], "ans": 4, "exp": "溶存酸素は腐食原因となるため、脱気や脱酸素剤で管理する。"},
  {"id": 20251019, "year": 202510, "num": 19, "field": "handling", "text": "アルカリ腐食や苛性脆化に関する問題で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["水位計の照明だけの問題である。", "燃料の完全燃焼だけの問題である。", "過度なアルカリ濃縮や応力部での障害として整理する。", "煙突高さだけで決まる。", "安全弁口径だけで決まる。"], "ans": 2, "exp": "水質の過度な濃縮や局部濃縮は腐食・脆化の問題として問われる。"},
  {"id": 20251020, "year": 202510, "num": 20, "field": "handling", "text": "キャリオーバが発生した場合に起こり得ることとして、適切なものは次のうちどれか。", "opts": ["蒸気が必ず完全に乾く。", "蒸気配管や過熱器に水分・不純物が運ばれる。", "燃料消費がゼロになる。", "水位確認が不要になる。", "安全弁が必ず閉じなくなる。"], "ans": 1, "exp": "キャリオーバは蒸気側への水分・不純物持込みで、配管や機器に悪影響を及ぼす。"},
  {"id": 20251021, "year": 202510, "num": 21, "field": "fuel", "text": "液体燃料の引火点に関する記述として、適切なものは次のうちどれか。", "opts": ["必ず燃焼温度と同じである。", "可燃性蒸気を発生し、点火源で引火し得る最低温度である。", "水の沸点である。", "安全弁の作動温度である。", "煙突内の温度である。"], "ans": 1, "exp": "引火点は燃料の取扱安全上重要な性質である。"},
  {"id": 20251022, "year": 202510, "num": 22, "field": "fuel", "text": "燃料の密度に関する記述として、適切なものは次のうちどれか。", "opts": ["安全弁の吹出し量である。", "水位の高さだけを示す。", "単位体積当たりの質量で、貯蔵量や流量換算に関係する。", "排ガス中の酸素濃度である。", "給水のpHである。"], "ans": 2, "exp": "密度は質量と体積の換算や燃料管理で用いられる。"},
  {"id": 20251023, "year": 202510, "num": 23, "field": "fuel", "text": "燃料の元素分析で主に見る成分として、適切でないものは次のうちどれか。", "opts": ["炭素", "水素", "水面計目盛", "酸素", "硫黄"], "ans": 2, "exp": "燃料の元素分析では炭素、水素、硫黄、酸素、窒素などが扱われる。"},
  {"id": 20251024, "year": 202510, "num": 24, "field": "fuel", "text": "重油中の硫黄分が多い場合に起こりやすい障害として、適切なものは次のうちどれか。", "opts": ["燃焼用空気不要化。", "水位の自動安定。", "安全弁の不要化。", "SOx発生や低温腐食。", "灰分の完全消失。"], "ans": 3, "exp": "硫黄分はSOxや硫酸露点、低温腐食と関連する。"},
  {"id": 20251025, "year": 202510, "num": 25, "field": "fuel", "text": "低温腐食を防ぐ考え方として、適切なものは次のうちどれか。", "opts": ["燃焼用空気をゼロにする。", "排ガスを必ず0度まで冷やす。", "硫黄分を増やす。", "空気予熱器を必ず水で満たす。", "排ガス温度を酸露点以下にしないよう管理する。"], "ans": 4, "exp": "低温腐食は酸露点以下で起こりやすく、排ガス温度管理が重要である。"},
  {"id": 20251026, "year": 202510, "num": 26, "field": "fuel", "text": "燃料油の霧化が悪い場合に起こり得ることとして、適切なものは次のうちどれか。", "opts": ["水位の自動補正。", "完全燃焼の保証。", "燃料消費ゼロ。", "NOx必ずゼロ。", "黒煙や未燃分の増加。"], "ans": 4, "exp": "霧化不良は燃料と空気の混合不良を招き、不完全燃焼につながる。"},
  {"id": 20251027, "year": 202510, "num": 27, "field": "fuel", "text": "油バーナの燃焼量調整に関係するものとして、適切なものは次のうちどれか。", "opts": ["安全弁の銘板だけ。", "水面計の目盛色だけ。", "燃料圧力、戻り油量、空気量など。", "煙突の塗色だけ。", "作業者の人数だけ。"], "ans": 2, "exp": "油バーナでは燃料供給量と空気量を適切に調整する。"},
  {"id": 20251028, "year": 202510, "num": 28, "field": "fuel", "text": "バーナタイルの目的として、適切なものは次のうちどれか。", "opts": ["給水を軟化する。", "火炎の安定や燃焼室入口部の保護に役立つ。", "燃料の硫黄を除去する。", "水面計の水位を表示する。", "安全弁を作動させる。"], "ans": 1, "exp": "バーナタイルは火炎保持や高温部保護に関係する部材である。"},
  {"id": 20251029, "year": 202510, "num": 29, "field": "fuel", "text": "都市ガスなどの気体燃料で漏えい検知が重要な理由として、適切なものは次のうちどれか。", "opts": ["安全弁の作動圧が上がるためだけ。", "水質を悪化させるためだけ。", "空気と混合して爆発性混合気を作るおそれがあるため。", "煙突を短くするため。", "給水ポンプを止めるためだけ。"], "ans": 2, "exp": "気体燃料は漏えい時に火災・爆発リスクが大きく、検知と換気が重要である。"},
  {"id": 20251030, "year": 202510, "num": 30, "field": "fuel", "text": "ガス燃料の燃焼管理で確認する事項として、適切なものは次のうちどれか。", "opts": ["水面計の材質だけ。", "ガス圧、空気量、火炎状態、漏えいの有無。", "安全弁の価格だけ。", "燃料タンク底の水だけ。", "ボイラー室の床色だけ。"], "ans": 1, "exp": "ガス燃料では圧力、空気量、火炎、漏えい管理が重要である。"},
  {"id": 20251031, "year": 202510, "num": 31, "field": "law", "text": "伝熱面積の問題で『片面だけが燃焼ガスに触れる』場合の読み方として、適切なものは次のうちどれか。", "opts": ["水面計の本数で決める。", "すべて両面を無条件に加える。", "燃料価格だけで決める。", "作業者数で決める。", "算入方法が部位や構造で異なるため条件を確認する。"], "ans": 4, "exp": "伝熱面積はボイラー種類と伝熱面の条件により扱いが変わる。"},
  {"id": 20251032, "year": 202510, "num": 32, "field": "law", "text": "貫流ボイラーの法令上の扱いで注意すべきこととして、適切なものは次のうちどれか。", "opts": ["常に法令対象外である。", "伝熱面積や最高使用圧力などの条件を確認する。", "燃料がガスならすべて同じ扱いである。", "水処理をすれば区分は不要である。", "煙突高さだけで決まる。"], "ans": 1, "exp": "貫流ボイラーは規模や条件により区分が変わるため、条件読みが重要である。"},
  {"id": 20251033, "year": 202510, "num": 33, "field": "law", "text": "ボイラー室に関する法令問題で見落としやすい条件として、適切なものは次のうちどれか。", "opts": ["作業者の趣味。", "出入口、通路、可燃物、換気など。", "燃料販売店の広告。", "机の色だけ。", "水面計メーカーの所在地。"], "ans": 1, "exp": "ボイラー室では安全な取扱いと避難・火災防止の観点が問われる。"},
  {"id": 20251034, "year": 202510, "num": 34, "field": "law", "text": "ボイラー据付け時の基礎や周囲空間に関する記述として、適切なものは次のうちどれか。", "opts": ["点検、修理、操作に支障がないようにする。", "点検できないほど密着させる。", "出入口をふさぐ。", "可燃物で囲む。", "換気をなくす。"], "ans": 0, "exp": "据付けでは保守点検や安全な操作ができる空間を確保する。"},
  {"id": 20251035, "year": 202510, "num": 35, "field": "law", "text": "ボイラー検査証を滅失した場合の扱いとして、法令問題で注意すべきことは次のうちどれか。", "opts": ["水面計を増やせばよい。", "検査証は不要なので放置する。", "燃料を変えればよい。", "再交付などの手続を確認する。", "安全弁を外せばよい。"], "ans": 3, "exp": "検査証の紛失や記載事項変更は手続問題として問われる。"},
  {"id": 20251036, "year": 202510, "num": 36, "field": "law", "text": "検査証の記載事項変更で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["作業者の昼食だけを届け出る。", "どの変更も届出不要である。", "所有者や設置場所など、変更内容に応じた手続を確認する。", "燃料価格だけで判断する。", "水面計の色だけで判断する。"], "ans": 2, "exp": "検査証記載事項の変更は、必要な手続と期限を問われることがある。"},
  {"id": 20251037, "year": 202510, "num": 37, "field": "law", "text": "廃止したボイラーに関する手続問題で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["水面計だけ外せばよい。", "廃止すれば記録も検査証も必ず放置してよい。", "燃料を抜けば手続不要と決めつける。", "煙突だけ残せば使用中とみなす。", "廃止届や検査証返還などの扱いを確認する。"], "ans": 4, "exp": "廃止時は届出や検査証の扱いが問われる。"},
  {"id": 20251038, "year": 202510, "num": 38, "field": "law", "text": "休止中のボイラーを再使用する場合の注意として、適切なものは次のうちどれか。", "opts": ["休止期間や検査証有効期間、必要検査を確認する。", "必ず無検査で再使用できる。", "燃料を入れれば直ちに使用できる。", "水面計を外したまま使用する。", "安全弁を固定して使用する。"], "ans": 0, "exp": "再使用では休止期間や検査証の状態に応じた手続確認が必要である。"},
  {"id": 20251039, "year": 202510, "num": 39, "field": "law", "text": "作業主任者が圧力の急激な上昇を防ぐべき理由として、適切なものは次のうちどれか。", "opts": ["燃料価格を下げるためだけ。", "過圧や熱応力などの危険を防ぐため。", "水面計の色を変えるため。", "煙突高さを上げるため。", "検査証を不要にするため。"], "ans": 1, "exp": "作業主任者は圧力、水位、燃焼などを監視し、安全な運転を確保する。"},
  {"id": 20251040, "year": 202510, "num": 40, "field": "law", "text": "ボイラー取扱者に必要な基本姿勢として、適切なものは次のうちどれか。", "opts": ["安全装置を無効化する。", "異常兆候を見逃さず、手順と法令に従う。", "水位を見ない。", "燃料漏れを放置する。", "検査証を破棄する。"], "ans": 1, "exp": "取扱者には安全確認、手順遵守、異常時対応が求められる。"},
  {"id": 20260401, "year": 202604, "num": 1, "field": "structure", "text": "節炭器の水漏れが疑われる兆候として、適切なものは次のうちどれか。", "opts": ["燃料発熱量の上昇。", "煙道内の湿りや給水量の異常増加。", "水位計の消失。", "安全弁の不要化。", "煙突高さの自動上昇。"], "ans": 1, "exp": "節炭器漏れでは煙道側への水漏れ、給水量変化、排ガス状態変化などに注意する。"},
  {"id": 20260402, "year": 202604, "num": 2, "field": "structure", "text": "空気予熱器で燃焼用空気を予熱する利点として、適切なものは次のうちどれか。", "opts": ["給水を軟化する。", "水位確認を不要にする。", "燃料中の灰分をなくす。", "安全弁の作動を止める。", "燃焼改善と熱効率向上に役立つ。"], "ans": 4, "exp": "空気予熱器は排熱を利用して燃焼用空気を温め、効率改善に寄与する。"},
  {"id": 20260403, "year": 202604, "num": 3, "field": "structure", "text": "給水ポンプのキャビテーションに関する記述として、適切なものは次のうちどれか。", "opts": ["吸込み側圧力低下などで気泡が発生し、騒音や損傷を招く。", "燃料の完全燃焼をいう。", "水面計の吹出しをいう。", "安全弁の吹出しをいう。", "煙突の自然通風をいう。"], "ans": 0, "exp": "キャビテーションはポンプ内で気泡が発生・崩壊し、性能低下や損傷につながる現象である。"},
  {"id": 20260404, "year": 202604, "num": 4, "field": "structure", "text": "水面計を2個設ける趣旨として、適切なものは次のうちどれか。", "opts": ["蒸気圧を下げるためだけ。", "水位を見えにくくするため。", "燃料を節約するためだけ。", "一方に異常があっても水位確認の信頼性を高めるため。", "煙突通風を止めるため。"], "ans": 3, "exp": "水面計は低水位事故防止に重要で、複数設置により確認の信頼性を高める。"},
  {"id": 20260405, "year": 202604, "num": 5, "field": "structure", "text": "安全弁の弁座漏れがある場合の影響として、適切なものは次のうちどれか。", "opts": ["低水位が起こらなくなる。", "燃焼効率が必ず上がる。", "水質が必ず改善する。", "給水が不要になる。", "蒸気漏れによる損失や作動不良につながる。"], "ans": 4, "exp": "安全弁の漏れは蒸気損失や機能低下の原因となるため点検が必要である。"},
  {"id": 20260406, "year": 202604, "num": 6, "field": "structure", "text": "圧力計の目盛範囲に関する記述として、適切なものは次のうちどれか。", "opts": ["水位だけを表示すればよい。", "目盛は全く不要である。", "燃料の粘度だけを表示すればよい。", "使用圧力を読み取りやすく、過圧も確認できる範囲が必要である。", "煙突高さだけを表示すればよい。"], "ans": 3, "exp": "圧力計は運転圧力と安全管理に必要な範囲を読み取れるものを用いる。"},
  {"id": 20260407, "year": 202604, "num": 7, "field": "structure", "text": "インタロックに関する記述として、適切なものは次のうちどれか。", "opts": ["煙突内のすすである。", "燃料を加熱するだけの装置である。", "水処理薬剤の名称である。", "必要条件が満たされないと燃焼開始などを許可しない仕組みである。", "安全弁のばね材料である。"], "ans": 3, "exp": "燃焼安全では、送風や火炎検出などの条件を満たさないと燃料供給しない制御が重要である。"},
  {"id": 20260408, "year": 202604, "num": 8, "field": "structure", "text": "シーケンス制御に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料の硫黄分を測る制御である。", "水の硬度だけを下げる制御である。", "点火、燃焼、停止などを所定の順序で進める制御である。", "安全弁を固定する制御である。", "煙突高さを測る制御である。"], "ans": 2, "exp": "シーケンス制御は、安全な順序で機器を動作させるために用いられる。"},
  {"id": 20260409, "year": 202604, "num": 9, "field": "structure", "text": "高圧燃料遮断に関する記述として、適切なものは次のうちどれか。", "opts": ["蒸気圧力が異常に上昇したとき燃料供給を止める安全機能である。", "給水を加熱する機能である。", "水位を高く表示する機能である。", "燃料中の水分を増やす機能である。", "煙突を冷却する機能である。"], "ans": 0, "exp": "高圧時の燃料遮断は過圧事故を防ぐための安全機能である。"},
  {"id": 20260410, "year": 202604, "num": 10, "field": "structure", "text": "蒸気止め弁に関する記述として、適切なものは次のうちどれか。", "opts": ["ボイラーから蒸気を送る配管を開閉するために設ける。", "給水中の酸素を除去する薬剤である。", "燃料油をろ過する装置である。", "煙突内の通風力を発生させる装置である。", "水面計の代わりに水位を示す装置である。"], "ans": 0, "exp": "蒸気止め弁は蒸気の送出を開閉する重要な附属品である。"},
  {"id": 20260411, "year": 202604, "num": 11, "field": "handling", "text": "ウォータハンマが起こりやすい状況として、適切なものは次のうちどれか。", "opts": ["安全弁の銘板が読める。", "燃料タンクが空である。", "煙突が高い。", "蒸気配管内に復水がたまっている。", "給水が軟化されている。"], "ans": 3, "exp": "蒸気配管内の復水はウォータハンマの原因となるため、ドレン排出が重要である。"},
  {"id": 20260412, "year": 202604, "num": 12, "field": "handling", "text": "長期停止前の清掃で重視すべきこととして、適切なものは次のうちどれか。", "opts": ["水位計を破損させる。", "燃料漏れを放置する。", "スラッジやすすを除去し、腐食原因を減らす。", "安全弁を固定する。", "煙道を詰まらせる。"], "ans": 2, "exp": "停止保存前は内部・外部の汚れを除去して腐食や劣化を防ぐ。"},
  {"id": 20260413, "year": 202604, "num": 13, "field": "handling", "text": "満水保存でボイラー水を満たす理由として、適切なものは次のうちどれか。", "opts": ["安全弁を作動させ続けるため。", "燃料を増やすため。", "空気との接触を減らして腐食を抑えるため。", "水面計を隠すため。", "煙突を洗うため。"], "ans": 2, "exp": "満水保存は脱酸素した水で満たし、酸素接触を抑える保存法である。"},
  {"id": 20260414, "year": 202604, "num": 14, "field": "handling", "text": "燃焼安全装置のリセット後に直ちに再点火してよいかについて、適切なものは次のうちどれか。", "opts": ["原因確認と換気など安全確認が必要である。", "原因を確認せず何度も再点火してよい。", "燃料を増やして再点火する。", "火炎検出器を外す。", "低水位警報を止める。"], "ans": 0, "exp": "安全装置が作動した場合は原因を確認し、未燃ガス排出などを行ってから再点火する。"},
  {"id": 20260415, "year": 202604, "num": 15, "field": "handling", "text": "火炎検出器の点検で注意すべきこととして、適切なものは次のうちどれか。", "opts": ["汚れているほど感度が上がる。", "汚れ、取付位置、検出状態を確認する。", "常に取り外して運転する。", "水位確認の代わりに使う。", "燃料の硫黄分を測る。"], "ans": 1, "exp": "火炎検出器の異常は失火検出や燃料遮断に影響する。"},
  {"id": 20260416, "year": 202604, "num": 16, "field": "handling", "text": "逆火が発生した場合の対応として、適切なものは次のうちどれか。", "opts": ["炉内換気をしない。", "燃料をさらに多く送る。", "燃料を遮断し、原因を確認してから再点火する。", "安全装置を無効にする。", "水位を見ずに運転を続ける。"], "ans": 2, "exp": "逆火は燃焼異常であり、燃料遮断、換気、原因確認が必要である。"},
  {"id": 20260417, "year": 202604, "num": 17, "field": "handling", "text": "燃料油圧が異常に低い場合に疑う事項として、適切なものは次のうちどれか。", "opts": ["ストレーナ詰まり、ポンプ不良、弁の状態など。", "水位が高いことだけ。", "安全弁の口径だけ。", "煙突高さだけ。", "ボイラー検査証の有効期間だけ。"], "ans": 0, "exp": "燃料油圧異常では燃料系統の詰まり、漏れ、ポンプ、弁を確認する。"},
  {"id": 20260418, "year": 202604, "num": 18, "field": "handling", "text": "排ガス温度が通常より高い場合に疑うこととして、適切なものは次のうちどれか。", "opts": ["燃料が不要になったこと。", "水質が必ず完全であること。", "伝熱面のすす付着やスケール付着。", "安全弁が不要になったこと。", "水面計の閉塞だけ。"], "ans": 2, "exp": "排ガス温度上昇は伝熱不良や燃焼過剰などのサインとなる。"},
  {"id": 20260419, "year": 202604, "num": 19, "field": "handling", "text": "日常点検で給水系統について確認する事項として、適切なものは次のうちどれか。", "opts": ["安全弁の価格だけ。", "燃料販売店の所在地だけ。", "煙突の塗装色だけ。", "ポンプ、弁、漏れ、圧力、給水量など。", "作業者の通勤経路だけ。"], "ans": 3, "exp": "給水系統の異常は低水位や運転停止につながるため、日常確認が重要である。"},
  {"id": 20260420, "year": 202604, "num": 20, "field": "handling", "text": "燃焼状態の目視確認で見る事項として、適切なものは次のうちどれか。", "opts": ["水処理薬剤の容器色だけ。", "作業靴の色だけ。", "検査証の紙質だけ。", "火炎の形、色、安定性、煙の状態など。", "燃料販売店の看板だけ。"], "ans": 3, "exp": "火炎や煙の状態は燃焼良否を判断する基本情報である。"},
  {"id": 20260421, "year": 202604, "num": 21, "field": "fuel", "text": "炉内圧が正圧になりすぎた場合の問題として、適切なものは次のうちどれか。", "opts": ["火炎や燃焼ガスの噴出のおそれがある。", "水質が必ず改善する。", "燃料消費がゼロになる。", "安全弁が不要になる。", "排ガスが発生しない。"], "ans": 0, "exp": "炉内圧の過度な正圧は燃焼ガス漏れや安全上の問題を招く。"},
  {"id": 20260422, "year": 202604, "num": 22, "field": "fuel", "text": "通風が強すぎる場合に起こり得ることとして、適切なものは次のうちどれか。", "opts": ["スケールが瞬時に消える。", "燃料が不要になる。", "水位が必ず上がる。", "火炎が不安定になり、排ガス熱損失が増えることがある。", "安全弁が開かなくなる。"], "ans": 3, "exp": "過大通風は燃焼不安定や熱損失増加の原因になる。"},
  {"id": 20260423, "year": 202604, "num": 23, "field": "fuel", "text": "空気不足で増加しやすいものとして、適切なものは次のうちどれか。", "opts": ["安全弁数。", "給水硬度の低下。", "一酸化炭素。", "ボイラー検査証の枚数。", "水面計の長さ。"], "ans": 2, "exp": "空気不足では不完全燃焼となりCOやすすが増加しやすい。"},
  {"id": 20260424, "year": 202604, "num": 24, "field": "fuel", "text": "燃焼温度が高いほど増加しやすい大気汚染物質として、適切なものは次のうちどれか。", "opts": ["給水硬度。", "水蒸気の乾き度。", "NOx。", "安全弁口径。", "ボイラー室照度。"], "ans": 2, "exp": "高温燃焼ではサーマルNOxが増加しやすい。"},
  {"id": 20260425, "year": 202604, "num": 25, "field": "fuel", "text": "理論空気量に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料を完全燃焼させるのに理論上必要な最小空気量である。", "実際に必ず供給してはならない空気量である。", "水処理に必要な薬剤量である。", "安全弁の吹出し量である。", "煙突高さの別名である。"], "ans": 0, "exp": "理論空気量は完全燃焼に必要な最小空気量で、実際には過剰空気を加える。"},
  {"id": 20260426, "year": 202604, "num": 26, "field": "fuel", "text": "空気比に関する記述として、適切なものは次のうちどれか。", "opts": ["燃料の密度を水の密度で割った値である。", "実際空気量を理論空気量で割った値である。", "水位を胴径で割った値である。", "安全弁口径を圧力で割った値である。", "煙突高さを室温で割った値である。"], "ans": 1, "exp": "空気比は実際に供給した空気量と理論空気量の比である。"},
  {"id": 20260427, "year": 202604, "num": 27, "field": "fuel", "text": "排ガス中CO2濃度が燃焼管理で使われる理由として、適切なものは次のうちどれか。", "opts": ["給水硬度を示すため。", "水位を直接示すため。", "空気比や燃焼状態を推定する手掛かりになるため。", "安全弁の設定圧を示すため。", "燃料価格を示すため。"], "ans": 2, "exp": "CO2、O2、COは燃焼状態や過剰空気判断の指標として用いられる。"},
  {"id": 20260428, "year": 202604, "num": 28, "field": "fuel", "text": "白煙が見える場合に考えられるものとして、適切なものは次のうちどれか。", "opts": ["水蒸気の凝縮や燃料中水分など。", "必ず完全燃焼で異常なし。", "必ず燃料がない。", "安全弁が開いている証拠だけ。", "水面計が正常な証拠だけ。"], "ans": 0, "exp": "白煙は水蒸気の凝縮などの場合があるが、燃料や燃焼状態と合わせて判断する。"},
  {"id": 20260429, "year": 202604, "num": 29, "field": "fuel", "text": "燃焼効率を悪化させる要因として、適切でないものは次のうちどれか。", "opts": ["過大な過剰空気", "伝熱面のすす付着", "排ガス温度の過大", "適正な空気比と清浄な伝熱面", "燃料の霧化不良"], "ans": 3, "exp": "適正空気比と清浄な伝熱面は効率維持に有効である。"},
  {"id": 20260430, "year": 202604, "num": 30, "field": "fuel", "text": "燃焼に必要な三要素として、適切な組合せは次のうちどれか。", "opts": ["給水、吹出し、保存。", "水位、圧力、検査証。", "安全弁、水面計、圧力計。", "可燃物、酸素、点火源又は温度。", "煙突、床、照明。"], "ans": 3, "exp": "燃焼には可燃物、酸素、着火に足る温度又は点火源が必要である。"},
  {"id": 20260431, "year": 202604, "num": 31, "field": "law", "text": "安全弁の調整に関する記述として、適切なものは次のうちどれか。", "opts": ["水面計の代わりに使う。", "運転中に任意に締め込んでよい。", "作動しないよう固定する。", "燃料節約のため封鎖する。", "みだりに調整を変更してはならない。"], "ans": 4, "exp": "安全弁は過圧防止の重要装置であり、勝手な調整や固定は危険である。"},
  {"id": 20260432, "year": 202604, "num": 32, "field": "law", "text": "水面計の機能保持に関する記述として、適切なものは次のうちどれか。", "opts": ["安全弁の代わりに用いる。", "常に閉じて見えないようにする。", "水位を隠す。", "燃料油を流す。", "見やすく、閉塞や漏れがない状態に保つ。"], "ans": 4, "exp": "水面計は低水位事故防止に直結するため、機能保持が重要である。"},
  {"id": 20260433, "year": 202604, "num": 33, "field": "law", "text": "圧力計の機能確認で注意することとして、適切なものは次のうちどれか。", "opts": ["指示の戻り、漏れ、コックの開閉状態などを確認する。", "常に指針を固定する。", "目盛を隠す。", "燃料を通す。", "水処理薬剤を注入する。"], "ans": 0, "exp": "圧力計は過圧防止の基本情報を示すため、指示異常や閉塞に注意する。"},
  {"id": 20260434, "year": 202604, "num": 34, "field": "law", "text": "定期自主検査で附属品を点検する意義として、適切なものは次のうちどれか。", "opts": ["作業主任者を不要にするため。", "検査証を不要にするため。", "燃料価格を下げるためだけ。", "安全運転に必要な機器の異常を早期に発見するため。", "水位確認をやめるため。"], "ans": 3, "exp": "附属品の異常は事故に直結するため、定期的な確認が重要である。"},
  {"id": 20260435, "year": 202604, "num": 35, "field": "law", "text": "定期自主検査の補修結果に関する記録として、適切なものは次のうちどれか。", "opts": ["煙突の色だけを記録する。", "異常があっても記録しない。", "燃料販売店だけを記録する。", "作業者の趣味だけを記録する。", "異常の内容と補修内容を記録する。"], "ans": 4, "exp": "定期自主検査では点検結果と補修内容の記録が重要である。"},
  {"id": 20260436, "year": 202604, "num": 36, "field": "law", "text": "法令問題で『遅滞なく』とある場合の注意として、適切なものは次のうちどれか。", "opts": ["水位で意味が変わる。", "いつでもよいという意味である。", "必ず1年後という意味である。", "燃料の種類で意味が変わる。", "期限表現を読み落とさず、手続のタイミングを確認する。"], "ans": 4, "exp": "法令の期限語は手続問題で正誤を分ける。"},
  {"id": 20260437, "year": 202604, "num": 37, "field": "law", "text": "法令問題で『所轄労働基準監督署長』が出る場合の注意として、適切なものは次のうちどれか。", "opts": ["作業主任者の別名である。", "燃料販売店のことと考える。", "届出先や申請先を混同しない。", "水面計のメーカーである。", "安全弁の形式名である。"], "ans": 2, "exp": "届出・申請・検査では相手先を問う問題が出やすい。"},
  {"id": 20260438, "year": 202604, "num": 38, "field": "law", "text": "数値条件がある法令問題の解き方として、適切なものは次のうちどれか。", "opts": ["常に最も長い選択肢を選ぶ。", "数値を読まずに選ぶ。", "単位、以上・未満、除外条件をセットで確認する。", "燃料名だけで選ぶ。", "問題番号で選ぶ。"], "ans": 2, "exp": "法令問題は境界値、単位、対象除外の読み違いが失点原因になりやすい。"},
  {"id": 20260439, "year": 202604, "num": 39, "field": "law", "text": "『ただし書き』がある選択肢を読む際の注意として、適切なものは次のうちどれか。", "opts": ["ただし書きは必ず無視する。", "本文と例外条件の両方を確認する。", "例外は常に本文を取り消さない。", "燃料の色で判断する。", "水面計の数だけで判断する。"], "ans": 1, "exp": "ただし書きは適用範囲や例外を示し、正誤に直結することがある。"},
  {"id": 20260440, "year": 202604, "num": 40, "field": "law", "text": "法令問題で『直ちに』と『遅滞なく』が問われた場合の基本姿勢として、適切なものは次のうちどれか。", "opts": ["どちらも手続不要という意味である。", "どちらも必ず1年後という意味である。", "手続の緊急度や期限表現を区別して読む。", "燃料の種類だけで決める。", "水位だけで決める。"], "ans": 2, "exp": "期限表現は届出や報告の正誤に関わるため、文言を区別する。"},
];

